#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_val_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_val_idx]) {
            min_val_idx = i;
        }
    }

    long long min_val = a[min_val_idx];
    long long total_spells = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_val_idx) {
            continue; // Cannot copy a pile into itself
        }
        // For each other pile a[i], we can add min_val to it as many times as possible
        // without exceeding k.
        // The number of times is (k - current_a_i) / min_val
        // Note: a[i] is guaranteed to be <= k initially.
        total_spells += (k - a[i]) / min_val;
    }

    std::cout << total_spells << std::endl;
}

