#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation is a common strategy for problems like this.
    // Let p' be the reversed permutation of p.
    // p' = [p_n, p_{n-1}, ..., p_2, p_1]
    // The sums of adjacent elements for p are:
    // [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n]
    // The sums of adjacent elements for p' are:
    // [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1]
    // These two sets of sums are identical, just in reverse order.
    // Therefore, their sorted versions (fingerprints) will be identical.
    // The only case where p' might be equal to p is if p is a palindrome.
    // A permutation of distinct integers from 1 to n cannot be a palindrome
    // unless n=1 (which is not allowed, n>=2) or n=0.
    // For n=2, p=[1,2], p'=[2,1]. They are different.
    // For n>=2, a permutation [p_1, ..., p_n] cannot be a palindrome
    // because if p_i = p_{n-i+1} for all i, then for n>=2, p_1=p_n.
    // But p_1 and p_n must be distinct values from 1 to n.
    // For example, if n=3, p=[1,2,3]. Reversed is [3,2,1]. Different.
    // If p=[1,3,2]. Reversed is [2,3,1]. Different.
    // The only way p could be equal to its reverse is if p_i = p_{n-i+1} for all i.
    // For example, if n=4, p=[1,2,3,4]. Reversed is [4,3,2,1]. Different.
    // If n=5, p=[1,2,3,4,5]. Reversed is [5,4,3,2,1]. Different.
    // A permutation of distinct integers from 1 to n can never be a palindrome
    // for n >= 2. If p_i = p_{n-i+1} for all i, then p_1 = p_n.
    // But p_1 and p_n must be distinct elements of the permutation unless n=1.
    // This is incorrect reasoning. A permutation can be a palindrome if n is odd and the middle element is unique, and pairs are symmetric.
    // E.g., for n=5, [1,2,3,2,1] is not a permutation because 2 appears twice.
    // A permutation of distinct integers from 1 to n cannot be a palindrome for n >= 2.
    // If p is a palindrome, then p_i = p_{n-i+1} for all i.
    // This implies p_1 = p_n. But p_1 and p_n are distinct elements of the permutation.
    // This is only possible if n=1, which is not allowed.
    // So, p is always different from its reverse p' for n >= 2.

    // Therefore, reversing the permutation always yields a different permutation
    // with the same fingerprint.
    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << "\n";
}

