void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int current_a1 = a[0];
    int days_left = d;

    for (int i = 1; i < n; ++i) {
        int pile_index = i + 1; // 1-indexed pile number
        int haybales_in_pile = a[i];
        int cost_per_haybale = i; // days to move from pile (i+1) to pile 1

        if (days_left <= 0) {
            break;
        }

        // Calculate how many haybales can be moved from this pile
        // based on available days.
        // num_haybales_to_move * cost_per_haybale <= days_left
        int max_movable_from_this_pile = days_left / cost_per_haybale;

        // The actual number of haybales moved is limited by
        // haybales_in_pile and max_movable_from_this_pile
        int moved_haybales = std::min(haybales_in_pile, max_movable_from_this_pile);

        current_a1 += moved_haybales;
        days_left -= moved_haybales * cost_per_haybale;
    }

    std::cout << current_a1 << std::endl;
}

