void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else {
        // For n >= 2, we can construct a number that satisfies the conditions.
        // The strategy is to use '2' as the first digit, and '3' for all subsequent digits.
        // This forms a number like 233...3.
        // Let's check the conditions for s = 233...3 (n-1 times '3').
        // 1. s > 0: True, as n >= 2.
        // 2. s consists of n digits: True by construction.
        // 3. No digit in s equals 0: True, only '2' and '3' are used.
        // 4. s is not divisible by any of its digits:
        //    The digits are '2' and '3'.
        //    Is s divisible by 2? No, because s ends in '3', which is odd.
        //    Is s divisible by 3? The sum of digits is 2 + (n-1)*3.
        //    Sum of digits = 2 + 3n - 3 = 3n - 1.
        //    For s to be divisible by 3, 3n - 1 must be divisible by 3.
        //    However, 3n is always divisible by 3, so 3n - 1 will never be divisible by 3.
        //    Thus, s is not divisible by 3.
        // All conditions are met.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << "\n";
    }
}

