void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix = a[n - 1]; // Initialize with the last element

    // Iterate from the second to last element backwards
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is
            // either equal to or less than min_suffix.
            // In this case, a[i] becomes the new minimum for elements
            // to its left.
            min_suffix = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

