int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_dist = 0;
        int last_r_pos = -1; // Represents the last 'R' position or the starting point 0.
                             // If last_r_pos = -1, it means the frog is at cell 0.
                             // If last_r_pos = i, it means the frog is at cell i.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed).
                // The distance from the previous 'R' cell (or 0) to this 'R' cell is (i+1) - (last_r_pos + 1)
                // which simplifies to i - last_r_pos.
                max_dist = std::max(max_dist, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' cell
        // (or 0 if no 'R's) to the target cell n+1.
        // The last 'R' cell is at index last_r_pos (0-indexed), so its cell number is last_r_pos + 1.
        // The distance from this cell to n+1 is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        max_dist = std::max(max_dist, n - last_r_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

