int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to the i-th cut (at height x_i)
        // should be i times the area of one piece.
        // Total area of the carrot = (1/2) * base * h = (1/2) * 1 * h = h/2.
        // Area of one piece = (h/2) / n = h / (2n).
        // Area of triangle up to x_i = i * (h / (2n)).
        //
        // For a triangle similar to the original, with height x_i, its area is (x_i^2) / (2h).
        // So, (x_i^2) / (2h) = i * (h / (2n)).
        // x_i^2 = i * (h / (2n)) * (2h)
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The numbers from 1 to k+1 will be used to generate k distinct differences.
                       // The differences will be k, k-1, ..., 1.

    // Generate the first k+1 elements to produce k distinct differences.
    // We alternate between the smallest available and largest available from the range [1, k+1].
    // This sequence will be: 1, k+1, 2, k, 3, k-1, ...
    // The differences will be: k, k-1, k-2, ..., 1.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, print smallest available
            std::cout << left++;
        } else { // Odd index, print largest available
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k+1) elements, we can just print them in increasing order.
    // This will generate a difference of 1 for each step, which is already one of the k distinct differences.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;
    int current_open_count = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_needed > 0) {
                result += '(';
                open_needed--;
                current_open_count++;
            }
        } else { // c == ')'
            if (close_needed > 0 && current_open_count > 0) {
                result += ')';
                close_needed--;
                current_open_count--;
            }
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k_max = n / m;

        if (k_max == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long last_digit_m = m % 10;

        std::vector<long long> cycle_sum_prefix(11); // cycle_sum_prefix[i] stores sum of first i last digits in a cycle
        cycle_sum_prefix[0] = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum_prefix[i] = cycle_sum_prefix[i-1] + (i * last_digit_m) % 10;
        }

        long long full_cycles = k_max / 10;
        long long remaining_elements = k_max % 10;

        long long total_sum = full_cycles * cycle_sum_prefix[10] + cycle_sum_prefix[remaining_elements];

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index 'p' such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // We start from n-1 and go left.
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }
    // After this loop, a[p...n-1] is non-decreasing.
    // If p is 0, the whole array is non-decreasing.

    // Now, find the rightmost index 'q' such that a[q...p-1] is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // We start from p-1 and go left.
    // If p is 0, this loop won't run, and q will remain 0.
    int q = p; // Initialize q to p. If p is 0, q remains 0.
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }
    // After this loop, a[q...p-1] is non-increasing.
    // If q is 0, then a[0...p-1] is non-increasing.

    // The length of the prefix to erase is q.
    std::cout << q << std::endl;
}

