int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For real solutions, d^2 - 4d >= 0
            // d(d - 4) >= 0
            // Since d >= 0, this means d - 4 >= 0, so d >= 4.
            // If d = 0, it's a special case handled above.
            // If d >= 4, then d^2 - 4d >= 0, so sqrt(d^2 - 4d) is real.

            double sqrt_discriminant = std::sqrt(d * d - 4 * d);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Check if a and b are non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d >= 4, then d-4 >= 0, so sqrt_discriminant >= 0.
            // Thus, a = (d + sqrt_discriminant) / 2.0 will always be >= d/2 >= 2, so positive.
            // For b = (d - sqrt_discriminant) / 2.0:
            // We need d - sqrt_discriminant >= 0, which means d >= sqrt_discriminant.
            // Squaring both sides (both are non-negative): d^2 >= d^2 - 4d.
            // This simplifies to 0 >= -4d, or 4d >= 0, which is true for d >= 0.
            // So, both a and b will be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
