        // We want to use the smallest possible a[j] that is greater than a[i]
        // to save larger elements for later positions.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] > a[i]
            count++;
            j++; // Move to the next element for placement
        } else {
