#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    std::vector<int> prefix_len(n);
    prefix_len[0] = 0; // a_1 must be >= 0
    for (int i = 1; i < n; ++i) {
        if (a[i] >= i) {
            prefix_len[i] = i;
        } else {
            prefix_len[i] = prefix_len[i-1];
        }
    }

    std::vector<int> suffix_len(n);
    suffix_len[n-1] = 0; // a_n must be >= 0
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            suffix_len[i] = (n - 1 - i);
        } else {
            suffix_len[i] = suffix_len[i+1];
        }
    }

    bool possible = false;
    for (int k_idx = 0; k_idx < n; ++k_idx) {
        // k_idx is 0-indexed, corresponds to a_k in 1-indexed problem statement
        // Left part: a_1 < a_2 < ... < a_{k_idx+1}
        // This requires a_i >= i-1 for 0 <= i <= k_idx
        // The length of the strictly increasing sequence ending at a[k_idx]
        // must be at least k_idx.
        // prefix_len[k_idx] stores the maximum length 'L' such that a[k_idx-L+1]...a[k_idx]
        // can be made 0,1,...,L-1.
        // So, we need k_idx <= prefix_len[k_idx].
        // This means a[0] >= 0, a[1] >= 1, ..., a[k_idx] >= k_idx.

        // Right part: a_{k_idx+1} > a_{k_idx+2} > ... > a_n
        // This requires a_i >= (n-1-i) for k_idx <= i <= n-1
        // The length of the strictly decreasing sequence starting at a[k_idx]
        // must be at least (n-1-k_idx).
        // suffix_len[k_idx] stores the maximum length 'L' such that a[k_idx]...a[k_idx+L-1]
        // can be made L-1,L-2,...,0.
        // So, we need (n-1-k_idx) <= suffix_len[k_idx].
        // This means a[k_idx] >= (n-1-k_idx), a[k_idx+1] >= (n-1-(k_idx+1)), ..., a[n-1] >= 0.

        if (prefix_len[k_idx] == k_idx && suffix_len[k_idx] == (n - 1 - k_idx)) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

