// Function to determine if a box can be the special box
// A, B, C, D are counts of toys in boxes 1, 2, 3, 4 respectively.
// target_box is the box we are checking (0-indexed: 0 for Box 1, 1 for Box 2, etc.)
bool can_be_special_box(long long A, long long B, long long C, long long D, int target_box) {
    long long total_toys = A + B + C + D;

    if (total_toys == 0) {
        return false; // No toys, no special box
    }
    if (total_toys == 1) {
        // If only one toy, it is the super toy. Check if it's in the target box.
        if (A == 1 && target_box == 0) return true;
        if (B == 1 && target_box == 1) return true;
        if (C == 1 && target_box == 2) return true;
        if (D == 1 && target_box == 3) return true;
        return false;
    }

    // Parity of negative numbers
    long long neg_count = A + B;
    bool final_is_negative_possible = (neg_count % 2 != 0);
    bool final_is_positive_possible = (neg_count % 2 == 0);

    // Check if magnitude can be >= 1
    bool final_mag_ge_1_possible = false;
    // Check if magnitude can be < 1
    bool final_mag_lt_1_possible = false;

    // Scenario 1: All toys with magnitude >= 1 (A and D) are multiplied first.
    // Then all toys with magnitude < 1 (B and C) are multiplied.
    // Then the two results are multiplied.
    // This strategy can maximize/minimize magnitude.

    // If there's at least one toy with magnitude >= 1 (A or D),
    // it's possible to end up with magnitude >= 1.
    // This is because if we have any toy with magnitude >= 1, say X,
    // and we multiply it by any other toy Y, the magnitude of X*Y will be
    // |X*Y| = |X|*|Y|. If |X| >= 1, then |X*Y| >= |Y|.
    // If we have at least one toy with magnitude >= 1, we can potentially keep the magnitude >= 1.
    // For example, if we have D toys, we can multiply them all together.
    // If D > 0, the result is >= 1.
    // If A > 0, we can multiply A toys. If A is even, result is >= 1. If A is odd, result is <= -1.
    // If A+D > 0, it's possible to get a magnitude >= 1.
    // If A+D == 0, then all toys are from B and C.
    // In this case, the final magnitude will always be < 1 (unless B+C=0, which is covered by total_toys=0).
    // So, final_mag_ge_1_possible is true if A+D > 0.
    // final_mag_lt_1_possible is true if B+C > 0.
    // If A+D > 0 and B+C > 0, then both are possible.
    // If A+D > 0 and B+C == 0, then only mag >= 1 is possible.
    // If A+D == 0 and B+C > 0, then only mag < 1 is possible.

    // More precise logic for magnitude:
    // If there are any toys in A or D, it's possible to get a final magnitude >= 1.
    // This is because we can always multiply all B and C toys together first,
    // resulting in a value with magnitude < 1. Then multiply this by an A or D toy.
    // If we have A or D toys, we can also multiply them together to get a large magnitude.
    // If we have only B and C toys, the final magnitude will always be < 1.
    // If we have A or D toys, we can always make the final magnitude >= 1.
    // Example: A=1, B=1, C=1, D=1.
    // (-2) * (-0.5) * (0.5) * (2)
    // (-2) * (2) = -4 (Box 1)
    // (-0.5) * (0.5) = 0.25 (Box 3)
    // -4 * 0.25 = -1 (Box 1) -> mag >= 1
    // (-2) * (-0.5) = 1 (Box 4)
    // (0.5) * (2) = 1 (Box 4)
    // 1 * 1 = 1 (Box 4) -> mag >= 1

    // It's always possible to get magnitude < 1 if B+C > 0.
    // If B+C > 0, we can pick one toy from B or C, say X.
    // Then multiply all other toys together. Let the result be Y.
    // Then multiply X and Y. If Y has a large magnitude, X*Y might still have a large magnitude.
    // However, we can always choose to multiply all toys from A and D first,
    // then multiply all toys from B and C first.
    // Let P_AD be the product of all A and D toys. |P_AD| >= 1 if A+D > 0.
    // Let P_BC be the product of all B and C toys. |P_BC| < 1 if B+C > 0.
    // If A+D > 0 and B+C > 0, then P_AD * P_BC can be >= 1 or < 1 depending on specific values.
    // But the question is "can be".

    // A simpler approach for magnitude:
    // If there is at least one toy in Box 1 or Box 4 (A+D > 0), it is possible to get a final magnitude >= 1.
    // This is because we can always multiply all toys from Box 2 and Box 3 first.
    // The product of B and C toys will have magnitude < 1 (if B+C > 0).
    // Let this product be $P_{BC}$.
    // Then we multiply $P_{BC}$ with toys from Box 1 and Box 4.
    // If we have $A+D$ toys, we can choose their values such that their product is large.
    // For example, if $A=1, D=1$, we can have $-100$ and $100$. Product is $-10000$.
    // If $B=1, C=1$, we can have $-0.01$ and $0.01$. Product is $-0.0001$.
    // If we multiply all these, $(-100)(-0.01)(0.01)(100) = 1 \cdot 1 = 1$.
    // It seems if A+D > 0, we can always make the final magnitude >= 1.
    // It seems if B+C > 0, we can always make the final magnitude < 1.
    // The only exception is if A+D=0, then all toys are from B and C, so magnitude must be < 1.
    // The only exception is if B+C=0, then all toys are from A and D, so magnitude must be >= 1.

    // Let's refine the magnitude logic:
    // Can we get magnitude >= 1?
    // Yes, if A+D > 0. (We can pick values like -100, 100, etc. for A/D toys, and -0.001, 0.001 for B/C toys.
    // The product of A/D toys can be made arbitrarily large. The product of B/C toys can be made arbitrarily small.
    // If we have at least one A/D toy, we can make the final product have magnitude >= 1.)
    // The only case where magnitude >= 1 is NOT possible is if A+D == 0.
    final_mag_ge_1_possible = (A + D > 0);

    // Can we get magnitude < 1?
    // Yes, if B+C > 0. (We can pick values like -0.001, 0.001 for B/C toys, and -100, 100 for A/D toys.
    // If we have at least one B/C toy, we can make the final product have magnitude < 1.)
    // The only case where magnitude < 1 is NOT possible is if B+C == 0.
    final_mag_lt_1_possible = (B + C > 0);

    // Special case: If A+D == 0, then all toys are from B and C.
    // The product of any number of toys from B and C will always have magnitude < 1.
    if (A + D == 0) {
        final_mag_ge_1_possible = false;
        final_mag_lt_1_possible = true; // Since total_toys > 1, B+C must be > 0.
    }
    // Special case: If B+C == 0, then all toys are from A and D.
    // The product of any number of toys from A and D will always have magnitude >= 1.
    if (B + C == 0) {
        final_mag_ge_1_possible = true; // Since total_toys > 1, A+D must be > 0.
        final_mag_lt_1_possible = false;
    }

    // Now combine sign and magnitude possibilities for each target box.
    // Box 1: Negative, magnitude >= 1
    if (target_box == 0) {
        return final_is_negative_possible && final_mag_ge_1_possible;
    }
    // Box 2: Negative, magnitude < 1
    if (target_box == 1) {
        return final_is_negative_possible && final_mag_lt_1_possible;
    }
    // Box 3: Positive, magnitude < 1
    if (target_box == 2) {
        return final_is_positive_possible && final_mag_lt_1_possible;
    }
    // Box 4: Positive, magnitude >= 1
    if (target_box == 3) {
        return final_is_positive_possible && final_mag_ge_1_possible;
    }

    return false; // Should not reach here
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        for (int i = 0; i < 4; ++i) {
            if (can_be_special_box(A, B, C, D, i)) {
                std::cout << "Ya";
            } else {
                std::cout << "Tidak";
            }
            if (i < 3) {
                std::cout << " ";
            }
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
