    int T;
    std::cin >> T;
    while (T--) {
        long long N;
        std::cin >> N;
        long long chanek_coins = 0;
        long long opponent_coins = 0;
        bool chanek_turn = true;

        while (N > 0) {
            if (chanek_turn) {
                if (N % 2 != 0) { // N is odd
                    chanek_coins += 1;
                    N -= 1;
                } else { // N is even
                    if (N == 2) { // Special case for N=2, Chanek takes 1
                        chanek_coins += 1;
                        N -= 1;
                    } else if ((N / 2) % 2 != 0) { // N/2 is odd, Chanek takes N/2
                        chanek_coins += N / 2;
                        N /= 2;
                    } else { // N/2 is even, Chanek takes 1
                        chanek_coins += 1;
                        N -= 1;
                    }
                }
            } else { // Opponent's turn
                if (N % 2 != 0) { // N is odd
                    opponent_coins += 1;
                    N -= 1;
                } else { // N is even
                    if (N == 2) { // Special case for N=2, Opponent takes 1
                        opponent_coins += 1;
                        N -= 1;
                    } else if ((N / 2) % 2 != 0) { // N/2 is odd, Opponent takes N/2
                        opponent_coins += N / 2;
                        N /= 2;
                    } else { // N/2 is even, Opponent takes 1
                        opponent_coins += 1;
                        N -= 1;
                    }
                }
            }
            chanek_turn = !chanek_turn;
        }
        std::cout << chanek_coins << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a subarray is a permutation
// It checks if all numbers from 1 to max_val are present exactly once.
// max_val is also the expected length of the permutation.
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx, int expected_max_val) {
    int len = end_idx - start_idx + 1;
    if (len != expected_max_val) {
        return false; // Length must match the expected maximum value
    }

    std::vector<bool> seen(expected_max_val + 1, false);
    int current_max = 0;

    for (int i = start_idx; i <= end_idx; ++i) {
        int val = arr[i];
        if (val < 1 || val > expected_max_val || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > current_max) {
            current_max = val;
        }
    }
    return current_max == expected_max_val; // Max element must be expected_max_val
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix permutation validity
    std::vector<bool> is_prefix_perm(n + 1, false); // is_prefix_perm[k] is true if a[0...k-1] is a perm of length k
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool possible_prefix = true;
    for (int k = 0; k < n; ++k) {
        int val = a[k];
        if (val < 1 || val > n || seen_prefix[val]) { // val > n is technically not needed as a_i <= n-1, but good for robustness
            possible_prefix = false;
        }
        if (possible_prefix) {
            seen_prefix[val] = true;
            if (val > current_max_prefix) {
                current_max_prefix = val;
            }
            if (current_max_prefix == k + 1) { // If max element seen so far is k+1, and all elements 1 to k+1 are present
                is_prefix_perm[k + 1] = true;
            }
        }
    }

    // Precompute suffix permutation validity
    std::vector<bool> is_suffix_perm(n + 1, false); // is_suffix_perm[k] is true if a[n-k...n-1] is a perm of length k
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int k = 0; k < n; ++k) {
        int val = a[n - 1 - k];
        if (val < 1 || val > n || seen_suffix[val]) {
            possible_suffix = false;
        }
        if (possible_suffix) {
            seen_suffix[val] = true;
            if (val > current_max_suffix) {
                current_max_suffix = val;
            }
            if (current_max_suffix == k + 1) { // If max element seen so far is k+1, and all elements 1 to k+1 are present
                is_suffix_perm[k + 1] = true;
            }
        }
    }

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

char beats(char c) {
    if (c == 'R') return 'P';
    if (c == 'S') return 'R';
    if (c == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_char = ' ';
        int max_count = -1;

        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_char = 'R';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_char = 'S';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_char = 'P';
        }

        char winning_move = beats(most_frequent_char);

        for (size_t i = 0; i < s.length(); ++i) {
            std::cout << winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

