        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Count pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Count pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (i.e., are identical points)
    // These pairs were counted twice: once for same x, once for same y.
    // We need to subtract them once to correct the overcounting.
    for (auto const& [point, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its parity pattern string
// The pattern is always 18 characters long, padded with '0's from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This corresponds to padding the number with '0's from the left
    while (pattern.length() < 18) {
        pattern += '0';
    }
    // Reverse to get the standard left-to-right representation of the pattern
    std::reverse(pattern.begin(), pattern.end());
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // A map to store counts of each parity pattern string
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            pattern_counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            pattern_counts[get_parity_pattern(a)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;

            // Normalize the query pattern to 18 characters
            // Pad with '0's from the left if shorter
            std::string normalized_s = s;
            while (normalized_s.length() < 18) {
                normalized_s = '0' + normalized_s;
            }

            std::cout << pattern_counts[normalized_s] << "\n";
        }
    }

    return 0;
}

