int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    for (int k = 0; k <= n; ++k) { // k is the number of items taken from the left
        // Items taken from left: w_1, ..., w_k
        // Items taken from right: w_{k+1}, ..., w_n
        // Number of items from left: k
        // Number of items from right: n - k

        long long current_energy = 0;

        // Energy for items taken from left
        current_energy += prefix_sum[k] * l;

        // Energy for items taken from right
        current_energy += (prefix_sum[n] - prefix_sum[k]) * r;

        // Add penalties
        int diff = k - (n - k); // k - (n-k) = 2k - n
        if (diff > 0) { // More items from left than right
            current_energy += (long long)(diff - 1) * Ql;
        } else if (diff < 0) { // More items from right than left
            current_energy += (long long)(-diff - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

