#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');

    for (int x = 0; x <= 9; ++x) {
        char last1 = '0' - 1; // Represents a value smaller than any digit
        char last2 = '0' - 1; // Represents a value smaller than any digit
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < (x + '0')) {
                // Must be color 1
                if (current_digit >= last1) {
                    result[i] = '1';
                    last1 = current_digit;
                } else {
                    possible = false;
                    break;
                }
            } else if (current_digit > (x + '0')) {
                // Must be color 2
                if (current_digit >= last2) {
                    result[i] = '2';
                    last2 = current_digit;
                } else {
                    possible = false;
                    break;
                }
            } else { // current_digit == (x + '0')
                // Can be either color 1 or color 2
                // Prioritize color 2 if it maintains non-decreasing order for S2
                if (current_digit >= last2) {
                    result[i] = '2';
                    last2 = current_digit;
                } else if (current_digit >= last1) {
                    // If cannot be color 2, try color 1
                    result[i] = '1';
                    last1 = current_digit;
                } else {
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            std::cout << result << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

