    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::min/max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // prefix_counts[0][i] stores count of 'x' up to index i-1
    // prefix_counts[1][i] stores count of 'y' up to index i-1
    // prefix_counts[2][i] stores count of 'z' up to index i-1
    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        prefix_counts[0][i + 1] = prefix_counts[0][i];
        prefix_counts[1][i + 1] = prefix_counts[1][i];
        prefix_counts[2][i + 1] = prefix_counts[2][i];
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r; // 1-indexed

        if (r - l + 1 < 3) { // Substring length less than 3
            std::cout << "YES\n";
            continue;
        }

        // Calculate counts for the substring s[l-1...r-1]
        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        // Find min and max counts among x, y, z
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        // If max_count - min_count <= 1, then the counts are balanced enough
        // (e.g., (k, k, k), (k, k, k+1), (k, k+1, k+1))
        // In this case, any 3-char substring will have counts (1,1,1) or (0,1,2) or (0,0,3) etc.
        // If counts are (k, k, k), (k, k, k+1), (k, k+1, k+1), then it's always possible to form a 3-char substring that is not 'xzy', 'zyx', 'yxz'.
        // For example, if counts are (k, k, k+1), we can always find 'z' and two other characters.
        // If counts are (k, k+1, k+1), we can always find 'y' and 'z' and one other character.
        // The only way it can get stuck is if all 3-char substrings are permutations of 'xyz'.
        // This implies that the counts of x, y, z in the entire substring must be very close.
        // Specifically, the difference between the maximum and minimum character count must be at most 1.
        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

