#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> pos_char(26);
    for (int i = 0; i < L; ++i) {
        pos_char[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int char_code = 0; char_code < 26; ++char_code) {
        if (pos_char[char_code].empty()) {
            continue; // This character does not appear in s
        }

        // These are the possible values of k given t[0] = char_code
        const std::vector<int>& possible_k_indices = pos_char[char_code];
        int num_possible_k = possible_k_indices.size();

        if (num_possible_k == 0) { // Should not happen if char_code is in s
            continue;
        }
        if (num_possible_k == 1) {
            // If only one k is possible, Vasya wins for sure for this t[0]
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose p (1 <= p < L) to maximize win probability
        double max_win_prob_for_char = 0.0;

        for (int p = 1; p < L; ++p) {
            std::map<std::pair<char, char>, int> counts;
            for (int k_idx : possible_k_indices) {
                char char_at_p = s[(k_idx + p) % L];
                counts[{s[k_idx], char_at_p}]++;
            }

            int current_wins = 0;
            for (auto const& [key, count] : counts) {
                if (count == 1) {
                    current_wins++;
                }
            }
            max_win_prob_for_char = std::max(max_win_prob_for_char, (double)current_wins / num_possible_k);
        }
        total_win_prob += max_win_prob_for_char;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

