#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two test values: 0 and 1023 (all bits set for 0-9)
    // We need to track how these values change after all operations.
    // This allows us to determine the final state of each bit.
    int val0 = 0;    // Represents the state of a 0-bit after all operations
    int val1023 = 1023; // Represents the state of a 1-bit after all operations

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1023 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1023 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1023 ^= x;
        }
    }

    // Now, for each bit position j (0 to 9):
    // - If the j-th bit of val0 is 0 and the j-th bit of val1023 is 0,
    //   it means any input bit j (0 or 1) becomes 0. This is equivalent to ANDing with 0.
    // - If the j-th bit of val0 is 0 and the j-th bit of val1023 is 1,
    //   it means input bit j becomes itself. This is equivalent to ANDing with 1, ORing with 0, XORing with 0.
    // - If the j-th bit of val0 is 1 and the j-th bit of val1023 is 0,
    //   it means input bit j becomes its inverse. This is equivalent to XORing with 1.
    // - If the j-th bit of val0 is 1 and the j-th bit of val1023 is 1,
    //   it means any input bit j (0 or 1) becomes 1. This is equivalent to ORing with 1.

    // We can combine these into three operations:
    // 1. An overall AND mask (initially all 1s)
    // 2. An overall OR mask (initially all 0s)
    // 3. An overall XOR mask (initially all 0s)

    int final_and_mask = 1023; // All bits 1
    int final_or_mask = 0;     // All bits 0
    int final_xor_mask = 0;    // All bits 0

    for (int j = 0; j < 10; ++j) {
        int bit_val0 = (val0 >> j) & 1;
        int bit_val1023 = (val1023 >> j) & 1;

        if (bit_val0 == 0 && bit_val1023 == 0) {
            // Input bit j becomes 0.
            // This means we must AND with 0 at this bit position.
            final_and_mask &= ~(1 << j); // Set j-th bit of AND mask to 0
        } else if (bit_val0 == 0 && bit_val1023 == 1) {
            // Input bit j becomes itself.
            // This means we must AND with 1, OR with 0, XOR with 0 at this bit position.
            // (No change to final_and_mask, final_or_mask, final_xor_mask for this bit)
        } else if (bit_val0 == 1 && bit_val1023 == 0) {
            // Input bit j becomes its inverse.
            // This means we must XOR with 1 at this bit position.
            final_xor_mask |= (1 << j); // Set j-th bit of XOR mask to 1
        } else if (bit_val0 == 1 && bit_val1023 == 1) {
            // Input bit j becomes 1.
            // This means we must OR with 1 at this bit position.
            final_or_mask |= (1 << j); // Set j-th bit of OR mask to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_or_mask != 0) {
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) {
        result_ops.push_back({'^', final_xor_mask});
    }
    if (final_and_mask != 1023) { // 1023 is all 1s for 10 bits, so no effect
        result_ops.push_back({'&', final_and_mask});
    }

    // The order of operations matters.
    // The sequence (x | OR_mask) ^ XOR_mask) & AND_mask
    // is equivalent to (x & AND_mask) ^ XOR_mask) | OR_mask
    // and also (x ^ XOR_mask) & AND_mask) | OR_mask
    // The problem statement implies that the order of operations in the output
    // should be consistent with how they are applied.
    // A common canonical form is: (x & A) | B ^ C
    // Let's verify this.
    // If we apply (x | OR_mask) ^ XOR_mask) & AND_mask:
    // For a bit j:
    // If bit_val0=0, bit_val1023=0: final_and_mask has 0, others 0.
    //   (x_j | 0) ^ 0) & 0 = 0. Correct.
    // If bit_val0=0, bit_val1023=1: all masks have 0.
    //   (x_j | 0) ^ 0) & 1 = x_j. Correct.
    // If bit_val0=1, bit_val1023=0: final_xor_mask has 1, others 0.
    //   (x_j | 0) ^ 1) & 1 = ~x_j. Correct.
    // If bit_val0=1, bit_val1023=1: final_or_mask has 1, others 0.
    //   (x_j | 1) ^ 0) & 1 = 1. Correct.
    // This order works.

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Max possible value for f(t) is N (length of s), which is 2e5.
    // 2^17 = 131072
    // 2^18 = 262144
    // So, the maximum length of a binary string whose decimal value is <= 2e5 is 18.
    // We can iterate through all possible starting positions `i`.
    // For each `i`, we can extend the substring to the right.
    // The maximum length of substring we need to check is 18 (or slightly more to be safe, say 20).
    // Let's use a constant `MAX_CHECK_LEN` for this.
    // A safe upper bound for MAX_CHECK_LEN would be 18 + 1 (for 0s) + 1 (safety) = 20.
    // Or simply, if the value exceeds N, we can stop.
    // The maximum value of N is 2e5.
    // The maximum length of a substring we need to consider is 18 (for 1xxxx... pattern).
    // If the substring starts with '0', it can have many leading zeros.
    // The actual length of the substring can be up to N.
    // The value f(t) is at most N.
    // The number of bits required to represent N is log2(N).
    // For N = 2e5, log2(2e5) is about 17.6. So, at most 18 bits.
    // This means the '1' in the binary representation cannot be further than 18 positions from the right end of the substring.
    // If a substring is s[l...r], its length is len = r - l + 1.
    // The value f(s[l...r]) must be equal to len.
    // If s[l] is '1', then the value is at least 2^(len-1).
    // If s[l] is '0', then we need to find the first '1' to calculate the value.
    // Let's iterate through all possible starting positions `i`.
    // For each `i`, we iterate through possible ending positions `j`.
    // The length of the substring s[i...j] is `len = j - i + 1`.
    // We need to calculate `val = f(s[i...j])`.
    // If `val == len`, it's a good substring.

    // The crucial observation is that if s[i] is '1', then `val` grows exponentially with `len`.
    // If `len` is large, `val` will quickly exceed `n`.
    // Specifically, if `s[i] == '1'`, then `val >= 2^(len-1)`.
    // If `2^(len-1) > n`, then `val > n`, so `val` cannot be equal to `len` (since `len <= n`).
    // `2^(len-1) > n` implies `len-1 > log2(n)`.
    // For `n = 2e5`, `log2(n)` is approx 17.6. So `len-1 > 17.6`, meaning `len > 18.6`.
    // So, if `s[i] == '1'`, we only need to check `len` up to about 19.
    // Let's set a practical limit, say `MAX_BITS = 20`.
    // This means for `s[i] == '1'`, we only need to check `j` such that `j - i + 1 <= MAX_BITS`.

    // What if `s[i]` is '0'?
    // Then `f(s[i...j])` is the value of `s[k...j]` where `k` is the first index >= `i` such that `s[k] == '1'`.
    // If all characters from `s[i...j]` are '0', then `f(s[i...j]) = 0`.
    // In this case, `len = j - i + 1`. If `len = 0`, it's a good substring. But `len` is always at least 1.
    // So `f(00...0) = 0` can never be equal to `len >= 1`.
    // Thus, a substring consisting only of '0's is never good.
    // This means we only care about substrings that contain at least one '1'.

    // Let's iterate `i` from `0` to `n-1`.
    // For each `i`, we iterate `j` from `i` to `n-1`.
    // We maintain the current binary value `current_val` and current length `current_len`.
    // We also need to handle leading zeros.

    for (int i = 0; i < n; ++i) {
        long long current_val = 0;
        // We need to find the first '1' to start calculating the value.
        // Let's say `first_one_idx` is the index of the first '1' in `s[i...j]`.
        // If `s[i]` is '0', we can skip it and count how many leading zeros there are.
        // The actual binary value starts from the first '1'.
        // The length of the substring is `j - i + 1`.
        // The value `f(s[i...j])` is the decimal value of `s[first_one_idx ... j]`.

        // Strategy: Iterate `i` from `0` to `n-1`.
        // For each `i`, iterate `j` from `i` to `n-1`.
        // Calculate `val = f(s[i...j])`.
        // If `val == j - i + 1`, increment count.
        // This is too slow (O(N^2 * logN) or O(N^2)). N=2e5, N^2=4e10.

        // Optimized strategy:
        // Iterate `i` from `0` to `n-1`.
        // Maintain `current_val` for `s[k...j]` where `k` is the first '1' in `s[i...j]`.
        // Maintain `leading_zeros_count` for `s[i...k-1]`.
        // The total length is `leading_zeros_count + (j - k + 1)`.

        // Let's fix the starting position `i`.
        // We need to find the first '1' at or after `i`.
        int first_one_idx = -1;
        for (int k = i; k < n; ++k) {
            if (s[k] == '1') {
                first_one_idx = k;
                break;
            }
        }

        if (first_one_idx == -1) {
            // No '1's from `i` to `n-1`. All remaining substrings are '0's.
            // f(00...0) = 0. Length is always >= 1. So no good substrings.
            break; // No more '1's in the rest of the string.
        }

        // Now `first_one_idx` is the index of the first '1' at or after `i`.
        // The number of leading zeros for a substring starting at `i` and having its first '1' at `first_one_idx` is `first_one_idx - i`.
        int leading_zeros = first_one_idx - i;
        current_val = 0;

        // Iterate `j` from `first_one_idx` to `n-1`.
        // This `j` is the right endpoint of the substring `s[i...j]`.
        // The actual binary value is formed by `s[first_one_idx ... j]`.
        // The length of this binary value part is `j - first_one_idx + 1`.
        // The total length of the substring `s[i...j]` is `leading_zeros + (j - first_one_idx + 1)`.

        for (int j = first_one_idx; j < n; ++j) {
            // Update current_val
            current_val = (current_val << 1) | (s[j] - '0');

            // Check if current_val exceeds a reasonable limit.
            // If current_val > n + MAX_BITS (e.g., 2e5 + 20), it's too large.
            // The maximum possible length is n.
            // If current_val > n, it cannot be equal to the length.
            // The length of the binary part is `j - first_one_idx + 1`.
            // The total length of the substring is `leading_zeros + (j - first_one_idx + 1)`.
            // If `current_val` becomes very large, it will exceed `n` and also `total_length`.
            // A safe upper bound for `current_val` to check is `n + MAX_BITS`.
            // `MAX_BITS` is roughly 18. So `n + 18`.
            // If `current_val` exceeds `n + 18`, then it's definitely too large to be equal to `total_length`.
            // This is because `total_length` is at most `n`.
            // So, if `current_val > n + 18`, we can break from this inner loop.
            // This is the key optimization.
            if (current_val > n + 20) { // Using 20 as a slightly larger safe constant
                break;
            }

            long long total_length = leading_zeros + (j - first_one_idx + 1);

            if (current_val == total_length) {
                good_substrings_count++;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    // Calculate prefix sums for differences (strawberry - blueberry)
    // For left side (jars 1 to n), iterate from right to left (n-1 down to 0)
    // For right side (jars n+1 to 2n), iterate from left to right (n up to 2n-1)

    // Map to store the minimum number of jars removed from the left side
    // to achieve a certain difference (strawberry - blueberry)
    // Key: difference, Value: count of jars removed
    std::map<int, int> left_diff_to_removed_count;

    // Base case: 0 jars removed from left, difference is 0
    left_diff_to_removed_count[0] = 0;

    int current_s_left = 0;
    int current_b_left = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            current_s_left++;
        } else {
            current_b_left++;
        }
        int diff = current_s_left - current_b_left;
        // We want to store the minimum number of jars removed to achieve this diff.
        // Since we iterate from n-1 down to 0, i.e., removing 1, 2, ..., n jars,
        // the first time we encounter a diff, it corresponds to the minimum jars removed.
        if (left_diff_to_removed_count.find(diff) == left_diff_to_removed_count.end()) {
            left_diff_to_removed_count[diff] = (n - i);
        }
    }

    int min_removed = 2 * n; // Initialize with maximum possible removals

    // Case 1: No jars removed from the right side
    // The target difference for the remaining jars is 0.
    // This means the total remaining S - total remaining B = 0.
    // (initial_s - current_s_left) - (initial_b - current_b_left) = 0
    // (initial_s - initial_b) - (current_s_left - current_b_left) = 0
    // (initial_s - initial_b) - diff = 0
    // diff = initial_s - initial_b
    int target_diff_for_left_only = initial_s - initial_b;
    if (left_diff_to_removed_count.count(target_diff_for_left_only)) {
        min_removed = std::min(min_removed, left_diff_to_removed_count[target_diff_for_left_only]);
    }

    // Iterate through jars removed from the right side
    int current_s_right = 0;
    int current_b_right = 0;
    for (int i = n; i < 2 * n; ++i) {
        if (a[i] == 1) {
            current_s_right++;
        } else {
            current_b_right++;
        }
        int diff_right = current_s_right - current_b_right;
        int removed_right_count = (i - n + 1);

        // We have removed `removed_right_count` jars from the right.
        // The remaining jars from the right side contribute `current_s_right` S and `current_b_right` B.
        // The total initial difference is `initial_s - initial_b`.
        // After removing `removed_right_count` jars from the right, the new total difference is
        // (initial_s - current_s_right) - (initial_b - current_b_right)
        // = (initial_s - initial_b) - (current_s_right - current_b_right)
        // = (initial_s - initial_b) - diff_right

        // To make the final S and B counts equal, we need to remove jars from the left
        // such that the remaining jars from the left have a difference equal to
        // `(initial_s - initial_b) - diff_right`.
        int required_diff_from_left = (initial_s - initial_b) - diff_right;

        if (left_diff_to_removed_count.count(required_diff_from_left)) {
            min_removed = std::min(min_removed, removed_right_count + left_diff_to_removed_count[required_diff_from_left]);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::max and std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies calculations as we can always assume n is the larger absolute coordinate.
        if (n < m) {
            std::swap(n, m);
        }

        // Case 1: Parity check.
        // The parity of (n + m) must be the same as the parity of k.
        // Each move changes the parity of (x+y) by 0 or 2 (diagonal) or 1 (axial).
        // (x_new + y_new) = (x_old +/- 1 + y_old +/- 1) = (x_old + y_old) +/- 2 or 0 (diagonal)
        // (x_new + y_new) = (x_old +/- 1 + y_old) = (x_old + y_old) +/- 1 (axial)
        // (x_new + y_new) = (x_old + y_old +/- 1) = (x_old + y_old) +/- 1 (axial)
        // So, (x_new + y_new) % 2 = (x_old + y_old) % 2 for diagonal moves.
        // And (x_new + y_new) % 2 != (x_old + y_old) % 2 for axial moves.
        // Starting at (0,0), (0+0)%2 = 0.
        // After k moves, the parity of (n+m) must be (0 + A) % 2, where A is number of axial moves.
        // This is equivalent to (n+m)%2 == k%2.
        if ((n % 2) != (k % 2)) { // (n+m)%2 == k%2 is equivalent to n%2 == k%2 if m%2 == 0, or n%2 != k%2 if m%2 == 1.
                                  // A simpler way: (n % 2) != (k % 2) is the condition for impossibility if m is even.
                                  // If m is odd, then (n % 2) != (k % 2) means (n+1)%2 != k%2.
                                  // Let's use the (n+m)%2 == k%2 directly.
            if (((n + m) % 2) != (k % 2)) {
                std::cout << -1 << "\n";
                continue;
            }
        }

        // Case 2: Not enough moves.
        // The minimum number of moves to reach (n, m) is max(n, m).
        // This is achieved by making min(n, m) diagonal moves and then (max(n, m) - min(n, m)) axial moves.
        if (k < n) { // Since n >= m, this is equivalent to k < max(n, m)
            std::cout << -1 << "\n";
            continue;
        }

        // If we pass the above checks, it's always possible to reach (n, m) in k moves.
        // We want to maximize diagonal moves.
        // Let D be diagonal moves, A be axial moves. k = D + A.
        // We want to maximize D.
        // The maximum number of diagonal moves is k.
        // However, we need to ensure the final position is (n, m).
        // Consider the parity of coordinates.
        // Each diagonal move changes both x and y parity.
        // Each axial move changes one coordinate's parity.
        // From (0,0) to (n,m):
        // x-coordinate changes parity D_x + A_x times.
        // y-coordinate changes parity D_y + A_y times.
        // For diagonal moves, D_x = D_y = D.
        // For axial moves, A_x is number of moves changing x, A_y is number of moves changing y.
        // A_x + A_y = A.
        // (n % 2) = (D % 2 + A_x % 2) % 2
        // (m % 2) = (D % 2 + A_y % 2) % 2
        //
        // A simpler approach:
        // We can make n diagonal moves to reach (n, n) (assuming n >= m).
        // This uses n moves. Remaining moves: k - n.
        // Current position: (n, n). Target: (n, m).
        // We need to change y-coordinate from n to m. This requires |n-m| changes.
        // We have k - n moves left.
        // Each pair of moves (e.g., (x,y) -> (x,y+1) -> (x,y)) can be used to "waste" moves
        // while keeping the parity of coordinates the same.
        //
        // The maximum number of diagonal moves is k.
        // However, we must reach (n, m).
        // The minimum number of axial moves required is (n - m).
        // This is because we need to cover the difference in coordinates.
        // We can make m diagonal moves to reach (m, m).
        // Then we need to make (n - m) axial moves along the x-axis to reach (n, m).
        // This uses m + (n - m) = n moves.
        // The remaining k - n moves must be "wasted" without changing the final position.
        // Each "wasted" move must be paired with another move that cancels its effect on the final position.
        // For example, (x,y) -> (x+1,y) -> (x,y). This uses 2 moves, changes x by 0, y by 0.
        // Or (x,y) -> (x+1,y+1) -> (x,y). This uses 2 moves, changes x by 0, y by 0.
        //
        // If k - n is even, we can use (k - n) / 2 pairs of moves like (x,y) -> (x+1,y) -> (x,y).
        // In this case, the number of diagonal moves is m.
        // The number of axial moves is (n - m) + (k - n).
        // Total moves = m + (n - m) + (k - n) = k.
        // Number of diagonal moves = m.
        //
        // If k - n is odd, we cannot simply use pairs of axial moves.
        // We need to adjust the parity of the final coordinates.
        // The condition (n % 2) == (k % 2) (since m is smaller, we can assume m is even or odd, but n is the dominant one)
        // (n+m)%2 == k%2 is the general condition.
        //
        // Let's consider the total number of moves k.
        // We want to maximize diagonal moves.
        // The maximum possible diagonal moves is k.
        // If we make k diagonal moves, we end up at a point (x,y) where x and y have the same parity as k.
        // For example, if k is even, (x,y) will be (even, even). If k is odd, (x,y) will be (odd, odd).
        //
        // The target is (n, m).
        // If n and m have the same parity, and k has the same parity as n (and m),
        // then we can make k diagonal moves.
        // Example: (2,2) in 2 moves. k=2. n=2, m=2. (2,2) -> (0,0) -> (2,2). 2 diagonal moves.
        // Example: (2,2) in 4 moves. k=4. n=2, m=2. (0,0)->(1,1)->(0,0)->(1,1)->(2,2). 4 diagonal moves.
        //
        // If n and m have different parities, it's impossible to reach (n,m) with only diagonal moves.
        // We need at least one axial move.
        //
        // The number of diagonal moves is at most k.
        // The number of diagonal moves is at most k - (n - m).
        // This is because we need at least (n - m) axial moves to cover the difference between n and m.
        // So, max_diag = k - (n - m).
        //
        // Now, consider the parity of (k - (n - m)).
        // If (k - (n - m)) is even, then we can make (k - (n - m)) diagonal moves.
        // The remaining (n - m) moves are axial.
        // Total moves = (k - (n - m)) + (n - m) = k.
        // The final position will be (n, m).
        // The number of diagonal moves is k - (n - m).
        //
        // What if (k - (n - m)) is odd?
        // This means we cannot make exactly (k - (n - m)) diagonal moves and (n - m) axial moves.
        // If (k - (n - m)) is odd, it means k and (n - m) have different parities.
        // This implies k - (n - m) - 1 is even.
        // We can make (k - (n - m) - 1) diagonal moves.
        // This leaves (n - m) + 1 moves.
        // We need to make (n - m) axial moves to cover the difference.
        // We have 1 extra move.
        // This extra move must be an axial move.
        // So, we make (n - m) + 1 axial moves.
        // Total axial moves = (n - m) + 1.
        // Total diagonal moves = k - (n - m) - 1.
        //
        // This logic is flawed. Let's restart.
        //
        // We have n, m, k. Assume n >= m.
        //
        // 1. Minimum moves: We need at least n moves to reach (n, m).
        //    If k < n, impossible. Output -1.
        //
        // 2. Parity check:
        //    Each move changes the parity of (x+y) by 1 (axial) or 0 (diagonal).
        //    Starting at (0,0), (x+y) is even.
        //    After k moves, (x+y) will have parity (k % 2) if all moves were axial.
        //    If we have D diagonal moves and A axial moves, k = D + A.
        //    The parity of (x+y) changes by A.
        //    So, (n+m) % 2 must be equal to (A % 2).
        //    Since A = k - D, (n+m) % 2 must be equal to ((k - D) % 2).
        //    This means (n+m) % 2 and (k - D) % 2 must be the same.
        //    This is equivalent to (n+m+k-D) % 2 == 0.
        //    Or, (n+m+k) % 2 == (D % 2).
        //    So, the number of diagonal moves D must have the same parity as (n+m+k).
        //
        //    If (n % 2) != (k % 2), then it's impossible.
        //    Why? Consider the coordinates modulo 2.
