        //   Else, we set current_b = a_i.
        // Else (a_i < prev_val):
        //   We cannot set b_i = a_i. We must increment.
        //   We need to find c_i such that (a_i + c_i) % m >= prev_val.
        //   The smallest such value is prev_val.
        //   To achieve prev_val, we need c_i = (prev_val - a_i + m) % m.
        //   If this c_i <= x, then we can set current_b = prev_val.
        //   Else (c_i > x), it's impossible to make b_i >= prev_val. Return false.

        if (current_a >= prev_val) {
            // We can potentially set b_i = a_i (c_i = 0). This is valid.
            // We can also potentially set b_i = prev_val.
            // This requires c_i = (prev_val - current_a + m) % m.
            // If this c_i is <= x, we can achieve prev_val.
            // Since we want to minimize b_i, we prefer prev_val if possible.
            if ((prev_val - current_a + m) % m <= x) {
                current_b = prev_val;
            } else {
                current_b = current_a;
            }
        } else { // current_a < prev_val
            // We must increment current_a.
            // We need to find c_i such that (current_a + c_i) % m >= prev_val.
            // The smallest such value is prev_val.
            // To achieve prev_val, we need c_i = (prev_val - current_a + m) % m.
            // If this c_i is <= x, then we can set current_b = prev_val.
            if ((prev_val - current_a + m) % m <= x) {
                current_b = prev_val;
            } else {
                // If we cannot achieve prev_val, it's impossible to satisfy the condition.
                return false;
            }
        }
        prev_val = current_b;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0, high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].id = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_office_cry_effect = children[i].v;
        long long accumulated_hall_cry_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated hall cry effect
            children[j].p -= accumulated_hall_cry_effect;

            // Apply current office cry effect
            if (current_office_cry_effect > 0) {
                children[j].p -= current_office_cry_effect;
                current_office_cry_effect--;
            }

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                accumulated_hall_cry_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
