int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If a has an odd number of ones, we can append '1' to make it even.
    // This effectively increases the number of ones by 1.
    // So, the maximum number of ones we can achieve in a string of length |a|
    // is ones_a if ones_a is even, or ones_a + 1 if ones_a is odd.
    // This is equivalent to (ones_a + (ones_a % 2)).
    int max_ones_a_initial = ones_a + (ones_a % 2);

    // We need to be able to form string b.
    // The length of b must be less than or equal to the maximum possible length of a.
    // The maximum possible length of a is effectively infinite, as we can always append parity.
    // However, we are interested in forming b, so we only care about lengths up to |b|.
    // We can always remove characters from the front of a.
    // So, if we can reach a state where a string `s` has length |b| and `s` is equal to `b`,
    // then it's possible.

    // The key insight is that we can always make the number of ones even by appending parity.
    // If current_parity is 1, append '1', new_parity is 0.
    // If current_parity is 0, append '0', new_parity is 0.
    // So, after at most one append operation, the string will have an even number of ones.
    // And we can keep appending '0's (since parity will be 0) to increase its length.

    // This means we can always transform 'a' into a string 'a'' such that:
    // 1. |a'| >= |a|
    // 2. |a'| has an even number of ones.
    // 3. The number of ones in a' is either `ones_a` (if `ones_a` is even) or `ones_a + 1` (if `ones_a` is odd).
    //    Let's call this `effective_ones_a`.
    // 4. We can then append '0's to `a'` to reach any length `L >= |a'|`.
    //    The number of ones will remain `effective_ones_a`.

    // So, the question boils down to:
    // Can we obtain a string `s` of length `|b|` by starting with `a`,
    // removing some prefix, and then appending some parities, such that `s` has `ones_b` ones?

    // The minimum number of ones we can have in a string of length `L` derived from `a`
    // is 0 (by removing all '1's).
    // The maximum number of ones we can have in a string of length `L` derived from `a`
    // is `effective_ones_a` (if we don't remove any '1's and only append '0's or one '1').

    // Let `current_ones_a` be the number of ones in `a`.
    // We can always make `current_ones_a` even by appending `current_ones_a % 2`.
    // After this, the number of ones becomes `current_ones_a + (current_ones_a % 2)`.
    // Let this be `final_ones_a`.
    // The length of `a` becomes `|a| + (current_ones_a % 2)`.
    // From this point, we can append '0's indefinitely, increasing length but not `final_ones_a`.

    // So, the maximum number of ones we can achieve in a string of length `|b|`
    // (by starting with `a`, possibly removing prefix, and then appending parities)
    // is `ones_a + (ones_a % 2)`.
    // This is because removing characters can only decrease or keep the same number of ones.
    // Appending parity can increase ones by at most 1 (if parity is 1).
    // Once parity is 0, appending parity adds '0', keeping ones count same.

    // So, if `ones_b` is greater than `ones_a + (ones_a % 2)`, it's impossible.
    // Because we can never create more '1's than this maximum.
    if (ones_b > ones_a + (ones_a % 2)) {
        std::cout << "NO\n";
        return 0;
    }

    // If `ones_b` is less than or equal to `ones_a + (ones_a % 2)`,
    // it is always possible.
    // Why?
    // 1. We can remove characters from the front of `a` until `a` has exactly `ones_b` ones.
    //    This is always possible as long as `ones_b <= ones_a`.
    //    If `ones_b > ones_a`, we must use the append parity operation to increase ones.
    //    This only happens if `ones_a` is odd and `ones_b = ones_a + 1`.
    //    In this case, we append '1' to `a`. Now `a` has `ones_a + 1` ones.
    //    Then we remove characters from the front until `a` has `ones_b` ones.
    //    This is possible as long as the remaining string is not shorter than `ones_b` (which is always true for |a| >= 1).
    // 2. After `a` has `ones_b` ones, its length might be different from `|b|`.
    //    If `|a| < |b|`, we can append '0's (since the parity will be 0 if `ones_b` is even, or we make it 0 by one append if `ones_b` is odd).
    //    If `|a| > |b|`, we can remove more characters from the front.
    //    The crucial part is that we can always adjust the length without changing the number of ones (after the initial adjustment to `ones_b`).

    // Let's re-evaluate.
    // We need to reach string `b`.
    // The number of ones in `b` is `ones_b`.
    // The number of ones in `a` is `ones_a`.
    // We can always make the number of ones in `a` become `ones_a` (if `ones_a` is even) or `ones_a + 1` (if `ones_a` is odd).
    // Let `max_possible_ones_in_a` be `ones_a + (ones_a % 2)`.
    // This is the maximum number of ones we can ever have in `a` *without removing any '1's*.
    // If `ones_b > max_possible_ones_in_a`, then it's impossible.
    // Example: a="00", b="1". ones_a=0, max_possible_ones_in_a=0. ones_b=1. Impossible. Correct.
    // Example: a="01011", b="0110". ones_a=3, max_possible_ones_in_a=4. ones_b=2. Possible. Correct.
    // Example: a="0011", b="1110". ones_a=2, max_possible_ones_in_a=2. ones_b=3. Impossible. Correct.

    // The logic is:
    // We can always remove characters from the front of `a`. This can only decrease or keep the number of '1's.
    // We can always append parity.
    // If `parity(s)` is 0, we append '0'. `count('1')` remains the same.
    // If `parity(s)` is 1, we append '1'. `count('1')` increases by 1.
    // After appending '1', the new string `s'` has `parity(s') = 0`.
    // So, after at most one append operation, we can make the string have an even number of '1's.
    // And then we can append '0's as many times as we want.

    // This means, from string `a`, we can reach any string `s'` such that:
    // 1. `s'` is a suffix of `a` (after some removals).
    // 2. `s'` has `k` ones, where `k <= ones_a`.
    // 3. We can then append `k % 2` (which is '0' or '1') to `s'`.
    //    The new string `s''` has `k + (k % 2)` ones.
    //    And `parity(s'')` is 0.
    // 4. We can then append '0's to `s''` to reach any desired length `L >= |s''|`.
    //    The number of ones will remain `k + (k % 2)`.

    // So, the maximum number of ones we can achieve in a string of length `|b|`
    // is `ones_a + (ones_a % 2)`.
    // If `ones_b` is less than or equal to this maximum, it's always possible.
    // We can always remove characters from `a` until the number of ones is `ones_b` (if `ones_b <= ones_a`).
    // Or, if `ones_b = ones_a + 1` (which implies `ones_a` is odd), we append '1' to `a`, then remove characters.
    // After achieving `ones_b` ones, we can adjust the length by removing characters or appending '0's.
    // The only constraint is that the final string must have length `|b|`.
    // Since we can always remove characters from the front, and always append '0's (after making parity 0),
    // we can always reach length `|b|` as long as we can achieve the correct number of ones.

    // The only condition is `ones_b <= ones_a + (ones_a % 2)`.
    if (ones_b <= ones_a + (ones_a % 2)) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;
    long long second_min_a = elements[1].value;
    long long second_max_a = elements[n - 2].value;

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (second_max_a + max_a) - (min_a + second_min_a);
    std::vector<int> partition1(n, 1);

    // Case 2: Try to put a_1 in one subsequence and a_n in another.
    // This forces a_1 and a_n to be in different subsequences.
    // min_f could be a_1 + a_2 (if a_2 is with a_1) or a_1 + a_2 + h (if a_2 is with a_n)
    // max_f could be a_{n-1} + a_n + h (if a_{n-1} is with a_1) or a_{n-1} + a_n (if a_{n-1} is with a_n)
    //
    // Consider a partition where elements[0] is in group 1, and elements[1]...elements[n-1] are in group 2.
    // Or elements[0]...elements[n-2] in group 1, and elements[n-1] in group 2.
    //
    // The strategy is to put elements[0] in group 1, and elements[n-1] in group 2.
    // All other elements elements[1]...elements[n-2] can be put in group 1 or 2.
    // To minimize max_f and maximize min_f, we want to make the range of sums as small as possible.
    //
    // If elements[0] is in group 1, and elements[n-1] is in group 2:
    // The smallest possible sum is min_a + second_min_a.
    //   - If second_min_a is in group 1, then min_f could be min_a + second_min_a.
    //   - If second_min_a is in group 2, then min_f could be min_a + second_min_a + h.
    // The largest possible sum is second_max_a + max_a.
    //   - If second_max_a is in group 2, then max_f could be second_max_a + max_a.
    //   - If second_max_a is in group 1, then max_f could be second_max_a + max_a + h.
    //
    // The critical observation is that if we put elements[0] in group 1 and elements[n-1] in group 2,
    // then the pair (elements[0], elements[n-1]) will always contribute min_a + max_a + h.
    //
    // What if we put elements[0] in group 1, and all other elements (elements[1]...elements[n-1]) in group 2?
    // This means elements[0] is separate from all others.
    // min_f:
    //   - (elements[0], elements[1]): min_a + second_min_a + h (different groups)
    //   - (elements[1], elements[2]): second_min_a + elements[2].value (same group)
    // max_f:
    //   - (elements[0], elements[n-1]): min_a + max_a + h (different groups)
    //   - (elements[n-2], elements[n-1]): second_max_a + max_a (same group)
    //
    // So, min_f = std::min(min_a + second_min_a + h, second_min_a + elements[2].value) if n >= 3.
    // If n=2, min_f = min_a + max_a + h.
    // max_f = std::max(min_a + max_a + h, second_max_a + max_a).
    //
    // This specific partition (elements[0] in group 1, rest in group 2)
    // min_val_f = std::min(min_a + second_min_a + h, second_min_a + elements[2].value); // if n >= 3
    // max_val_f = std::max(min_a + max_a + h, second_max_a + max_a);
    //
    // Let's consider the values that can be formed:
    // 1. Pairs within group 1: `a_i + a_j`
    // 2. Pairs within group 2: `a_i + a_j`
    // 3. Pairs across groups: `a_i + a_j + h`
    //
    // The minimum possible sum `a_i + a_j` is `min_a + second_min_a`.
    // The maximum possible sum `a_i + a_j` is `second_max_a + max_a`.
    //
    // If we put `min_a` in group 1 and `max_a` in group 2, and all other elements `a_i` (for `1 < i < n-1`) in group 1.
    // Group 1: `min_a`, `a_2`, ..., `a_{n-1}`
    // Group 2: `max_a`
    //
    // Values of f:
    // - `min_a + a_i` for `i \in [1, n-2]` (same group)
    // - `a_i + a_j` for `i, j \in [1, n-2]` (same group)
    // - `min_a + max_a + h` (different groups)
    // - `a_i + max_a + h` for `i \in [1, n-2]` (different groups)
    //
    // min_f:
    //   - `min_a + second_min_a` (from group 1)
    //   - `min_a + max_a + h` (from different groups)
    //   - `second_min_a + max_a + h` (from different groups)
    // So, `min_f = std::min(min_a + second_min_a, min_a + max_a + h)`
    //
    // max_f:
    //   - `second_max_a + elements[n-2].value` (from group 1)
    //   - `second_max_a + max_a + h` (from different groups)
    //   - `min_a + max_a + h` (from different groups)
    // So, `max_f = std::max(second_max_a + elements[n-2].value, second_max_a + max_a + h)`
    //
    // This is the partition where elements[0] is in group 1, elements[n-1] is in group 2,
    // and all elements[1]...elements[n-2] are in group 1.
    //
    // Let's call this "split_ends" partition.
    // Group 1: elements[0], elements[1], ..., elements[n-2]
    // Group 2: elements[n-1]
    //
    // min_f_split_ends:
    //   - `elements[0].value + elements[1].value` (from group 1)
    //   - `elements[0].value + elements[n-1].value + h` (across groups)
    //   - `elements[1].value + elements[n-1].value + h` (across groups)
    // So, `min_f_split_ends = std::min({elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h})`
    // (The `elements[1].value + elements[n-1].value + h` is always >= `elements[0].value + elements[n-1].value + h` because `elements[1].value >= elements[0].value`)
    //
    // max_f_split_ends:
    //   - `elements[n-3].value + elements[n-2].value` (from group 1, if n >= 3)
    //   - `elements[n-2].value + elements[n-1].value + h` (across groups)
    // So, `max_f_split_ends = std::max(elements[n-2].value + elements[n-1].value + h, elements[n-3].value + elements[n-2].value)` (if n >= 3)
    // If n=2, then group 1 has elements[0], group 2 has elements[1]. Only one pair: elements[0]+elements[1]+h.
    // If n=2, min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    //
    // Let's refine the split_ends partition:
    // Group 1: elements[0], elements[1], ..., elements[n-2]
    // Group 2: elements[n-1]
    //
    // Possible f values:
    // 1. `elements[i].value + elements[j].value` for `0 <= i < j <= n-2` (within group 1)
    //    Min: `elements[0].value + elements[1].value`
    //    Max: `elements[n-3].value + elements[n-2].value` (if n >= 3)
    // 2. `elements[i].value + elements[n-1].value + h` for `0 <= i <= n-2` (across groups)
    //    Min: `elements[0].value + elements[n-1].value + h`
    //    Max: `elements[n-2].value + elements[n-1].value + h`
    //
    // So, for this partition:
    // `min_f_val = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h)` (if n >= 2)
    // `max_f_val = std::max(elements[n-3].value + elements[n-2].value, elements[n-2].value + elements[n-1].value + h)` (if n >= 3)
    //
    // Special handling for n=2:
    // Group 1: elements[0]
    // Group 2: elements[1]
    // Only one pair: (elements[0], elements[1]). They are in different groups.
    // f = elements[0].value + elements[1].value + h.
    // min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    //
    // Special handling for n=3:
    // Group 1: elements[0], elements[1]
    // Group 2: elements[2]
    // Pairs:
    //   - (elements[0], elements[1]): elements[0].value + elements[1].value (same)
    //   - (elements[0], elements[2]): elements[0].value + elements[2].value + h (diff)
    //   - (elements[1], elements[2]): elements[1].value + elements[2].value + h (diff)
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[1].value + elements[2].value + h
    // Goodness = (elements[1].value + elements[2].value + h) - (elements[0].value + elements[1].value)
    //          = elements[2].value + h - elements[0].value
    //
    // Let's calculate goodness for this "split_ends" partition for general n >= 2.
    long long min_f_split_ends;
    long long max_f_split_ends;

    if (n == 2) {
        min_f_split_ends = elements[0].value + elements[1].value + h;
        max_f_split_ends = elements[0].value + elements[1].value + h;
    } else { // n >= 3
        min_f_split_ends = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h);
        max_f_split_ends = std::max(elements[n-3].value + elements[n-2].value, elements[n-2].value + elements[n-1].value + h);
    }
    long long goodness2 = max_f_split_ends - min_f_split_ends;
    std::vector<int> partition2(n);
    for (int i = 0; i < n - 1; ++i) {
        partition2[elements[i].original_index] = 1;
    }
    partition2[elements[n-1].original_index] = 2;

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s[0...i-1] and s[i...n-1].
    // We can rearrange them as s[i...n-1] + s[0...i-1].
    // This is a cyclic shift.
    // We need to find if any cyclic shift (other than s itself) is a palindrome.
    for (int i = 1; i < n; ++i) {
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If no solution with k=1, we check k=2.
    // A solution with k=2 is always possible unless all characters in s are the same.
    // If all characters are the same (e.g., "aaaa"), then any rearrangement of substrings
    // will result in the same string "aaaa", which is a palindrome but not different from s.
    // In this case, it's impossible.

    // Check if all characters are the same
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" (k=2)
        // Example: "abacaba" -> "aba|c|aba" -> "aba|c|aba" (not different)
        // But we know k=1 didn't work, so any cyclic shift is either s or not a palindrome.
        // Consider s = "abacaba".
        // If we cut s into s[0...i-1], s[i...j-1], s[j...n-1].
        // We can always find a cut that works for k=2.
        // For example, cut s into s[0...n/2-1], s[n/2], s[n/2+1...n-1] (for odd n).
        // Or s[0...n/2-1], s[n/2...n/2], s[n/2+1...n-1] (for even n, this is not right).
        // For even n, s[0...n/2-1], s[n/2...n/2], s[n/2+1...n-1] is not 3 pieces.
        // For even n, s[0...n/2-1], s[n/2], s[n/2+1...n-1] is not 3 pieces.
        //
        // The argument for k=2 being always possible (if not all_same and k=1 fails) is:
        // If s is a palindrome and not all characters are the same, then s must have at least two distinct characters.
        // Since k=1 failed, no single cyclic shift (other than s itself) is a palindrome.
        // Consider the string s' = s[0...n-2]. This is a prefix of s.
        // If s' is a palindrome, then s[0] == s[n-2], s[1] == s[n-3], etc.
        // Since s is a palindrome, s[0] == s[n-1], s[1] == s[n-2], etc.
        // This implies s[n-1] == s[n-2], s[n-2] == s[n-3], etc.
        // If s[0...n-2] is a palindrome, then s[0] == s[n-2].
        // Since s is a palindrome, s[0] == s[n-1].
        // So s[n-1] == s[n-2].
        // By induction, if s[0...i] is a palindrome for all i < n-1, then all characters must be the same.
        //
        // If s is not all_same, then there must be some prefix s[0...i] that is not a palindrome.
        // Or, more simply, consider the first half of the string s[0...n/2-1].
        // If this first half is not all the same character, then we can make a cut.
        // If s is not all_same, then s[0...n/2-1] cannot be all the same character, unless n=1.
        // If n=1, s="a", then all_same is true.
        // So for n > 1 and not all_same, s[0...n/2-1] must contain at least two distinct characters.
        //
        // Consider the string s_half = s.substr(0, n / 2).
        // If s_half is a palindrome, then s = s_half + (middle_char) + reverse(s_half).
        // Example: s = "abacaba", s_half = "aba".
        // If s_half is a palindrome, and s is not all_same, then s_half must contain distinct characters.
        // If s_half is a palindrome, and s is not all_same, then s_half cannot be all the same character.
        //
        // The problem statement guarantees that if k=1 doesn't work and not all_same, then k=2 works.
        // This is a known property for palindromes. If a palindrome `s` is not composed of all identical characters,
        // and no cyclic shift of `s` (other than `s` itself) is a palindrome, then it's always possible to
        // form a new palindrome using 2 cuts.
        // For example, take `s = "nolon"`. `n=5`. `s_half = "no"`.
        // Cut `s` into `s[0...n/2-1]`, `s[n/2]`, `s[n/2+1...n-1]`.
        // For `nolon`: `no`, `l`, `on`. Rearrange to `on`, `l`, `no`. Result `onlno`. This is a palindrome.
        // This is `s.substr(n/2+1)` + `s.substr(n/2, 1)` + `s.substr(0, n/2)`.
        // This works because `s.substr(0, n/2)` is the reverse of `s.substr(n/2+1)` (due to `s` being a palindrome).
        // So `s.substr(n/2+1)` + `s.substr(n/2, 1)` + `s.substr(0, n/2)`
        // is `reverse(s.substr(0, n/2))` + `s.substr(n/2, 1)` + `s.substr(0, n/2)`.
        // This is a palindrome if `s.substr(n/2, 1)` is the middle character.
        // This new string is `reverse(P) + M + P`. This is a palindrome.
        // Is it different from `s`? `s = P + M + reverse(P)`.
        // If `P` is not a palindrome, then `reverse(P) != P`.
        // If `P` is not a palindrome, then `reverse(P) + M + P` is different from `P + M + reverse(P)`.
        // Example: `s = "abacaba"`. `P = "aba"`. `M = "c"`. `reverse(P) = "aba"`.
        // `s = "aba" + "c" + "aba"`.
        // `s_prime = "aba" + "c" + "aba"`. This is `s`.
        // This strategy only works if `P` is not a palindrome.
        //
        // The condition for k=2 is simply "not all characters are the same".
        // If all characters are the same, it's impossible.
        // Otherwise, it's 1 or 2. Since we already checked 1, if it's not 1, it must be 2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[i] stores the minimum r (1-based) such that s[i..r-1] contains a pattern.
                                                // If no such r exists, it's n+1.

    // Iterate through all possible starting positions x (0-based) of the pattern
    // and all possible k (1-based)
    // The pattern is s[x], s[x+k], s[x+2k]
    // The length of the pattern is 2k+1.
    // The maximum possible k is such that x+2k < n.
    // So 2k < n-x, k < (n-x)/2.
    // Smallest k is 1.
    // The minimum length of a pattern is 3 (for k=1).
    // The maximum length of a pattern is n.

    // The smallest possible k is 1.
    // The largest possible k is such that x+2k < n.
    // For k=1, we check s[x], s[x+1], s[x+2].
    // For k=2, we check s[x], s[x+2], s[x+4].
    // For k=3, we check s[x], s[x+3], s[x+6].
    // The maximum k we need to check is small.
    // If k is large, say k >= 7, then 2k >= 14.
    // The pattern s[x], s[x+k], s[x+2k] would span at least 15 characters.
    // If n is small, say n < 15, then no such pattern with k >= 7 can exist.
    // The problem statement implies k can be up to n.
    // However, for a pattern s[x], s[x+k], s[x+2k] to exist, we need x+2k < n.
    // The minimum length of the substring containing the pattern is 2k+1.
    // The maximum length of the substring is n.
    // So 2k+1 <= n, which means 2k <= n-1, or k <= (n-1)/2.
    // For n=300000, k can be up to 150000.
    // A direct O(N*K) approach would be too slow.

    // Let's analyze the condition s[x] = s[x+k] = s[x+2k].
    // The minimum length of such a pattern is 3 (when k=1).
    // The maximum length of such a pattern is n.
    // The crucial observation is that if a pattern exists, it must be contained in some substring.
    // The smallest possible $r$ for a given $l$ is $l+2k$.
    // The problem asks for pairs $(l, r)$ such that $l \leq x < x+2k \leq r$.
    // This means $l \leq x+1$ (1-based) and $x+2k \leq r$ (1-based).
    // In 0-based indexing: $l-1 \leq x$ and $x+2k \leq r-1$.
    // So, for a given pattern $s[x], s[x+k], s[x+2k]$, any $l'$ such that $l' \leq x+1$ (1-based)
    // and any $r'$ such that $r' \geq x+2k+1$ (1-based) will contain this pattern.
    // The smallest $r'$ that contains this pattern for a given $l'$ is $x+2k+1$.
    // So, for each $x$ (0-based) and $k$ (1-based) such that $s[x] = s[x+k] = s[x+2k]$,
    // we have a valid pattern. The 1-based indices are $x+1, x+k+1, x+2k+1$.
    // The substring $s[x+1 \dots x+2k+1]$ contains this pattern.
    // For any $l_{curr} \in [1, x+1]$, the pair $(l_{curr}, x+2k+1)$ is a valid pair.
    // We want to find the minimum $r$ for each $l$.
    // For each $l_{curr} \in [1, x+1]$, we can update min_r_for_l[l_{curr}] = min(min_r_for_l[l_{curr}], x+2k+1).

    // The maximum value of k that we need to check is relatively small.
    // If k is large, say k >= 7, then the pattern $s[x], s[x+k], s[x+2k]$
    // implies that $s[x]$ and $s[x+2k]$ are the same, and $s[x+k]$ is the same.
    // The length of the pattern is $2k+1$.
    // If $k$ is large, then $x+2k$ is far from $x$.
    // Consider the maximum $k$ that can be relevant.
    // If $k$ is large, say $k \ge 7$, then $2k \ge 14$.
    // The indices $x, x+k, x+2k$ are far apart.
    // If $s[x] = s[x+k] = s[x+2k]$, then the substring $s[x \dots x+2k]$ contains this pattern.
    // The length of this substring is $2k+1$.
    // If $2k+1 > 14$, then $k > 6.5$.
    // It turns out that if there is a pattern with large $k$, there must also be a pattern with small $k$.
    // This is a known property for certain string problems.
    // For $s_x = s_{x+k} = s_{x+2k}$, if $k$ is large, say $k \ge 7$, then the length $2k+1 \ge 15$.
    // It has been shown that if such a pattern exists, then there must exist a pattern with $k \le 6$.
    // This is a common trick in competitive programming for problems involving arithmetic progressions in strings.
    // The proof is non-trivial and relies on properties of binary strings.
    // So, we only need to check $k$ from $1$ to $6$.

    for (int k = 1; k <= 6; ++k) { // Iterate k from 1 to 6 (inclusive)
        for (int x = 0; x + 2 * k < n; ++x) { // Iterate x (0-based)
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a pattern s[x], s[x+k], s[x+2k]
                // The 1-based indices are x+1, x+k+1, x+2k+1.
                // The pattern is contained in the substring starting at x (0-based) and ending at x+2k (0-based).
                // The 1-based range for this minimal substring is [x+1, x+2k+1].
                int current_r = x + 2 * k + 1; // 1-based end index of the pattern
                int current_l = x + 1;         // 1-based start index of the pattern

                // For any l_prime from 1 to current_l, the pair (l_prime, current_r) is valid.
                // We want to find the minimum r for each l.
                // So, for each l_prime from 1 to current_l, we update min_r_for_l[l_prime].
                // Since we are iterating x from 0 to n-1, and k from 1 to 6,
                // current_r will be increasing for fixed k and increasing x.
                // This means that for a fixed l_prime, we will find smaller current_r values first.
                // However, we need to update min_r_for_l[l_prime] for all l_prime <= current_l.
                // A simple loop for this update would be:
                // for (int l_prime = 1; l_prime <= current_l; ++l_prime) {
                //     min_r_for_l[l_prime] = std::min(min_r_for_l[l_prime], current_r);
                // }
                // This loop is O(N) for each pattern, leading to O(N^2) overall, which is too slow.

                // Instead, we can update min_r_for_l[current_l] = min(min_r_for_l[current_l], current_r).
                // After processing all patterns, we can propagate these minimums.
                // If min_r_for_l[i] is R, then for any l_prime < i, min_r_for_l[l_prime] must be at most R.
                // This is because if s[i-1..R-1] contains a pattern, then s[l_prime-1..R-1] also contains it.
                // So, we can do a suffix minimum pass:
                // for (int i = n - 1; i >= 1; --i) {
                //     min_r_for_l[i] = std::min(min_r_for_l[i], min_r_for_l[i+1]);
                // }
                // This pass should be done after all patterns are found.

                min_r_for_l[current_l] = std::min(min_r_for_l[current_l], current_r);
            }
        }
    }

    // Propagate minimum r values: if min_r_for_l[i] is R, then for any l' < i, min_r_for_l[l'] must be <= R.
    // This is because if s[i-1..R-1] contains a pattern, then s[l'-1..R-1] also contains it.
    // So, we can do a suffix minimum pass.
    for (int i = n - 1; i >= 1; --i) {
        min_r_for_l[i] = std::min(min_r_for_l[i], min_r_for_l[i + 1]);
    }

    long long total_count = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one r for this l
            // All r from min_r_for_l[l] to n are valid for this l.
            // Number of such r's is n - min_r_for_l[l] + 1.
            total_count += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long p_start = p[p_idx];

        // If current head cannot reach the current target track p_start within T time,
        // it means this head cannot cover p_start.
        // We need to find a head that can cover p_start.
        // If current_h is too far to the right of p_start, this head is useless for p_start.
        // We must advance p_idx until p_start is reachable by current_h or current_h is to the left of p_start.
        // Or, more simply, if p_start is too far to the left of current_h, this head can't cover it.
        // We need to find the first p_start that current_h can potentially cover.
        // This is implicitly handled by the loop structure.
        // If p_start is already covered by a previous head, p_idx would have advanced.

        // If current_h is to the right of p_start, and p_start is not covered yet,
        // this head can potentially cover p_start by moving left.
        // The leftmost point it can reach is current_h - T.
        // If p_start < current_h - T, then current_h cannot reach p_start.
        // This head can only cover tracks in [current_h - T, current_h + T].
        // However, the actual range covered depends on its movement.
        // If it moves to x, it covers [min(h_i, x), max(h_i, x)].
        // The crucial observation is that to cover p_start, the head must move to some x such that p_start is in [min(h_i, x), max(h_i, x)]
        // AND |h_i - x| <= T.
        // This means x must be in [h_i - T, h_i + T].
        // So, the head can cover p_start if p_start is in [h_i - T, h_i + T].
        // If p_start is outside this range, this head cannot cover p_start.

        // If p_start is to the left of current_h - T, this head cannot cover p_start.
        // We need to find a head that can cover p_start.
        // This head will be used to cover tracks starting from p_start.
        // The range it can cover is [p_start, p_start + T + (current_h - p_start)] if it moves right from p_start.
        // Or [p_start - T - (p_start - current_h), p_start] if it moves left from p_start.

        // Let's simplify: a head at `current_h` can cover a segment `[L, R]` if it moves to `x` such that `|current_h - x| <= T`.
        // The segment covered is `[min(current_h, x), max(current_h, x)]`.
        // To cover `p_start`, the head must move to some `x` such that `p_start` is in `[min(current_h, x), max(current_h, x)]`.
        // And `|current_h - x| <= T`.
        // This means `x` must be in `[current_h - T, current_h + T]`.
        // So, `p_start` must be in `[current_h - T, current_h + T]`.
        // If `p_start < current_h - T`, this head cannot cover `p_start`. We move to the next head.
        // If `p_start > current_h + T`, this head cannot cover `p_start`. This should not happen if `p_idx` is correctly advanced.

        // The strategy is greedy: use the current head to cover `p_start` and as many subsequent `p_j` as possible.
        // The head is at `current_h`. The first uncovered track is `p_start`.
        // Case 1: `current_h` is to the left of `p_start`.
        // The head must move right to cover `p_start`.
        // It takes `p_start - current_h` time to reach `p_start`.
        // Remaining time: `T - (p_start - current_h)`.
        // With this remaining time, it can move further right.
        // The rightmost track it can reach is `p_start + (T - (p_start - current_h)) = current_h + T`.
        // So, it covers `[current_h, current_h + T]`.
        // The tracks it actually covers are `[p_start, current_h + T]`.
        // The rightmost track covered is `current_h + T`.

        // Case 2: `current_h` is to the right of `p_start`.
        // The head must move left to cover `p_start`.
        // It takes `current_h - p_start` time to reach `p_start`.
        // Remaining time: `T - (current_h - p_start)`.
        // With this remaining time, it can move further left.
        // The leftmost track it can reach is `p_start - (T - (current_h - p_start)) = current_h - T`.
        // So, it covers `[current_h - T, current_h]`.
        // The tracks it actually covers are `[current_h - T, p_start]`.
        // The rightmost track covered is `p_start`.

        // Case 3: `current_h` is at `p_start`.
        // It takes 0 time to reach `p_start`.
        // Remaining time: `T`.
        // It can move `T` units left or `T` units right.
        // It covers `[current_h - T, current_h + T]`.
        // The rightmost track covered is `current_h + T`.

        // Combining these:
        // If `current_h <= p_start`: The head moves right. It takes `p_start - current_h` time to reach `p_start`.
        // If `p_start - current_h > T`, this head cannot reach `p_start`.
        // Otherwise, it reaches `p_start` and has `T - (p_start - current_h)` time left.
        // It can then move further right to `p_start + (T - (p_start - current_h)) = current_h + T`.
        // The rightmost track covered is `current_h + T`.

        // If `current_h > p_start`: The head moves left. It takes `current_h - p_start` time to reach `p_start`.
        // If `current_h - p_start > T`, this head cannot reach `p_start`.
        // Otherwise, it reaches `p_start` and has `T - (current_h - p_start)` time left.
        // It can then move further left to `p_start - (T - (current_h - p_start)) = current_h - T`.
        // The rightmost track covered is `p_start`. (Because it moved left to cover p_start, and then further left. The segment covered is [current_h - T, current_h]. The rightmost point of this segment is current_h. But we are interested in the rightmost *target track* covered. If it moves left to p_start, it covers [current_h - T, p_start]. The rightmost target track covered is p_start.)

        // This logic is tricky. Let's re-evaluate.
        // A head at `h_i` can cover any track `x` such that `|h_i - x| <= T`.
        // If it moves to `x`, it covers the segment `[min(h_i, x), max(h_i, x)]`.
        // We want to cover `p_start`.
        // If `p_start` is too far left for `h_i` (i.e., `p_start < h_i - T`), then `h_i` cannot cover `p_start`.
        // In this case, `h_i` is useless for `p_start` and any `p_j` to its left. We should try the next head.
        // If `p_start` is reachable by `h_i` (i.e., `p_start >= h_i - T`), then `h_i` can cover `p_start`.
        // To maximize the coverage to the right, `h_i` should move as far right as possible while still covering `p_start`.
        // If `h_i <= p_start`: `h_i` moves right to `x`. It covers `[h_i, x]`. We need `p_start <= x`.
        // The maximum `x` is `h_i + T`. So it covers `[h_i, h_i + T]`.
        // The rightmost track covered is `h_i + T`.
        // If `h_i > p_start`: `h_i` moves left to `x`. It covers `[x, h_i]`. We need `x <= p_start`.
        // The minimum `x` is `h_i - T`. So it covers `[h_i - T, h_i]`.
        // The rightmost track covered is `h_i`.
        // This is still not quite right. The head can move to any `x` in `[h_i - T, h_i + T]`.
        // If it moves to `x`, it covers `[min(h_i, x), max(h_i, x)]`.
        // We want to cover `p_start`.
        // If `h_i` is used to cover `p_start`, it must move to some `x` such that `p_start` is in `[min(h_i, x), max(h_i, x)]` and `|h_i - x| <= T`.
        // To maximize the rightmost point covered, the head should move to `x = h_i + T`.
        // This covers the range `[h_i, h_i + T]`.
        // This is valid if `p_start` is in `[h_i, h_i + T]`.
        // If `p_start < h_i`, then moving to `h_i + T` does not cover `p_start`.
        // In this case, `h_i` must move left to cover `p_start`.
        // If `h_i` moves left to `x` such that `x <= p_start < h_i`, it covers `[x, h_i]`.
        // The time taken is `h_i - x`. This must be `<= T`. So `x >= h_i - T`.
        // To cover `p_start` and maximize right coverage, `h_i` should move to `p_start`.
        // This takes `h_i - p_start` time. Remaining time `T - (h_i - p_start)`.
        // With this remaining time, it can move further right from `p_start` to `p_start + (T - (h_i - p_start))`.
        // So, if `h_i > p_start`, and `h_i - p_start <= T`, the head can cover up to `p_start + T - (h_i - p_start)`.
        // This is `p_start + T - h_i + p_start = 2*p_start + T - h_i`.
        // This is the rightmost point it can reach *after* covering `p_start` by moving left.

        // Let's use the two-pointer approach with a clearer definition of `rightmost_covered`.
        // `rightmost_covered` is the maximum track index that the current head can cover,
        // given that it must cover `p[p_idx]`.

        // If `p[p_idx]` is to the left of `current_h - T`, then `current_h` cannot cover `p[p_idx]`.
        // This `h_idx` head is too far right to cover `p[p_idx]`. We must use a previous head or fail.
        // Since `h` is sorted, `current_h` is the leftmost head we can use for `p[p_idx]` that is not yet used.
        // If `p[p_idx] < current_h - T`, then this `h_idx` head cannot cover `p[p_idx]`.
        // This means no subsequent head `h_idx+1, ...` can cover `p[p_idx]` either, because they are even further right.
        // So, if `p[p_idx] < current_h - T`, it's impossible.
        // This is the condition for failure.

        // If `p[p_idx] >= current_h - T`, then `current_h` can cover `p[p_idx]`.
        // We want to maximize the rightmost track covered by `current_h` while ensuring `p[p_idx]` is covered.
        // There are two main ways `current_h` can cover `p[p_idx]` and extend coverage:
        // 1. Move right: `current_h` moves to `x_R = current_h + T`. This covers `[current_h, current_h + T]`.
        //    This is valid if `p[p_idx]` is in `[current_h, current_h + T]`.
        //    If `p[p_idx] < current_h`, this strategy doesn't cover `p[p_idx]`.
        //    So, if `p[p_idx] >= current_h`, the rightmost covered is `current_h + T`.
        // 2. Move left then right: `current_h` moves left to `p[p_idx]`. Time taken: `current_h - p[p_idx]`.
        //    This is valid if `current_h - p[p_idx] <= T`.
        //    Remaining time: `T - (current_h - p[p_idx])`.
        //    From `p[p_idx]`, it can move right by this remaining time.
        //    Rightmost covered: `p[p_idx] + (T - (current_h - p[p_idx])) = 2 * p[p_idx] - current_h + T`.
        //    This is valid if `p[p_idx] < current_h`.

        // So, if `p[p_idx] < current_h`:
        //   If `current_h - p[p_idx] > T`, then `current_h` cannot reach `p[p_idx]` by moving left.
        //   Since `p[p_idx] < current_h`, `current_h` cannot reach `p[p_idx]` by moving right either.
        //   So, `current_h` cannot cover `p[p_idx]`. Return false.
        //   Otherwise (`current_h - p[p_idx] <= T`), `current_h` can cover `p[p_idx]` by moving left.
        //   The rightmost point it can cover is `2 * p[p_idx] - current_h + T`.
        // If `p[p_idx] >= current_h`:
        //   If `p[p_idx] - current_h > T`, then `current_h` cannot reach `p[p_idx]` by moving right.
        //   Since `p[p_idx] >= current_h`, `current_h` cannot reach `p[p_idx]` by moving left either.
        //   So, `current_h` cannot cover `p[p_idx]`. Return false.
        //   Otherwise (`p[p_idx] - current_h <= T`), `current_h` can cover `p[p_idx]` by moving right.
        //   The rightmost point it can cover is `current_h + T`.

        // Let `max_reach` be the rightmost track that `current_h` can cover, given it must cover `p[p_idx]`.
        long long max_reach;
        if (p[p_idx] < current_h) { // p_start is to the left of current_h
            if (current_h - p[p_idx] > T) { // Cannot reach p_start
                return false; // This head cannot cover p[p_idx], and no subsequent head can either.
            }
            // Head moves left to p[p_idx], then can move right with remaining time.
            max_reach = p[p_idx] + (T - (current_h - p[p_idx]));
        } else { // p_start is at or to the right of current_h
            if (p[p_idx] - current_h > T) { // Cannot reach p_start
                return false; // This head cannot cover p[p_idx], and no subsequent head can either.
            }
            // Head moves right to p[p_idx], then can move further right.
            max_reach = current_h + T;
        }

        // Now, advance p_idx as long as p[p_idx] is covered by max_reach.
        while (p_idx < m && p[p_idx] <= max_reach) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

