    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance between p_m and h_1, or p_1 and h_n.
                               // Max p_i is 10^10, min h_i is 1. Max diff is 10^10.
                               // Max h_i is 10^10, min p_i is 1. Max diff is 10^10.
                               // So 10^10 is a reasonable upper bound.
                               // 2e10 + 7 is safe.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // We need to find b1, b2, ... such that (current_sum + sum_b) = 2 * (current_xor ^ xor_b)
    // Let sum_b = b1 + b2 + ...
    // Let xor_b = b1 ^ b2 ^ ...

    // Strategy: Append at most 2 elements.
    // Let's try to append two elements, say X_0 and S_0.
    // New sum S' = current_sum + X_0 + S_0
    // New xor X' = current_xor ^ X_0 ^ S_0
    // We want S' = 2 * X'

    // Let's try to append two elements: current_xor and current_sum.
    // This is not quite right. The problem is that current_sum can be very large.
    // The elements can be up to 10^18.

    // Consider the property: A + B = (A XOR B) + 2 * (A AND B)
    // This implies A + B >= A XOR B.
    // Also, A + B and A XOR B have the same parity.
    // (A + B) - (A XOR B) = 2 * (A AND B), which is always even.

    // We have current_sum and current_xor.
    // We want to append elements b_1, ..., b_s such that
    // (current_sum + sum(b_i)) = 2 * (current_xor ^ xor(b_i))

    // Let's try to append two elements:
    // 1. current_xor
    // 2. current_sum + current_xor
    // This is a common trick.
    // Let b1 = current_xor
    // Let b2 = current_sum + current_xor
    //
    // New sum S' = current_sum + b1 + b2
    //            = current_sum + current_xor + (current_sum + current_xor)
    //            = 2 * current_sum + 2 * current_xor
    //
    // New xor X' = current_xor ^ b1 ^ b2
    //            = current_xor ^ current_xor ^ (current_sum + current_xor)
    //            = 0 ^ (current_sum + current_xor)
    //            = current_sum + current_xor
    //
    // Check condition: S' = 2 * X'
    // (2 * current_sum + 2 * current_xor) = 2 * (current_sum + current_xor)
    // This is always true!

    // So, we can always append two elements: current_xor and (current_sum + current_xor).
    // The problem states that appended elements can be up to 10^18.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor can be up to 2^30 - 1 (since a_i <= 10^9 < 2^30).
    // So, current_sum + current_xor will be around 10^14, which fits in long long and is well within 10^18.

    // Output:
    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << current_sum + current_xor << std::endl;
}

