// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x such that p % x == 0 and x % q != 0.
        // This means x must be a divisor of p, and x must not be a multiple of q.
        // The strategy is to take p, and for each prime factor f of q,
        // remove enough factors of f from p to make it not divisible by q,
        // while keeping the resulting number as large as possible.
        // We do this for each distinct prime factor of q and take the maximum.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 1;

        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Count how many times f divides q
            long long q_f_count = 0;
            long long temp_q = q;
            while (temp_q > 0 && temp_q % f == 0) {
                q_f_count++;
                temp_q /= f;
            }

            // Count how many times f divides p
            long long p_f_count = 0;
            long long temp_p = p;
            while (temp_p > 0 && temp_p % f == 0) {
                p_f_count++;
                temp_p /= f;
            }

            // If p has fewer factors of f than q, then p is not divisible by q,
            // which contradicts the initial check `p % q != 0`.
            // So p_f_count must be >= q_f_count.
            // To make current_p not divisible by q (specifically, not divisible by f^q_f_count),
            // we need to reduce the count of f in current_p to p_f_count - q_f_count + 1 - 1 = p_f_count - q_f_count.
            // This means we divide p by f exactly (q_f_count - 1) + 1 = q_f_count times.
            // No, we need to divide p by f until it has fewer than q_f_count factors of f.
            // The largest such divisor is p / f^(q_f_count).
            // Example: p=12, q=6. f=2. q_f_count=1. p_f_count=2.
            // We need to remove 2 factors of 2 from p.
            // p / f^(p_f_count - (q_f_count - 1)) = p / f^(p_f_count - q_f_count + 1)
            // This is the largest divisor of p that has exactly (p_f_count - q_f_count) factors of f.
            // This divisor is p / f^(q_f_count).
            // No, this is wrong.
            // We want to find x = p / f^k such that x % q != 0.
            // The largest such x is p / f^(p_f_count - (q_f_count - 1)).
            // This means we want to reduce the power of f in p to (q_f_count - 1).
            // So we divide p by f^(p_f_count - (q_f_count - 1)).
            // This is equivalent to dividing p by f until its power of f is (q_f_count - 1).
            // The number of times we need to divide p by f is p_f_count - (q_f_count - 1).
            // Let's call this `num_divs`.
            long long num_divs = p_f_count - q_f_count + 1;
            for (int i = 0; i < num_divs; ++i) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

