int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<std::pair<int, int>> a_indexed(n);
        std::vector<std::pair<int, int>> b_indexed(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a_indexed[i].first;
            a_indexed[i].second = i; // Store original index
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b_indexed[i].first;
            b_indexed[i].second = i; // Store original index
        }

        // Sort both arrays based on brightness values
        std::sort(a_indexed.begin(), a_indexed.end());
        std::sort(b_indexed.begin(), b_indexed.end());

        // Create arrays to store the final assignment for each daughter
        // The i-th element of assigned_a will be the necklace for daughter i
        // The i-th element of assigned_b will be the bracelet for daughter i
        std::vector<int> assigned_a(n);
        std::vector<int> assigned_b(n);

        // The strategy is to pair the i-th smallest necklace with the i-th largest bracelet.
        // This ensures that the sums are distinct.
        // Specifically, if a_i is sorted ascending and b_i is sorted descending,
        // then a_i + b_i will be distinct.
        // Here, a_indexed is sorted ascending. We will use b_indexed in reverse order.
        for (int i = 0; i < n; ++i) {
            // The daughter who originally had the i-th smallest necklace (a_indexed[i].second)
            // will now receive the necklace a_indexed[i].first
            // and the bracelet b_indexed[n - 1 - i].first.
            // The problem asks for the output in the order of daughters (1 to n).
            // So, we assign the i-th sorted necklace to the i-th daughter,
            // and the i-th sorted bracelet (in reverse order) to the i-th daughter.
            assigned_a[i] = a_indexed[i].first;
            assigned_b[i] = b_indexed[n - 1 - i].first;
        }

        // Print the assigned necklaces
        for (int i = 0; i < n; ++i) {
            std::cout << assigned_a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";

        // Print the assigned bracelets
        for (int i = 0; i < n; ++i) {
            std::cout << assigned_b[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

