int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The problem asks for a different permutation p' with the same fingerprint.
        // Reversing the permutation p always yields a permutation p_rev
        // such that F(p_rev) = F(p).
        // This is because the set of adjacent sums {p_i + p_{i+1}} for p
        // is the same as the set of adjacent sums {p_{n-i} + p_{n-i-1}} for p_rev,
        // just in a different order. Since the fingerprint sorts these sums,
        // F(p) will be equal to F(p_rev).
        //
        // The only case where p_rev might be equal to p is if p is a palindrome.
        // However, a permutation of length n (n >= 2) cannot be a palindrome.
        // For p to be a palindrome, p_i must be equal to p_{n-1-i} for all i.
        // This means p_0 = p_{n-1}, p_1 = p_{n-2}, etc.
        // But a permutation consists of distinct integers from 1 to n.
        // So, p_0 cannot be equal to p_{n-1} unless n=1 (which is not allowed, n>=2).
        // Thus, p_rev is always different from p for n >= 2.
        //
        // Therefore, reversing the given permutation p always provides a valid solution.

        std::reverse(p.begin(), p.end());

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

