void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0]; // Use long long for current_a1 to avoid overflow if a[i] are large, though constraints suggest int is fine.
                                 // But it's good practice for sums.

    // Iterate through piles from 2nd to nth (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 (0-indexed 0)
        int cost_per_haybale = i; 

        // If we have enough days to move at least one haybale from this pile
        if (d >= cost_per_haybale) {
            // Calculate how many haybales we can move from this pile
            // We have 'a[i]' haybales in this pile.
            // We have 'd' days remaining.
            // Each haybale costs 'cost_per_haybale' days.
            int haybales_to_move = std::min(a[i], d / cost_per_haybale);

            current_a1 += haybales_to_move;
            d -= haybales_to_move * cost_per_haybale;
        } else {
            // If we don't even have enough days for one haybale from this pile,
            // we can't move any haybales from this pile or any further piles
            // (since further piles have higher costs).
            break; 
        }
    }

    std::cout << current_a1 << std::endl;
}

