void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The strategy is to use '2' as the first digit,
        // and '3' for all subsequent digits, except the last one.
        // The last digit will be '9'.
        // This forms a number like 233...39.
        // Let's check divisibility:
        // - Not divisible by 2 (ends in 9, which is odd).
        // - Not divisible by 3 (sum of digits: 2 + (n-2)*3 + 9 = 2 + 3n - 6 + 9 = 3n + 5.
        //   Since 3n is divisible by 3, 3n+5 is not divisible by 3).
        // - Not divisible by 9 (sum of digits 3n+5 is not divisible by 9,
        //   as 3n+5 is never a multiple of 9 for n >= 2.
        //   For n=2, sum=11. For n=3, sum=14. For n=4, sum=17.
        //   3n+5 mod 9:
        //   n=2: 11 mod 9 = 2
        //   n=3: 14 mod 9 = 5
        //   n=4: 17 mod 9 = 8
        //   n=5: 20 mod 9 = 2
        //   The sequence of (3n+5) mod 9 is 2, 5, 8, 2, 5, 8, ...
        //   It never becomes 0. So not divisible by 9.
        // All digits are non-zero.
        // This construction works for n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

