    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Exclude a[i][i] which is 0
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        // If max_val_in_row is n-1, then p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic works because if p[i] = n, then min(p[i], p[j]) = p[j] for all j != i.
        // The maximum of these p[j] values will be n-1.
        // If p[i] < n, then there must be some p[k] > p[i].
        // For any j such that p[j] >= p[i], min(p[i], p[j]) = p[i].
        // For any j such that p[j] < p[i], min(p[i], p[j]) = p[j].
        // The maximum of min(p[i], p[j]) over all j != i will be p[i].
        // This is because there must be at least one p[j] > p[i] (unless p[i]=n),
        // and for such p[j], min(p[i], p[j]) = p[i].
        // If all p[j] < p[i], then p[i] would be the largest, which is covered by the n-1 case.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
