        } else { // l is even
            std::cout << 2 << std::endl;
        }
    } else {
        // If l != r, the range contains at least two numbers.
        // If l is even, or l is odd but r is even, there is at least one even number.
        // If l is odd and r is odd, and l != r, then r = l + 2k for some k >= 1.
        // So l+1, l+3, ..., r-1 are all even numbers in the range.
