#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from C's stdio and disables synchronization,
    // which can significantly speed up I/O operations.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) { // Loop through each test case
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a std::vector to store prices.
        // Using a fixed-size array or dynamically allocated array is also possible,
        // but vector is convenient and safe.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n <= 1) {
            // If there's only one day or no days, no price can be "bad"
            // because there are no later days.
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_price_suffix with the last price.
        // This variable will store the minimum price encountered
        // from the current position to the end of the array (inclusive).
        int min_price_suffix = a[n - 1];

        // Iterate from the second-to-last day backwards to the first day.
        // For each day i, we compare a[i] with the minimum price found
        // in the suffix a[i+1...n-1].
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_price_suffix) {
                // If the current price a[i] is greater than the minimum price
                // found in any subsequent day, then a[i] is a bad price.
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_price_suffix, it means
                // a[i] is either equal to or less than the minimum price
                // in the suffix. In this case, a[i] itself becomes a new
                // candidate for the minimum price in the suffix starting from i.
                min_price_suffix = a[i];
            }
        }

        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

#include <iostream>
