int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams, we need at least 'mid' coders and 'mid' mathematicians.
            // The remaining students (c - mid) coders, (m - mid) mathematicians, and x no-specialization students
            // can be used to fill the remaining slots in the 'mid' teams.
            // Each team needs 3 members. 'mid' teams need 3 * mid members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, 2 * mid slots are filled.
            // We need to fill 'mid' more slots (3 * mid - 2 * mid = mid slots).
            // These 'mid' slots can be filled by any remaining student.
            // The total number of remaining students is (c - mid) + (m - mid) + x.

            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_r_pos = 0; // Represents the position of the last 'R' or the starting point (cell 0)

        // Iterate through the string to find 'R' characters
        // The string s has indices 0 to n-1, corresponding to cells 1 to n.
        // Cell 0 is the starting point.
        // Cell n+1 is the target.

        // We need to consider jumps from cell 0 to the first 'R' or n+1.
        // And jumps between consecutive 'R's.
        // And jumps from the last 'R' to n+1.

        // The positions of 'R' cells are 1-indexed.
        // If s[i] is 'R', it means cell i+1 is an 'R' cell.

        // Initial gap from cell 0 to the first 'R' or n+1
        // If the first char is 'R', then last_r_pos is 0, and the first 'R' is at index 0 (cell 1).
        // The gap is 1.
        // If the first char is 'L', we need to find the first 'R'.
        // Example: LLR. last_r_pos = 0. First 'R' is at index 2 (cell 3). Gap is 3-0 = 3.
        // Example: RRR. last_r_pos = 0. First 'R' is at index 0 (cell 1). Gap is 1-0 = 1.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current 'R' is at cell i+1.
                // The previous 'R' (or cell 0) was at last_r_pos.
                // The distance needed to jump from last_r_pos to i+1 is (i+1) - last_r_pos.
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1; // Update last_r_pos to the current 'R' cell
            }
        }

        // After iterating, last_r_pos holds the position of the last 'R' cell encountered.
        // We need to consider the jump from this last 'R' cell to the target cell n+1.
        // The distance needed is (n+1) - last_r_pos.
        max_gap = std::max(max_gap, (n + 1) - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

