#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to minimize |median(C1) - median(C2)|.
        // Let the sorted array be a_0, a_1, ..., a_{2n-1}.
        // The optimal strategy is to assign the smallest n elements to one class
        // and the largest n elements to the other class.
        // Specifically, the median of the first class will be a_{n-1}
        // and the median of the second class will be a_n.
        // This is because if we sort the entire array, the elements a_0, ..., a_{n-1}
        // are the smallest n elements, and a_n, ..., a_{2n-1} are the largest n elements.
        // If we form two classes of size n, this is not allowed as n can be even.
        // However, the problem states that each class must have an odd number of students.
        // The key insight is that the minimum difference is achieved by taking
        // the (n-1)-th element and the n-th element from the sorted array.
        // These correspond to a[n-1] and a[n] in 0-indexed sorted array.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // We need to pick two medians.
        // Let the first class have $k_1$ students and the second class have $k_2$ students.
        // $k_1, k_2$ must be odd, and $k_1 + k_2 = 2n$.
        // The median of a class of size $k$ is the element at index $(k-1)/2$ in its sorted list.
        //
        // The minimum possible difference is always achieved by taking the two middle elements
        // of the globally sorted array, i.e., a[n-1] and a[n].
        //
        // Proof sketch:
        // Let $m_1$ be the median of class $C_1$ and $m_2$ be the median of class $C_2$.
        // Suppose $m_1 < m_2$.
        // For $m_1$ to be the median of $C_1$ (size $k_1$), there must be at least $(k_1-1)/2$ elements
        // in $C_1$ that are less than or equal to $m_1$, and at least $(k_1-1)/2$ elements
        // in $C_1$ that are greater than or equal to $m_1$.
        // Similarly for $m_2$ and $C_2$ (size $k_2$).
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        // The value $a_{n-1}$ is the largest among the first $n$ elements.
        // The value $a_n$ is the smallest among the last $n$ elements.
        //
        // If we assign $a_0, \dots, a_{n-1}$ to one class and $a_n, \dots, a_{2n-1}$ to another,
        // this would be two classes of size $n$. This is not allowed if $n$ is even.
        //
        // However, the problem asks for the minimum possible absolute difference.
        // The minimum difference is always $|a_n - a_{n-1}|$.
        // We can always construct a partition that achieves this difference.
        //
        // Let $C_1$ consist of $a_0, \dots, a_{n-1}$.
        // Let $C_2$ consist of $a_n, \dots, a_{2n-1}$.
        // This is not a valid partition if $n$ is even.
        //
        // Consider the elements $a_0, \dots, a_{2n-1}$.
        // The median of the first $n$ elements is $a_{(n-1)/2}$ if $n$ is odd.
        // The median of the last $n$ elements is $a_{n + (n-1)/2}$ if $n$ is odd.
        //
        // The crucial observation is that the median of any class $C_X$ must be one of the $a_i$'s.
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Without loss of generality, assume $m_1 \le m_2$.
        //
        // For $m_1$ to be the median of $C_1$ (size $k_1$), there must be at least $(k_1-1)/2$ elements
        // in $C_1$ that are $\le m_1$ and at least $(k_1-1)/2$ elements in $C_1$ that are $\ge m_1$.
        //
        // For $m_2$ to be the median of $C_2$ (size $k_2$), there must be at least $(k_2-1)/2$ elements
        // in $C_2$ that are $\le m_2$ and at least $(k_2-1)/2$ elements in $C_2$ that are $\ge m_2$.
        //
        // The total number of elements less than or equal to $m_1$ is at least $(k_1-1)/2$.
        // The total number of elements greater than or equal to $m_2$ is at least $(k_2-1)/2$.
        //
        // Summing these up:
        // Number of elements $\le m_1$ is at least $(k_1-1)/2$.
        // Number of elements $\ge m_2$ is at least $(k_2-1)/2$.
        //
        // Since $m_1 \le m_2$, these two sets of elements are disjoint.
        // So, the total number of elements in the entire $2n$ student pool that are
        // either $\le m_1$ or $\ge m_2$ is at least $(k_1-1)/2 + (k_2-1)/2 = (k_1+k_2-2)/2 = (2n-2)/2 = n-1$.
        //
        // This means that there are at least $n-1$ elements that are not strictly between $m_1$ and $m_2$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        // The value $a_{n-1}$ is the $(n-1)$-th element (0-indexed).
        // The value $a_n$ is the $n$-th element (0-indexed).
        //
        // We can always form two classes $C_1$ and $C_2$ such that $a_{n-1}$ is the median of $C_1$
        // and $a_n$ is the median of $C_2$.
        //
        // For example, let $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$ and $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // If $n$ is odd, then $|C_1|=n$ and $|C_2|=n$ are both odd.
        // The median of $C_1$ is $a_{(n-1)/2}$. The median of $C_2$ is $a_{n+(n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler than that. The minimum difference is always $a_n - a_{n-1}$.
        // This is because we can always construct a partition where $a_{n-1}$ is the median of one class
        // and $a_n$ is the median of the other.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        // We need to pick $k_1$ elements for $C_1$ and $k_2$ elements for $C_2$, where $k_1, k_2$ are odd.
        //
        // Let's try to make $a_{n-1}$ the median of $C_1$ and $a_n$ the median of $C_2$.
        // To make $a_{n-1}$ the median of $C_1$, $C_1$ must contain $a_{n-1}$, and
        // $(k_1-1)/2$ elements $\le a_{n-1}$ and $(k_1-1)/2$ elements $\ge a_{n-1}$.
        // The elements $a_0, \dots, a_{n-2}$ are all $\le a_{n-1}$. There are $n-1$ such elements.
        // The elements $a_n, \dots, a_{2n-1}$ are all $\ge a_n > a_{n-1}$. There are $n$ such elements.
        //
        // We can form $C_1$ using $a_{n-1}$ as its median.
        // We can form $C_2$ using $a_n$ as its median.
        //
        // The minimum difference is indeed $a[n] - a[n-1]$.
        // This is a known result for this type of problem.
        // The two medians will be the two middle elements of the sorted array.
        //
        // Example 1: n=1, a = [1, 1]. Sorted: [1, 1]. n-1=0, n=1. a[0]=1, a[1]=1. Diff = 0.
        // Example 2: n=3, a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6]. n-1=2, n=3. a[2]=3, a[3]=4. Diff = 1.
        // Example 3: n=5, a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16]. Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // n-1=4, n=5. a[4]=8, a[5]=13. Diff = 5.
        //
        // The logic holds for all examples.
        // The proof relies on the fact that if you have $2n$ elements, and you partition them into two sets of odd sizes $k_1, k_2$,
        // then the median of the first set $m_1$ and the median of the second set $m_2$ must "straddle" the middle of the sorted array.
        // Specifically, $m_1 \le a_{n-1}$ and $m_2 \ge a_n$ (or vice versa).
        // This implies $|m_1 - m_2| \ge |a_n - a_{n-1}|$.
        //
        // To show this:
        // Let $m_1$ be the median of $C_1$ (size $k_1$) and $m_2$ be the median of $C_2$ (size $k_2$).
        // Assume $m_1 \le m_2$.
        // $C_1$ has $(k_1-1)/2$ elements $\le m_1$ and $(k_1-1)/2$ elements $\ge m_1$.
        // $C_2$ has $(k_2-1)/2$ elements $\le m_2$ and $(k_2-1)/2$ elements $\ge m_2$.
        //
        // The total number of elements $\le m_1$ is at least $(k_1-1)/2$.
        // The total number of elements $\ge m_2$ is at least $(k_2-1)/2$.
        //
        // Let $S_1 = \{x \in \text{all students} \mid x \le m_1\}$.
        // Let $S_2 = \{x \in \text{all students} \mid x \ge m_2\}$.
        // $|S_1| \ge (k_1-1)/2 + (\text{elements from } C_2 \text{ that are } \le m_1)$.
        // $|S_2| \ge (k_2-1)/2 + (\text{elements from } C_1 \text{ that are } \ge m_2)$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // Suppose $m_1 > a_{n-1}$. Then $m_1$ must be at least $a_n$.
        // If $m_1 \ge a_n$, then all $n$ elements $a_0, \dots, a_{n-1}$ are less than $m_1$.
        // If $m_2 < a_n$, then $m_2$ must be at most $a_{n-1}$.
        //
        // It can be shown that one median must be $\le a_{n-1}$ and the other must be $\ge a_n$.
        // Suppose both medians are $\le a_{n-1}$. Then $m_1 \le m_2 \le a_{n-1}$.
        // The number of elements $\ge m_2$ is at least $(k_2-1)/2$.
        // The number of elements $\ge m_1$ is at least $(k_1-1)/2$.
        // Total elements $\ge m_1$ is at least $(k_1-1)/2 + (k_2-1)/2 = n-1$.
        // But if $m_1 \le a_{n-1}$, then there are at most $n$ elements $\ge m_1$ (namely $a_{n-1}, \dots, a_{2n-1}$).
        // This doesn't lead to a contradiction directly.
        //
        // The standard argument is:
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Assume $m_1 \le m_2$.
        // $C_1$ has at least $(k_1+1)/2$ elements $\le m_1$.
        // $C_2$ has at least $(k_2+1)/2$ elements $\ge m_2$.
        //
        // The total number of elements $\le m_1$ in the entire set is at least $(k_1+1)/2$.
        // The total number of elements $\ge m_2$ in the entire set is at least $(k_2+1)/2$.
        //
        // If $m_1 > a_{n-1}$, then there are at most $n-1$ elements $\le a_{n-1}$.
        // So, if $m_1 > a_{n-1}$, then $m_1$ must be at least $a_n$.
        // If $m_2 < a_n$, then there are at most $n-1$ elements $\ge a_n$.
        // So, if $m_2 < a_n$, then $m_2$ must be at most $a_{n-1}$.
        //
        // It must be that $m_1 \le a_{n-1}$ and $m_2 \ge a_n$.
        // Suppose $m_1 > a_{n-1}$. Then $m_1 \ge a_n$.
        // This means that all elements $a_0, \dots, a_{n-1}$ are strictly less than $m_1$.
        // If $m_1$ is the median of $C_1$, then $C_1$ must contain $m_1$ and $(k_1-1)/2$ elements $\le m_1$.
        // If $m_1 \ge a_n$, then all elements $a_0, \dots, a_{n-1}$ are $\le m_1$.
        //
        // The simplest way to think about it is that the two medians must "cross" the global median split.
        // The $n$-th smallest element ($a_{n-1}$) and the $(n+1)$-th smallest element ($a_n$)
        // are the "middle" two elements of the entire sorted array.
        // Any partition into two odd-sized classes will have one median $\le a_{n-1}$ and the other $\ge a_n$.
        //
        // To achieve $a_n - a_{n-1}$:
        // We can form $C_1$ with $a_0, \dots, a_{n-1}$ and $C_2$ with $a_n, \dots, a_{2n-1}$.
        // This is not valid if $n$ is even.
        //
        // A valid construction:
        // Let $k_1 = 1$ and $k_2 = 2n-1$.
        // $C_1 = \{a_{n-1}\}$. Median is $a_{n-1}$.
        // $C_2 = \{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // This $C_2$ has $n-1 + n = 2n-1$ elements.
        // The elements in $C_2$ are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // The median of $C_2$ is $a_n$ because it's the $( (2n-1)-1 )/2 = n-1$-th element in $C_2$.
        // The elements $a_0, \dots, a_{n-2}$ are $n-1$ elements.
        // The element $a_n$ is the $(n-1)$-th element in $C_2$ (0-indexed).
        // So, the median of $C_2$ is $a_n$.
        //
        // This construction works for any $n \ge 1$.
        // For $n=1$, $2n=2$. $k_1=1, k_2=1$. $C_1=\{a_0\}$, $C_2=\{a_1\}$. Medians $a_0, a_1$. Diff $|a_1-a_0|$.
        // This matches $a_n - a_{n-1}$ for $n=1$.
        //
        // For $n > 1$:
        // $C_1 = \{a_{n-1}\}$. Median is $a_{n-1}$.
        // $C_2 = \{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // The elements of $C_2$ are sorted. Its size is $2n-1$.
        // The median is the element at index $((2n-1)-1)/2 = n-1$.
        // The elements $a_0, \dots, a_{n-2}$ are $n-1$ elements.
        // The next element is $a_n$. So $a_n$ is the $(n-1)$-th element (0-indexed) in $C_2$.
        // Thus, the median of $C_2$ is $a_n$.
        //
        // The absolute difference is $|a_n - a_{n-1}|$.
        // Since the array is sorted, $a_n \ge a_{n-1}$, so the difference is $a_n - a_{n-1}$.

        long long result = a[n] - a[n - 1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate differences up to k

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // After generating k distinct differences (1 to k),
    // the remaining numbers should be placed such that they don't introduce new distinct differences.
    // The simplest way is to place them in increasing order.
    // The last number used was either 'left-1' or 'right+1'.
    // The next available number is 'left' (if right was used last) or 'right' (if left was used last).
    // However, 'left' is always the next smallest available number.
    // So, we just append the remaining numbers in increasing order.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This is equivalent to p[i] = left; left++;
                      // Because after the loop, 'left' will be k+1 if k is even,
                      // and 'left' will be (k+1)/2 + 1 if k is odd.
                      // No, this is not correct.
                      // Let's trace:
                      // If k is even, p[k] = left, so left becomes (k/2)+1.
                      // The numbers used are 1, 2, ..., k/2 and k+1, k, ..., k/2+1.
                      // The next available number is (k/2)+1.
                      // If k is odd, p[k] = right, so right becomes (k+1)/2.
                      // The numbers used are 1, 2, ..., (k+1)/2 and k+1, k, ..., (k+1)/2+1.
                      // The next available number is (k+1)/2 + 1.
                      // In both cases, the next available number is k+1.
                      // So, we can just continue with k+1, k+2, ..., n.
        p[i] = left;
        left++;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k = n / m; // Number of multiples of m up to n

        if (k == 0) { // No multiples found
            std::cout << 0 << "\n";
            continue;
        }

        // Precompute the sum of last digits for the first 10 multiples of m
        // (m*1)%10, (m*2)%10, ..., (m*10)%10
        std::vector<long long> cycle_last_digits(10);
        for (int i = 0; i < 10; ++i) {
            cycle_last_digits[i] = (m * (i + 1)) % 10;
        }

        long long sum_of_one_cycle = 0;
        for (long long digit : cycle_last_digits) {
            sum_of_one_cycle += digit;
        }

        // Calculate how many full cycles of 10 multiples are there
        long long num_full_cycles = k / 10;
        long long total_sum = num_full_cycles * sum_of_one_cycle;

        // Add the sum of remaining multiples
        long long remaining_multiples = k % 10;
        for (int i = 0; i < remaining_multiples; ++i) {
            total_sum += cycle_last_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

