                // next_cost = (2 * (2^k - 1) + 1) * (2 * 2^(k-1))
                // This is not a simple recurrence.

                // Let's just calculate the next n and then its cost.
                // If current_cost is for n_prev, then n_prev = (sqrt(8*current_cost + 1) - 1) / 2.
                // This is integer arithmetic.
                // 8*current_cost + 1 must be a perfect square.
                // Let N_prev = (long long)((-1 + sqrt(8.0 * current_cost + 1.0)) / 2.0 + 0.5);
                // This is prone to precision issues for large numbers.
                // A better way:
                // The sequence of n values is 1, 3, 7, 15, ...
                // Each term is 2 * previous_term + 1.
                // So, if current_n is the n for current_cost, then next_n = 2 * current_n + 1.
                // We need to find current_n from current_cost.
                // current_cost = current_n * (current_n + 1) / 2.
                // 2 * current_cost = current_n^2 + current_n.
                // current_n^2 + current_n - 2 * current_cost = 0.
                // current_n = (-1 + sqrt(1 - 4 * 1 * (-2 * current_cost))) / 2
                // current_n = (-1 + sqrt(1 + 8 * current_cost)) / 2.
                // Since current_cost is always from the sequence (1, 6, 28, ...), 1 + 8*current_cost is always a perfect square.
                // Let's find current_n.
                // For current_cost = 1, current_n = (-1 + sqrt(9))/2 = (-1+3)/2 = 1.
                // For current_cost = 6, current_n = (-1 + sqrt(49))/2 = (-1+7)/2 = 3.
                // For current_cost = 28, current_n = (-1 + sqrt(225))/2 = (-1+15)/2 = 7.
                // This works.
                // So, we can find current_n, then next_n = 2 * current_n + 1, then next_cost = next_n * (next_n + 1) / 2.

                // However, a simpler observation:
                // The costs are 1, 6, 28, 120, 496, ...
                // Notice that 6 = 1 * 4 + 2
                // 28 = 6 * 4 + 4
                // 120 = 28 * 4 + 8
                // 496 = 120 * 4 + 16
                // The recurrence is C_k = 4 * C_{k-1} + 2^k.
                // Let's verify:
                // C_1 = 1
                // C_2 = 4*C_1 + 2^2 = 4*1 + 4 = 8. This is wrong. C_2 should be 6.
                // The recurrence is C_k = 2 * C_{k-1} + (2^k - 1) * 2^(k-1) - (2^(k-1) - 1) * 2^(k-2)
                // This is not simple.

                // Let's use the direct formula for the next cost:
                // current_cost = (2^k - 1) * 2^(k-1)
                // next_cost = (2^(k+1) - 1) * 2^k
                // next_cost = (2 * (2^k - 1) + 1) * 2^k
                // next_cost = (2 * (2^k - 1) + 1) * (2 * 2^(k-1))
                // This is not a simple recurrence.

                // Let's try to find a pattern for current_cost.
                // 1 = 1
                // 6 = 1 * 2 + 4
                // 28 = 6 * 2 + 16
                // 120 = 28 * 2 + 64
                // 496 = 120 * 2 + 256
                // The recurrence is C_k = 2 * C_{k-1} + 4^(k-1).
                // Let's check:
                // C_1 = 1
                // C_2 = 2 * C_1 + 4^(2-1) = 2 * 1 + 4 = 6. Correct.
                // C_3 = 2 * C_2 + 4^(3-1) = 2 * 6 + 16 = 12 + 16 = 28. Correct.
                // C_4 = 2 * C_3 + 4^(4-1) = 2 * 28 + 64 = 56 + 64 = 120. Correct.
                // C_5 = 2 * C_4 + 4^(5-1) = 2 * 120 + 256 = 240 + 256 = 496. Correct.
                // This is the recurrence relation for the costs.
                // So, current_cost = 2 * current_cost + power_of_4.
                // We need to keep track of power_of_4.
                // Initial power_of_4 for C_1 is 4^0 = 1.
                // For C_2, it's 4^1 = 4.
                // For C_k, it's 4^(k-1).
                // So, the next power_of_4 is 4 * current_power_of_4.

                long long next_power_of_4 = 4; // For the next iteration, k=2, 4^(k-1) = 4^1 = 4.
                current_cost = 1; // This is C_1.
                sum_of_costs = 0;
                count = 0;

                while (true) {
                    if (sum_of_costs + current_cost <= x) {
                        sum_of_costs += current_cost;
                        count++;
                        // Calculate the next cost
                        // C_k = 2 * C_{k-1} + 4^(k-1)
                        // Here, current_cost is C_{k-1}.
                        // next_cost = 2 * current_cost + next_power_of_4.
                        // next_power_of_4 is 4^(k-1).
                        // For the next iteration, we need 4^k.
                        if (current_cost > (x - next_power_of_4) / 2) { // Check for overflow before multiplication
                            break; // next_cost would exceed x, or 2*current_cost would overflow
                        }
                        current_cost = 2 * current_cost + next_power_of_4;
                        if (next_power_of_4 > x / 4) { // Check for overflow before multiplication
                            next_power_of_4 = x + 1; // Mark as too large
                        } else {
                            next_power_of_4 *= 4;
                        }
                    } else {
                        break;
                    }
                }
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] = index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx = pos[1], max_idx = pos[1]. Length = 1. Max value = 1.
        // This is a permutation of 1. So 1 is beautiful.

        // For m > 1, we need to expand the segment to include m.
        // The segment must contain 1, 2, ..., m.
        // The current segment covers values 1, ..., m-1.
        // Its boundaries are current_min_idx and current_max_idx.
        // To include 'm', we must expand the segment to include pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx, current_max_idx]
        // is a permutation of 1, ..., m.
        // This requires two conditions:
        // 1. The length of the segment must be m.
        //    (current_max_idx - current_min_idx + 1 == m)
        // 2. The maximum value in the segment must be m.
        //    (This is implicitly handled by how we expand current_min_idx/max_idx.
        //     Since we are iterating m from 1 to n, and always expanding
        //     the range to include pos[m], the maximum value in the
        //     segment [current_min_idx, current_max_idx] will always be m.
        //     The minimum value will always be 1 because pos[1] is always included.)

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

