        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // For a and b to be real, the discriminant d^2 - 4d must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, this implies d - 4 >= 0, so d >= 4.
        // The case d=0 is handled above.
        if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double sqrt_discriminant = std::sqrt(d * d - 4.0 * d);
            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // The problem statement implies a and b must be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d >= 4, then d-4 >= 0, so sqrt_discriminant is real and non-negative.
            // a = (d + sqrt_discriminant) / 2.0 is clearly non-negative.
            // b = (d - sqrt_discriminant) / 2.0.
            // We need to ensure d - sqrt_discriminant >= 0, which means d >= sqrt_discriminant.
            // Squaring both sides (both are non-negative): d^2 >= d^2 - 4d.
            // This simplifies to 0 >= -4d, or 4d >= 0, which is true for d >= 0.
            // So, both a and b will always be non-negative when d >= 4.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This marks the end of the non-decreasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }

    // If i is 0, the entire array is non-decreasing, so it's good.
    // If i is n-1, the last two elements are a[n-2] > a[n-1].
    // The suffix a[i...n-1] is a[i], a[i+1], ..., a[n-1].
    // At this point, a[i-1] > a[i] (if i > 0).
    // The suffix a[i...n-1] is non-decreasing.
    // We need to find the rightmost index `j` such that a[j] > a[j+1]
    // This marks the end of the non-increasing suffix (from right to left)
    // or the start of the non-decreasing suffix (from left to right).
    // The current `i` is the first element of the non-decreasing suffix from the right.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // n=7
    // i=6, a[5]=5, a[6]=2. a[5] > a[6]. Loop stops. i=6.
    // This is incorrect. The loop should find the first element of the "valley".
    // Let's re-evaluate.

    // Find the rightmost index `p` such that a[p] < a[p-1].
    // All elements from a[p] to a[n-1] form a non-decreasing suffix.
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // n=7
    // p=6, a[5]=3, a[6]=2. a[5] > a[6]. Loop stops. p=6.
    // This means a[6] is the start of the non-decreasing suffix.
    // The suffix is [2]. This is not what we want.

    // The logic is:
    // 1. Find the rightmost index `p` such that `a[p] < a[p-1]`.
    //    All elements from `a[p]` to `a[n-1]` form a non-decreasing sequence.
    //    Example: [4, 3, 3, 8, 4, 5, 2]
    //    n=7
    //    p=6: a[5]=5, a[6]=2. a[5] > a[6]. Loop stops. p=6.
    //    This means the suffix [a[6]] is non-decreasing.
    //    Example: [1, 2, 3, 4]
    //    p=3: a[2]=3, a[3]=4. a[2] <= a[3]. p becomes 2.
    //    p=2: a[1]=2, a[2]=3. a[1] <= a[2]. p becomes 1.
    //    p=1: a[0]=1, a[1]=2. a[0] <= a[1]. p becomes 0.
    //    Loop ends. p=0.
    //    This `p` is the starting index of the longest non-decreasing suffix.

    int p = n - 1;
    while (p > 0 && a[p-1] <= a[p]) {
        p--;
    }
    // After this loop, `a[p...n-1]` is a non-decreasing sequence.
    // If `p` is 0, the entire array is non-decreasing.

    // 2. Now, from `p-1` down to 0, find the rightmost index `q` such that `a[q] > a[q+1]`.
    //    All elements from `a[q]` to `a[p-1]` form a non-increasing sequence.
    //    Example: [4, 3, 3, 8, 4, 5, 2]
    //    From step 1, p=6.
    //    Now we look at elements from index p-1=5 downwards.
    //    q=5: a[5]=5, a[6]=2. a[5] > a[6]. This is not the right condition.
    //    We need to find the rightmost index `q` such that `a[q] > a[q+1]`
    //    where `q` is in the range `0` to `p-1`.
    //    This `q` marks the end of the non-increasing part before the non-decreasing part.
    //    The elements `a[q...p-1]` should be non-increasing.
    //    Example: [4, 3, 3, 8, 4, 5, 2]
    //    p=6.
    //    q starts at p-1 = 5.
    //    q=5: a[5]=5, a[4]=4. a[4] <= a[5]. q becomes 4.
    //    q=4: a[4]=4, a[3]=8. a[3] > a[4]. Loop stops. q=4.
    //    So, the suffix we are interested in starts at index `q`.
    //    The elements `a[q...n-1]` are `[4, 5, 2]`.
    //    This is the array we want to check if it's good.
    //    The prefix to remove is `a[0...q-1]`. Length `q`.

    int q = p; // Start checking from `p`
    while (q > 0 && a[q-1] >= a[q]) { // Find the first element from the right that breaks non-increasing
        q--;
    }
    // After this loop, `a[q...p-1]` is a non-increasing sequence (if q < p).
    // And `a[p...n-1]` is a non-decreasing sequence.
    // The combined sequence `a[q...n-1]` is the candidate for a "good" array.
    // The length of the prefix to remove is `q`.

    std::cout << q << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

