#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_possible: minimum value a[i] must be to satisfy a_1 < ... < a_i
    // If a_1' = 0, a_2' = 1, ..., a_i' = i-1, then a[i] must be at least i-1.
    // This is equivalent to a[i] >= i-1.
    // We can check this by iterating from left.
    // If a[i] < i, it's impossible to make a_i = i-1.
    // So, we need to find the first index `i` from the left where a[i] < i.
    // All elements before this index `i` (i.e., a[0]...a[i-1]) satisfy a[j] >= j.
    // The peak `k` must be at or before this index `i-1`.
    int left_limit = n; // The first index `i` such that a[i] < i.
                        // All indices `j < left_limit` satisfy a[j] >= j.
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_limit = i;
            break;
        }
    }

    // Calculate suffix_possible: minimum value a[i] must be to satisfy a_i > ... > a_n
    // If a_n' = 0, a_{n-1}' = 1, ..., a_i' = n-i-1, then a[i] must be at least n-i-1.
    // This is equivalent to a[i] >= n-1-i.
    // We can check this by iterating from right.
    // If a[i] < n-1-i, it's impossible to make a_i = n-1-i.
    // So, we need to find the first index `i` from the right where a[i] < n-1-i.
    // All elements after this index `i` (i.e., a[i+1]...a[n-1]) satisfy a[j] >= n-1-j.
    // The peak `k` must be at or after this index `i+1`.
    int right_limit = -1; // The first index `i` such that a[i] < n-1-i.
                          // All indices `j > right_limit` satisfy a[j] >= n-1-j.
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            right_limit = i;
            break;
        }
    }

    // A sharpened array is possible if there exists a peak index `k` (0-indexed)
    // such that:
    // 1. For the increasing part: a[k] >= k (i.e., k < left_limit)
    // 2. For the decreasing part: a[k] >= n-1-k (i.e., k > right_limit)
    // Combining these, we need to find if there's any index `k` such that
    // `k < left_limit` AND `k > right_limit`.
    // This means `right_limit < k < left_limit`.
    // If such a `k` exists, then `right_limit + 1 < left_limit`.
    // Or, more simply, if `left_limit > right_limit`.
    // The range of possible peak indices `k` is `[right_limit + 1, left_limit - 1]`.
    // If this range is non-empty, then a sharpened array is possible.
    // This is true if `right_limit + 1 <= left_limit - 1`, or `right_limit + 2 <= left_limit`.
    // However, the condition is just that there is *some* `k`.
    // If `left_limit > right_limit`, then there is at least one `k` (e.g., `right_limit + 1` if `right_limit + 1 < left_limit`).
    // The condition `left_limit > right_limit` means there is at least one index `i`
    // that satisfies both `a[i] >= i` and `a[i] >= n-1-i`.
    // This is exactly what we need.

    if (left_limit > right_limit) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
