struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Sort array B elements based on their values in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // Assign elements from sorted A to A' based on sorted B's original indices
    // The largest A_i should be paired with the largest B_j (which means smallest k_j)
    // The smallest A_i should be paired with the smallest B_j (which means largest k_j)
    // This means we pair a[i] with b_elements[m-1-i]
    // The element a[i] (from sorted A) should go to the position b_elements[m-1-i].original_index
    for (int i = 0; i < m; ++i) {
        a_prime[b_elements[i].original_index] = a[m - 1 - i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a prefix of length 'len' is a permutation
// max_val_prefix[len-1] stores the maximum value in a[0...len-1]
// is_distinct_prefix[len-1] is true if a[0...len-1] contains distinct elements
bool is_prefix_permutation(int len, const std::vector<int>& max_val_prefix, const std::vector<bool>& is_distinct_prefix) {
    if (len == 0) return false; // Permutation length must be non-zero
    return is_distinct_prefix[len - 1] && (max_val_prefix[len - 1] == len);
}

// Function to check if a suffix of length 'len' is a permutation
// max_val_suffix[n-len] stores the maximum value in a[n-len...n-1]
// is_distinct_suffix[n-len] is true if a[n-len...n-1] contains distinct elements
bool is_suffix_permutation(int len, int n, const std::vector<int>& max_val_suffix, const std::vector<bool>& is_distinct_suffix) {
    if (len == 0) return false; // Permutation length must be non-zero
    return is_distinct_suffix[n - len] && (max_val_suffix[n - len] == len);
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> max_val_prefix(n);
    std::vector<bool> is_distinct_prefix(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n, so size n+1
    int current_max_prefix = 0;
    bool current_distinct_prefix = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max value in permutation of length k is k.
                                             // If a[i] > n, it can't be part of any permutation of length <= n.
                                             // However, a[i] can be up to n-1, so a[i] > i+1 is more accurate for permutation check.
                                             // But for distinctness, a[i] > n is fine.
            current_distinct_prefix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_prefix = std::max(current_max_prefix, a[i]);
        max_val_prefix[i] = current_max_prefix;
        is_distinct_prefix[i] = current_distinct_prefix;
    }

    // Precompute for suffixes
    std::vector<int> max_val_suffix(n);
    std::vector<bool> is_distinct_suffix(n);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix for suffix check
    int current_max_suffix = 0;
    bool current_distinct_suffix = true;

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || seen_prefix[a[i]]) {
            current_distinct_suffix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_suffix = std::max(current_max_suffix, a[i]);
        max_val_suffix[i] = current_max_suffix;
        is_distinct_suffix[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, l2 must be at least 1
        int l2 = n - l1;
        if (is_prefix_permutation(l1, max_val_prefix, is_distinct_prefix) &&
            is_suffix_permutation(l2, n, max_val_suffix, is_distinct_suffix)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;

    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is better than N/2 for Chanek
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n / 2 != 1) { // N/2 is odd and N/2 > 1
                    // If Chanek takes N/2, opponent gets an odd number of coins (N/2)
                    // and will be forced to take 1.
                    // If Chanek takes 1, opponent gets an even number of coins (N-1).
                    // Taking 1 coin leaves N-1, which is odd. Opponent will take 1.
                    // Chanek gets 1, Opponent gets 1.
                    // Taking N/2 coins leaves N/2, which is odd. Opponent will take 1.
                    // Chanek gets N/2, Opponent gets 1.
                    // So Chanek prefers N/2.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even or N/2 == 1
                    // If N/2 is even, opponent can take N/4.
                    // If Chanek takes N/2, opponent gets an even number of coins (N/2).
                    // If Chanek takes 1, opponent gets an odd number of coins (N-1).
                    // Chanek prefers to take 1 to force opponent to take 1.
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is better than N/2 for opponent
                    opponent_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n / 2 != 1) { // N/2 is odd and N/2 > 1
                    // Opponent prefers N/2 to maximize their own coins.
                    opponent_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even or N/2 == 1
                    // Opponent prefers to take 1 to force Chanek to take 1.
                    opponent_coins += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

