    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // We need S' = 2 * X'
        // Let S' = current_sum + b1 + b2 + ...
        // Let X' = current_xor_sum ^ b1 ^ b2 ^ ...

        // Strategy: Append at most 3 elements.
        // We can always make it good by appending two elements.
        // Let's append b1 and b2.
        // We want (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2).

        // Let b1 = current_xor_sum.
        // Then X' = current_xor_sum ^ current_xor_sum ^ b2 = 0 ^ b2 = b2.
        // The condition becomes (current_sum + current_xor_sum + b2) = 2 * b2.
        // current_sum + current_xor_sum = 2 * b2 - b2
        // current_sum + current_xor_sum = b2.

        // So, if we choose b1 = current_xor_sum and b2 = current_sum + current_xor_sum,
        // the new sum S' = current_sum + current_xor_sum + (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum).
        // The new XOR sum X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum) = 0 ^ (current_sum + current_xor_sum) = current_sum + current_xor_sum.
        // Thus, S' = 2 * X' is satisfied.

        // The number of elements to append is 2.
        // The elements are current_xor_sum and current_sum + current_xor_sum.

        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
    return 0;
}

