// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        return "0"; // Special case for 0
    }
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern_str += '0';
        } else { // Odd digit
            pattern_str += '1';
        }
        n /= 10;
    }
    std::reverse(pattern_str.begin(), pattern_str.end()); // Digits were extracted right-to-left, reverse to get left-to-right
    return pattern_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Using a map to store counts of numbers based on their 18-digit parity pattern.
    // The key will be a string of 18 '0's and '1's.
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            // Pad with '0's from the left to make it 18 characters long
            // This effectively means padding the number with leading zeros for comparison
            // e.g., 1 -> "00...001", 241 -> "00...0101"
            std::string padded_pattern(18 - pattern.length(), '0');
            padded_pattern += pattern;
            counts[padded_pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            std::string padded_pattern(18 - pattern.length(), '0');
            padded_pattern += pattern;
            counts[padded_pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to make it 18 characters long
            std::string padded_query_pattern(18 - s.length(), '0');
            padded_query_pattern += s;
            std::cout << counts[padded_query_pattern] << "\n";
        }
    }

    return 0;
}

