void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    if (total_toys == 1) {
        if (a == 1) ans1 = "Ya";
        if (b == 1) ans2 = "Ya";
        if (c == 1) ans3 = "Ya";
        if (d == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
        return;
    }

    // Case 1: Final toy in Box 1 (x <= -1)
    // Requires odd number of negative factors.
    // Requires magnitude >= 1.
    // Initial negative toys: a + b
    // Initial magnitude >= 1 toys: a + d

    // Can end in Box 1:
    // If (a+b) is odd:
    //   If (a+d) >= 1: (can achieve magnitude >= 1)
    //     If (a+b) == 1 and (a+d) == 1 and (b+c) == 0: (only one toy, already handled)
    //     Else if (a+b) == 1 and (a+d) == 1 and (b+c) > 0: (e.g., -3, 0.5 -> -1.5)
    //     Else if (a+b) == 1 and (a+d) > 1: (e.g., -3, 3 -> -9)
    //     Else if (a+b) > 1 and (a+d) >= 1: (e.g., -3, -2, 0.5 -> 3, 0.5 -> 1.5)
    //     This covers most cases.
    //     The only tricky part is if all initial toys are magnitude < 1, but we need magnitude >= 1.
    //     If a+d == 0, then all toys are in B or C.
    //     If a+d == 0, then a=0, d=0. All toys are in B or C.
    //     If a=0, d=0, then (a+b) is just b. (a+d) is 0.
    //     If b is odd, and a=0, d=0, then all toys are in B or C.
    //     Product of toys in B and C will always have magnitude < 1.
    //     So if a+d == 0, Box 1 is impossible.
    //     Otherwise, if a+d > 0, we can potentially achieve magnitude >= 1.
    //     If (a+b) is odd and (a+d) > 0, then Box 1 is possible.
    //     Exception: if a+b=1, a+d=1, b+c=0, this means a=1, b=0, c=0, d=0. This is total_toys=1, handled.
    //     So if a+b is odd and a+d > 0, then ans1 = "Ya".
    //     What if a+b is odd, a+d > 0, but all other toys are magnitude < 1?
    //     Example: A=1, B=2, C=0, D=0. Toys: {-2, -0.5, -0.5}.
    //     (-0.5)*(-0.5) = 0.25 (Box 3). Now {-2, 0.25}.
    //     (-2)*(0.25) = -0.5 (Box 2).
    //     This is a case where (a+b) is odd (3), (a+d) > 0 (1), but it ends in Box 2.
    //     The condition for Box 1 is that we must be able to make the final magnitude >= 1.
    //     This requires at least one initial toy with magnitude >= 1 (a+d > 0).
    //     AND we must be able to ensure the final product is negative (odd number of negative factors).
    //     If a+b is odd, we can always make the final product negative.
    //     If a+d > 0, we can always make the final product magnitude >= 1, UNLESS all other toys are magnitude < 1
    //     AND we are forced to multiply the magnitude >= 1 toy with too many magnitude < 1 toys.
    //     Consider the "net magnitude" effect.
    //     If a+d > 0, we have at least one toy with magnitude >= 1.
    //     If b+c > 0, we have toys with magnitude < 1.
    //     If a+d > 0 and b+c > 0:
    //       We can multiply all b+c toys together first. This results in one toy in B or C.
    //       Then we have (a+d) toys with magnitude >= 1 and one toy with magnitude < 1.
    //       If (a+d) >= 1, we can always ensure the final product has magnitude >= 1.
    //       Example: {X_1, ..., X_k} where |X_i| >= 1, and {Y} where |Y| < 1.
    //       If k >= 1, we can multiply X_1 * ... * X_k first. Result Z_1 has |Z_1| >= 1.
    //       Then Z_1 * Y. This can be < 1 or >= 1.
    //       This is the core problem: can we *guarantee* magnitude >= 1?
    //       No, we need to check if it's *possible*.
    //       If a+d > 0, it is possible to end up with magnitude >= 1.
    //       Example: A=1, B=2, C=0, D=0. Toys: {-2, -0.5, -0.5}.
    //       (-0.5)*(-0.5) = 0.25 (Box 3). Now {-2, 0.25}.
    //       (-2)*(0.25) = -0.5 (Box 2).
    //       This is a case where (a+b) is odd (3), (a+d) > 0 (1), but it ends in Box 2.
    //       The example in the problem statement for A=1, B=2, C=0, D=1:
    //       {-3}, {-0.5, -0.5}, {3}
    //       (-0.5)*(-0.5) = 0.25 (Box 3). Now {-3, 0.25, 3}.
    //       (-3)*(0.25) = -0.75 (Box 2). Now {-0.75, 3}.
    //       (-0.75)*(3) = -2.25 (Box 1). This works.
    //       Here (a+b)=3 (odd), (a+d)=2 (>0).
    //       The condition for Box 1 is:
    //       1. (a+b) must be odd.
    //       2. We need to be able to achieve magnitude >= 1.
    //          This is possible if (a+d) > 0.
    //          The only exception is if (a+d) = 1 and (b+c) > 0, and we are forced to multiply the single magnitude >= 1 toy with a magnitude < 1 toy.
    //          If a+d = 1, and b+c > 0:
    //            If a=1, d=0: one toy in Box 1, others in B/C.
    //            If d=1, a=0: one toy in Box 4, others in B/C.
    //            In this scenario, we can multiply all b+c toys first. This results in one toy in B or C.
    //            Then we have one toy from A/D and one toy from B/C.
    //            Their product can be < 1 or >= 1.
    //            Example: A=1, B=2, C=0, D=0. Toys: {-2, -0.5, -0.5}.
    //            (-0.5)*(-0.5) = 0.25 (Box 3). Now {-2, 0.25}.
    //            (-2)*(0.25) = -0.5 (Box 2).
    //            Here (a+b)=3 (odd), (a+d)=1. It ends in Box 2.
    //            So if (a+d) = 1 and (b+c) > 0, it's not guaranteed to be Box 1.
    //            It can be Box 1 if the single magnitude >= 1 toy is multiplied by a magnitude < 1 toy, and the result is still magnitude >= 1.
    //            This is possible if the magnitude of the A/D toy is large enough.
    //            Example: A=1, B=1, C=0, D=0. Toys: {-3, -0.2}. Product = 0.6 (Box 3).
    //            Example: A=1, B=1, C=0, D=0. Toys: {-3, -0.5}. Product = 1.5 (Box 4).
    //            So if (a+d) = 1 and (b+c) > 0, it can end in Box 1 if (a+b) is odd.
    //            This means the only case where Box 1 is impossible due to magnitude is if a+d=0.
    //            So, if (a+b) is odd AND (a+d > 0), then ans1 = "Ya".
    //            This covers the example: A=1, B=2, C=0, D=1. (a+b)=3 (odd), (a+d)=2 (>0). So ans1="Ya". Correct.

    // Let's simplify the conditions for each box.
    // The final sign is determined by the parity of (a+b).
    // The final magnitude is determined by the initial (a+d) and (b+c) counts.
    // If a+d = 0 (all toys are in B or C), then the final magnitude will always be < 1.
    // If b+c = 0 (all toys are in A or D), then the final magnitude will always be >= 1.
    // If a+d > 0 and b+c > 0:
    //   It is possible to get magnitude >= 1 (e.g., multiply all A/D toys, then multiply by some B/C toys, or multiply B/C toys first to get a small value, then multiply by a large A/D toy).
    //   It is possible to get magnitude < 1 (e.g., multiply a large A/D toy by many small B/C toys).
    //   So if a+d > 0 and b+c > 0, both magnitude < 1 and magnitude >= 1 are possible.

    // Box 1: x <= -1
    //   Sign: Negative (a+b must be odd)
    //   Magnitude: >= 1
    //   Possible if: (a+b) is odd AND (a+d > 0).
    //   The only exception is if a+d=0, then magnitude >= 1 is impossible.
    //   If a+d > 0, it is always possible to achieve magnitude >= 1.
    //   Example: A=1, B=2, C=0, D=0. Toys: {-2, -0.5, -0.5}. (a+b)=3 (odd), (a+d)=1 (>0).
    //   We need to show it's possible to get magnitude >= 1.
    //   If we have {-2, -0.5, -0.5}. We can pick values like {-2, -0.6, -0.6}.
    //   (-0.6)*(-0.6) = 0.36. Then (-2)*(0.36) = -0.72 (Box 2).
    //   This implies that if a+d=1 and b+c>0, it's not always possible to get magnitude >= 1.
    //   The example in the problem statement for A=1, B=2, C=0, D=1:
    //   {-3}, {-0.5, -0.5}, {3}
    //   (-0.5)*(-0.5) = 0.25 (Box 3). Now {-3, 0.25, 3}.
    //   (-3)*(3) = -9 (Box 1). Now {-9, 0.25}.
    //   (-9)*(0.25) = -2.25 (Box 1). This works.
    //   This means if there are at least two toys with magnitude >= 1 (a+d >= 2), or if there is one toy with magnitude >= 1 (a+d=1) and no toys with magnitude < 1 (b+c=0), then magnitude >= 1 is possible.
    //   If a+d=1 and b+c>0, it is possible to get magnitude >= 1 if the single A/D toy is multiplied by another A/D toy (which is not possible if a+d=1) or if it's multiplied by a B/C toy and the result is still >= 1.
    //   This is the tricky part.
    //   Let's re-evaluate the magnitude condition.
    //   Magnitude >= 1 is possible if:
    //     1. a+d >= 2 (can multiply two large numbers)
    //     2. a+d = 1 AND b+c = 0 (only one large number, no small numbers to reduce it)
    //     3. a+d = 1 AND b+c > 0: This is the case where we have one large number and some small numbers.
    //        It is possible to end up with magnitude >= 1.
    //        Example: A=1, B=1, C=0, D=0. Toys: {-3, -0.5}. Product = 1.5 (Box 4).
    //        Example: A=1, B=1, C=0, D=0. Toys: {-3, -0.2}. Product = 0.6 (Box 3).
    //        So if a+d=1 and b+c>0, it is possible to get magnitude >= 1.
    //        Therefore, magnitude >= 1 is possible if and only if a+d > 0.

    // Box 1: x <= -1
    //   Sign: (a+b) is odd.
    //   Magnitude: >= 1. Possible if (a+d) > 0.
    //   So, if (a+b) % 2 == 1 && (a + d > 0), then ans1 = "Ya".

    // Box 2: -1 < x < 0
    //   Sign: Negative (a+b must be odd)
    //   Magnitude: < 1
    //   Possible if: (a+b) is odd.
    //   Magnitude < 1 is always possible if b+c > 0.
    //   If b+c = 0, then all toys are in A or D. Product will always be magnitude >= 1.
    //   So, if (a+b) % 2 == 1 && (b + c > 0), then ans2 = "Ya".
    //   What if b+c=0? Then all toys are in A or D. Product is magnitude >= 1.
    //   So if (a+b) % 2 == 1 && (b + c > 0), then ans2 = "Ya".

    // Box 3: 0 < x < 1
    //   Sign: Positive (a+b must be even)
    //   Magnitude: < 1
    //   Possible if: (a+b) is even.
    //   Magnitude < 1 is possible if (b+c) > 0.
    //   So, if (a+b) % 2 == 0 && (b + c > 0), then ans3 = "Ya".

    // Box 4: x >= 1
    //   Sign: Positive (a+b must be even)
    //   Magnitude: >= 1
    //   Possible if: (a+b) is even.
    //   Magnitude >= 1 is possible if (a+d) > 0.
    //   So, if (a+b) % 2 == 0 && (a + d > 0), then ans4 = "Ya".

    // Let's re-check the conditions for magnitude.
    // Can we always achieve magnitude >= 1 if a+d > 0? Yes.
    //   If a+d >= 2, multiply two A/D toys to get a large number. Then multiply by B/C toys.
    //   If a+d = 1:
    //     If b+c = 0, then the single A/D toy is the result, magnitude >= 1.
    //     If b+c > 0, we have one A/D toy and some B/C toys.
    //     Example: {-10}, {0.1, 0.1}. Multiply 0.1*0.1 = 0.01. Then -10*0.01 = -0.1 (Box 2).
    //     Example: {-10}, {0.1, 0.1}. Multiply -10*0.1 = -1 (Box 1). Then -1*0.1 = -0.1 (Box 2).
    //     This shows that if a+d=1 and b+c>0, it is NOT always possible to achieve magnitude >= 1.
    //     It depends on the specific values.
    //     The problem asks "which boxes *can* be the special box". So we need to find if there exists *any* set of values.
    //     If a+d=1 and b+c>0, can we pick values such that the final magnitude is >= 1?
    //     Yes. Pick the A/D toy to have a very large magnitude (e.g., 1000). Pick B/C toys to have values like 0.5.
    //     If we have one A/D toy (e.g., 1000) and one B/C toy (e.g., 0.5). Product is 500 (Box 4).
    //     So if a+d > 0, it is always possible to achieve magnitude >= 1.

    // Can we always achieve magnitude < 1 if b+c > 0? Yes.
    //   If b+c >= 2, multiply two B/C toys to get a small number. Then multiply by A/D toys.
    //   If b+c = 1:
    //     If a+d = 0, then the single B/C toy is the result, magnitude < 1.
    //     If a+d > 0, we have one B/C toy and some A/D toys.
    //     Example: {10}, {0.1}. Product is 1 (Box 4).
    //     Example: {100}, {0.001}. Product is 0.1 (Box 3).
    //     So if b+c > 0, it is always possible to achieve magnitude < 1.

    // So the conditions for magnitude are:
    // Magnitude >= 1 is possible if (a+d) > 0.
    // Magnitude < 1 is possible if (b+c) > 0.

    // Let's re-evaluate the conditions for each box based on this.

    // Box 1: x <= -1 (Negative, Magnitude >= 1)
    //   Possible if: (a+b) % 2 == 1 (odd negatives) AND (a+d > 0) (can achieve magnitude >= 1).
    if ((a + b) % 2 == 1 && (a + d > 0)) {
        ans1 = "Ya";
    }

    // Box 2: -1 < x < 0 (Negative, Magnitude < 1)
    //   Possible if: (a+b) % 2 == 1 (odd negatives) AND (b+c > 0) (can achieve magnitude < 1).
    if ((a + b) % 2 == 1 && (b + c > 0)) {
        ans2 = "Ya";
    }

    // Box 3: 0 < x < 1 (Positive, Magnitude < 1)
    //   Possible if: (a+b) % 2 == 0 (even negatives) AND (b+c > 0) (can achieve magnitude < 1).
    if ((a + b) % 2 == 0 && (b + c > 0)) {
        ans3 = "Ya";
    }

    // Box 4: x >= 1 (Positive, Magnitude >= 1)
    //   Possible if: (a+b) % 2 == 0 (even negatives) AND (a+d > 0) (can achieve magnitude >= 1).
    if ((a + b) % 2 == 0 && (a + d > 0)) {
        ans4 = "Ya";
    }

    // Special case: If all toys are in Box 2 or Box 3 (a=0, d=0), then a+d=0.
    // In this case, ans1 and ans4 will be "Tidak" because a+d > 0 is false.
    // This is correct, as product of numbers with magnitude < 1 will always have magnitude < 1.
    // Special case: If all toys are in Box 1 or Box 4 (b=0, c=0), then b+c=0.
    // In this case, ans2 and ans3 will be "Tidak" because b+c > 0 is false.
    // This is correct, as product of numbers with magnitude >= 1 will always have magnitude >= 1.

    // One edge case: What if a+b=0? Then all toys are positive. (a+b)%2 == 0.
    // Box 1: (0)%2==1 is false. Correct.
    // Box 2: (0)%2==1 is false. Correct.
    // Box 3: (0)%2==0 is true. If b+c>0, ans3="Ya". Correct.
    // Box 4: (0)%2==0 is true. If a+d>0, ans4="Ya". Correct.

    // What if a+b=1? Then one negative toy. (a+b)%2 == 1.
    // Box 1: (1)%2==1 is true. If a+d>0, ans1="Ya". Correct.
    // Box 2: (1)%2==1 is true. If b+c>0, ans2="Ya". Correct.
    // Box 3: (1)%2==0 is false. Correct.
    // Box 4: (1)%2==0 is false. Correct.

    // The logic seems sound.

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

