int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // prefix_counts[i][j] stores the count of character 'x' (j=0), 'y' (j=1), 'z' (j=2)
    // in the prefix s[0...i-1].
    // prefix_counts[0] is all zeros.
    // prefix_counts[k] stores counts for s[0...k-1].
    std::vector<std::vector<int>> prefix_counts(n + 1, std::vector<int>(3, 0));

    for (int i = 0; i < n; ++i) {
        prefix_counts[i + 1] = prefix_counts[i]; // Copy counts from previous prefix
        if (s[i] == 'x') {
            prefix_counts[i + 1][0]++;
        } else if (s[i] == 'y') {
            prefix_counts[i + 1][1]++;
        } else { // s[i] == 'z'
            prefix_counts[i + 1][2]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        // Adjust to 0-based indexing
        // Substring is s[l-1 ... r-1]
        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Calculate counts of 'x', 'y', 'z' in the substring s[l-1 ... r-1]
        int count_x = prefix_counts[r][0] - prefix_counts[l - 1][0];
        int count_y = prefix_counts[r][1] - prefix_counts[l - 1][1];
        int count_z = prefix_counts[r][2] - prefix_counts[l - 1][2];

        // The algorithm terminates if and only if it's possible to reach a state
        // where all 3-character substrings are one of "zyx", "xzy", "yxz".
        // This implies that the counts of 'x', 'y', 'z' in any 3-character substring
        // must be exactly one 'x', one 'y', and one 'z'.
        // If the total counts of 'x', 'y', 'z' in the entire substring s[l-1 ... r-1]
        // are too far apart, it's impossible to satisfy this condition for all 3-char substrings.
        // Specifically, the difference between the maximum and minimum count of any character
        // in the substring must be at most 1.
        // For example, if counts are (5, 2, 2), then max-min = 3 > 1, so NO.
        // If counts are (4, 3, 3), then max-min = 1, so YES.
        // If counts are (3, 3, 3), then max-min = 0, so YES.

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

