bool is_sorted(const std::string& s) {
    for (size_t i = 0; i + 1 < s.length(); ++i) {
        if (s[i] > s[i+1]) {
            return false;
        }
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::string result(n, ' ');

    for (int x = 0; x <= 9; ++x) { // x is the split digit
        std::string s1_temp;
        std::string s2_temp;
        bool possible_x = true;

        // First pass: assign digits < x to color 1, digits > x to color 2
        // Digits == x are initially unassigned
        for (int i = 0; i < n; ++i) {
            int digit = d_str[i] - '0';
            if (digit < x) {
                result[i] = '1';
                s1_temp += d_str[i];
            } else if (digit > x) {
                result[i] = '2';
                s2_temp += d_str[i];
            }
        }

        // Check if s1_temp and s2_temp are already sorted
        if (!is_sorted(s1_temp) || !is_sorted(s2_temp)) {
            continue; // This x won't work
        }

        // Second pass: assign digits == x
        // All digits == x that are colored 1 must come before all digits == x that are colored 2.
        // To maximize chances of success, we try to color as many 'x's as possible with '1'
        // as long as it maintains the sorted property of s1_temp.
        // Then, the remaining 'x's are colored '2'.

        // Find the last digit of s1_temp (if any)
        char last_s1_char = (s1_temp.empty() ? '0' : s1_temp.back()); // '0' is a safe lower bound

        // Find the first digit of s2_temp (if any)
        char first_s2_char = (s2_temp.empty() ? '9' + 1 : s2_temp.front()); // '9'+1 is a safe upper bound

        // If s1_temp is not empty and s2_temp is not empty, check the boundary condition
        if (!s1_temp.empty() && !s2_temp.empty() && last_s1_char > first_s2_char) {
            continue; // This x won't work
        }

        // Now, process digits equal to x
        // We need to find a split point for digits equal to x.
        // All d_i = x before this split point go to S1, all after go to S2.
        // This split point must be chosen such that S1 and S2 remain sorted.
        // The digits d_i = x that go to S1 must be >= last_s1_char.
        // The digits d_i = x that go to S2 must be <= first_s2_char.
        // Since all these digits are 'x', this is always true.
        // The only constraint is that the sequence of 'x's within S1 must be non-decreasing,
        // and similarly for S2. Since they are all 'x', this is also true.
        // The critical part is the split point for 'x's.
        // We want to find an index `k` such that d_i = x for i < k are colored 1,
        // and d_i = x for i >= k are colored 2.
        // This is equivalent to finding the first 'x' that should be colored 2.

        int first_x_to_color_2_idx = -1;
        for (int i = n - 1; i >= 0; --i) {
            if (d_str[i] - '0' == x) {
                first_x_to_color_2_idx = i;
                break;
            }
        }

        // If no 'x' digits, then this x is valid if s1_temp and s2_temp are sorted and boundary condition holds.
        // We already checked this.
        if (first_x_to_color_2_idx == -1) {
            std::cout << result << "\n";
            return;
        }

        // Try to find the optimal split point for 'x's
        // All 'x's before `first_x_to_color_2_idx` are colored 1.
        // All 'x's from `first_x_to_color_2_idx` onwards are colored 2.
        // This is the strategy: color all 'x's with '1' first, then find the first 'x' that breaks the sorted property of S1,
        // and color it and all subsequent 'x's with '2'.

        std::string current_s1;
        std::string current_s2;
        bool current_possible = true;

        for (int i = 0; i < n; ++i) {
            int digit = d_str[i] - '0';
            if (digit < x) {
                result[i] = '1';
                current_s1 += d_str[i];
            } else if (digit > x) {
                result[i] = '2';
                current_s2 += d_str[i];
            } else { // digit == x
                // Try to color 'x's with '1' as long as possible
                if (current_s1.empty() || d_str[i] >= current_s1.back()) {
                    result[i] = '1';
                    current_s1 += d_str[i];
                } else {
                    // This 'x' cannot be colored '1' without breaking S1's sorted property.
                    // So, this 'x' and all subsequent 'x's must be colored '2'.
                    // This implies that all 'x's before this one must have been colored '1'.
                    // And all 'x's from this point onwards must be colored '2'.
                    // This is the split point for 'x's.
                    // Let's re-evaluate the coloring for 'x's based on this split.

                    // Reset result and rebuild based on the split point for 'x's
                    std::string temp_result(n, ' ');
                    std::string final_s1;
                    std::string final_s2;
                    bool valid_split = true;

                    for (int j = 0; j < n; ++j) {
                        int current_digit = d_str[j] - '0';
                        if (current_digit < x) {
                            temp_result[j] = '1';
                            final_s1 += d_str[j];
                        } else if (current_digit > x) {
                            temp_result[j] = '2';
                            final_s2 += d_str[j];
                        } else { // current_digit == x
                            if (j < i) { // 'x's before the split point
                                temp_result[j] = '1';
                                final_s1 += d_str[j];
                            } else { // 'x's from the split point onwards
                                temp_result[j] = '2';
                                final_s2 += d_str[j];
                            }
                        }
                    }

                    // Check if the constructed sequences are valid
                    if (is_sorted(final_s1) && is_sorted(final_s2)) {
                        if (final_s1.empty() || final_s2.empty() || final_s1.back() <= final_s2.front()) {
                            std::cout << temp_result << "\n";
                            return;
                        }
                    }
                    current_possible = false; // This split didn't work
                    break; // No need to check further for this x
                }
            }
        }

        if (current_possible) { // If all 'x's could be colored '1'
            if (is_sorted(current_s1) && is_sorted(current_s2)) {
                if (current_s1.empty() || current_s2.empty() || current_s1.back() <= current_s2.front()) {
                    std::cout << result << "\n";
                    return;
                }
            }
        }
    }

    std::cout << "-\n";
}

