#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> seen_chars;

    for (size_t i = 0; i < s.length(); ++i) {
        seen_chars.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string result_layout = "";
    std::set<char> visited_in_path;
    char start_node = '\0';

    // Find a starting node for a path (degree 1 or 0)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) == 0) { // Character not in password, degree 0
            // If it's the only character in the password, it's a valid start.
            // Otherwise, we'll add it later.
            if (seen_chars.size() == 1 && seen_chars.count(c) > 0) {
                start_node = c;
                break;
            }
            continue;
        }
        if (adj[c].size() <= 1) { // Degree 1
            start_node = c;
            break;
        }
    }

    // If no degree 0 or 1 node found, it means all nodes have degree 2.
    // This implies cycles. We can pick any node to start.
    if (start_node == '\0' && !seen_chars.empty()) {
        start_node = *seen_chars.begin();
    } else if (start_node == '\0' && seen_chars.empty()) { // Empty password or only one char
        start_node = 'a'; // Default start for an empty path
    }


    if (start_node != '\0') {
        char current = start_node;
        char prev = '\0'; // Sentinel for the previous character in the path

        while (visited_in_path.find(current) == visited_in_path.end() && adj.count(current) > 0) {
            result_layout += current;
            visited_in_path.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
        }
    }

    // Check if all characters from the password have been included in the path
    for (char c : seen_chars) {
        if (visited_in_path.find(c) == visited_in_path.end()) {
            std::cout << "NO\n"; // This means there's a disconnected component or a cycle not handled
            return;
        }
    }

    // Add remaining characters not in the password
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_path.find(c) == visited_in_path.end()) {
            result_layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << result_layout << "\n";
}

