    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, 1000000007 - 2);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = Sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    long long sum_r_val;
    if (b == 1) { // If b=1, then b-1=0, so sum_r is 0.
        sum_r_val = 0;
    } else {
        sum_r_val = ((b - 1) % MOD * (b % MOD)) % MOD;
        sum_r_val = (sum_r_val * modInverse(2)) % MOD;
    }

    // Calculate sum_k = Sum_{k=1 to a} k
    // sum_k = a * (a+1) / 2
    long long sum_k_val = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * modInverse(2)) % MOD;

    // The total sum is (sum_k * b * sum_r) + (a * sum_r)
    // = sum_r * (sum_k * b + a)

    long long term1 = (sum_k_val * (b % MOD)) % MOD;
    long long term2 = a % MOD;
    long long inner_sum = (term1 + term2) % MOD;

    long long total_sum = (sum_r_val * inner_sum) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

