// Function to compute Z-array for a string
std::vector<int> compute_z_array(const std::string& str) {
    int n = str.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n
    int l = 0, r = 0;
    for (int i = 1; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && str[z[i]] == str[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute Z-arrays for all cyclic shifts of s
    // z_arrays[i] stores the Z-array for s[i...L-1] + s[0...i-1]
    std::vector<std::vector<int>> z_arrays(L);
    for (int i = 0; i < L; ++i) {
        std::string shifted_s = s.substr(i) + s.substr(0, i);
        z_arrays[i] = compute_z_array(shifted_s);
    }

    double total_win_prob = 0.0;

    // Iterate over all possible initial shifts k_actual (Kolya's choice)
    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char char0 = s[k_actual]; // Vasya learns t[0] = s[k_actual]

        // Find all k_prime such that s[k_prime] == char0
        std::vector<int> possible_k_primes;
        for (int k_prime = 0; k_prime < L; ++k_prime) {
            if (s[k_prime] == char0) {
                possible_k_primes.push_back(k_prime);
            }
        }

        // If only one k_prime matches char0, Vasya wins immediately for this k_actual
        if (possible_k_primes.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // Otherwise, Vasya needs to choose a position p to maximize win probability
        double max_win_prob_for_k_actual = 0.0;

        // Iterate over all possible positions p (from 1 to L-1)
        for (int p = 1; p < L; ++p) {
            char char_p = s[(k_actual + p) % L]; // Vasya learns t[p] = s[(k_actual + p) % L]

            int num_unique_k_primes = 0;
            for (int k_prime : possible_k_primes) {
                if (s[(k_prime + p) % L] == char_p) {
                    num_unique_k_primes++;
                }
            }

            // If only one k_prime matches both char0 and char_p, Vasya wins
            if (num_unique_k_primes == 1) {
                max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, 1.0);
                continue; // Can't do better than 1.0 for this k_actual
            }

            // If multiple k_primes match, Vasya needs to check if they are distinct
            // based on the full string comparison.
            // A k_prime is "unique" if no other k_double_prime (from possible_k_primes)
            // matches both t[0] and t[p] AND has the same full string t.

            // For a given k_actual, char0, char_p, and chosen p:
            // We are interested in the set of k_prime values such that:
            // 1. s[k_prime] == char0
            // 2. s[(k_prime + p) % L] == char_p
            // Let this set be S_match.
            // Vasya wins if there is exactly one k_prime in S_match, OR
            // if all k_prime in S_match produce distinct full strings t.
            // The problem states: "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
            // This means if there exist k_prime1, k_prime2 in S_match such that k_prime1 != k_prime2, Vasya loses.
            // This is equivalent to saying Vasya wins if |S_match| == 1.
            // The problem statement is a bit ambiguous here. "at least two cyclic shifts of s that fit the information Vasya knowns"
            // could mean two distinct k values, or two distinct resulting strings t.
            // Given the example "tictictactac", if t[0]='t', t[3]='t', then k=0 and k=3 are possible.
            // s="tictictactac"
            // k=0: t="tictictactac"
            // k=3: t="tictactactac"
            // These are different strings. If Vasya knows t[0]='t' and t[3]='t', he can't distinguish k=0 from k=3.
            // This implies he loses if there are multiple k_prime values that satisfy the conditions, even if they lead to different full strings.
            // So, the condition for winning is that exactly one k_prime satisfies s[k_prime] == char0 AND s[(k_prime + p) % L] == char_p.
            // This is what `num_unique_k_primes == 1` checks.

            // The problem statement is actually more subtle: "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
            // This means if there exist k1 != k2 such that (s[k1] == char0 AND s[(k1+p)%L] == char_p) AND (s[k2] == char0 AND s[(k2+p)%L] == char_p),
            // then Vasya loses.
            // This is exactly what `num_unique_k_primes == 1` checks.
            // So, if `num_unique_k_primes == 1`, Vasya wins for this `p`.
            // If `num_unique_k_primes > 1`, Vasya loses for this `p`.
            // If `num_unique_k_primes == 0`, Vasya loses for this `p` (as k_actual is not found).
            // But k_actual is always in `possible_k_primes` and will always satisfy `s[(k_actual+p)%L] == char_p`.
            // So `num_unique_k_primes` will always be at least 1.
            // Thus, Vasya wins if and only if `num_unique_k_primes == 1`.

            // The only remaining case is when `num_unique_k_primes > 1`.
            // In this case, Vasya needs to check if these multiple `k_prime` values
            // actually correspond to the same *full string* `t`.
            // If all `k_prime` values that satisfy the conditions lead to the *same* full string `t`,
            // then Vasya effectively knows `k` uniquely (because all valid `k` values produce the same `t`).
            // This is the "Lyndon factorization" part of the problem.
            // Two shifts `k1` and `k2` produce the same string `t` if `s` is periodic.
            // Specifically, `s_k1` is the same as `s_k2` if `s` is periodic with period `|k1-k2|`.
            // This means `s_i = s_{i+d}` for all `i`, where `d = |k1-k2|`.
            // This is equivalent to checking if `s` is equal to `s` shifted by `d`.
            // This can be checked using Z-algorithm.
            // `s` shifted by `d` is `s[d...L-1] + s[0...d-1]`.
            // We need to check if `s == s[d...L-1] + s[0...d-1]`.
            // This is true if `z_arrays[d][0] == L`.

            if (num_unique_k_primes > 1) {
                // Check if all these k_prime values lead to the same full string t.
                // This happens if s is periodic with period `d = |k_prime1 - k_prime2|` for all pairs.
                // More generally, if all k_prime values in S_match produce the same string,
                // it means that for any two k_prime_a, k_prime_b in S_match,
                // the string s shifted by k_prime_a is identical to s shifted by k_prime_b.
                // This is equivalent to checking if s is periodic with period `(k_prime_b - k_prime_a + L) % L`.
                // If this holds for all pairs, then Vasya wins.
                // If it holds for some pairs but not others, Vasya loses.
                // If it holds for all pairs, then all strings are identical.
                // We can just pick the first k_prime in S_match, say `k_first`,
                // and check if all other `k_prime_i` in S_match produce the same string as `k_first`.
                // This means `s` shifted by `k_first` must be equal to `s` shifted by `k_prime_i`.
                // This is true if `z_arrays[(k_prime_i - k_first + L) % L][0] == L`.

                int k_first_match = -1;
                for (int k_prime : possible_k_primes) {
                    if (s[(k_prime + p) % L] == char_p) {
                        if (k_first_match == -1) {
                            k_first_match = k_prime;
                        } else {
                            // Check if s shifted by k_first_match is same as s shifted by k_prime
                            int diff = (k_prime - k_first_match + L) % L;
                            if (z_arrays[diff][0] != L) {
                                // They produce different strings, so Vasya loses for this p
                                max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, 0.0);
                                goto next_p_loop; // Break out of inner loops and go to next p
                            }
                        }
                    }
                }
                // If we reach here, all matching k_primes produce the same string. Vasya wins.
                max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, 1.0);
            }
            next_p_loop:;
        }
        total_win_prob += max_win_prob_for_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    // Calculate prefix sums for jars 1 to n (left side)
    // diff_L[i] = (count of 1s in a[0...i-1]) - (count of 2s in a[0...i-1])
    // diff_L[0] = 0
    // diff_L[k] = (S_k - B_k) for jars 1 to k
    std::vector<int> diff_L(n + 1, 0);
    int current_s = 0;
    int current_b = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            current_s++;
        } else {
            current_b++;
        }
        diff_L[i + 1] = current_s - current_b;
    }

    // Calculate suffix sums for jars n+1 to 2n (right side)
    // diff_R[i] = (count of 1s in a[i...2n-1]) - (count of 2s in a[i...2n-1])
    // diff_R[2n] = 0
    // diff_R[k] = (S_k - B_k) for jars k to 2n
    std::vector<int> diff_R(2 * n + 1, 0);
    current_s = 0;
    current_b = 0;
    for (int i = 2 * n - 1; i >= n; --i) {
        if (a[i] == 1) {
            current_s++;
        } else {
            current_b++;
        }
        diff_R[i] = current_s - current_b;
    }

    // Map to store the minimum number of jars removed from the left (k_L)
    // to achieve a certain difference (S_kL - B_kL)
    // key: difference, value: k_L
    std::map<int, int> left_diff_to_kL;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff = diff_L[k_L];
        if (left_diff_to_kL.find(current_diff) == left_diff_to_kL.end()) {
            left_diff_to_kL[current_diff] = k_L;
        }
    }

    int min_removed = 2 * n; // Max possible removed jars

    // Iterate through all possible numbers of jars removed from the right (k_R)
    // k_R ranges from 0 to n
    for (int k_R = 0; k_R <= n; ++k_R) {
        // The jars remaining on the right are from index n to 2n-1-k_R
        // The difference for these remaining jars is diff_R[n] - diff_R[2n-k_R]
        // This is the difference of the segment [n, 2n-1-k_R]
        // No, this is not correct. diff_R[i] is for segment [i, 2n-1].
        // We are interested in the segment [n, 2n-1-k_R].
        // Let's re-evaluate diff_R.
        // diff_R[i] = (S - B) for jars a[i...2n-1].
        // We remove k_R jars from the right, meaning jars a[2n-k_R...2n-1] are removed.
        // The remaining jars on the right are a[n...2n-k_R-1].
        // Let's calculate the difference for this segment.
        // The total difference of all jars is initial_s - initial_b.
        // If we remove k_L jars from left and k_R jars from right,
        // the remaining jars are a[k_L ... 2n-1-k_R].
        // The difference for this remaining segment is what we need to be 0.
        // (S_total - S_removed) - (B_total - B_removed) = 0
        // (S_total - B_total) - (S_removed - B_removed) = 0
        // D_0 - (D_L_removed + D_R_removed) = 0
        // D_L_removed is diff_L[k_L]
        // D_R_removed is (S_kR - B_kR) for jars a[2n-k_R ... 2n-1]
        // This is exactly diff_R[2n-k_R] (as defined: S-B for a[idx...2n-1])

        int diff_removed_right = diff_R[2 * n - k_R];
        int target_diff_L = initial_s - initial_b - diff_removed_right;

        if (left_diff_to_kL.count(target_diff_L)) {
            int k_L = left_diff_to_kL[target_diff_L];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0-9), we track how an initial 0 and an initial 1
    // would transform after all operations.
    // state_0[k] will be the k-th bit of the result if the input k-th bit was 0.
    // state_1[k] will be the k-th bit of the result if the input k-th bit was 1.
    // Initialize: if input k-th bit is 0, output is 0. If input k-th bit is 1, output is 1.
    std::vector<int> state_0(10); // All zeros initially
    std::vector<int> state_1(10);
    std::iota(state_1.begin(), state_1.end(), 0); // state_1[k] = 1 for k-th bit

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int k = 0; k < 10; ++k) {
            int x_k = (x >> k) & 1; // k-th bit of constant x

            if (op_char == '&') {
                state_0[k] = state_0[k] & x_k;
                state_1[k] = state_1[k] & x_k;
            } else if (op_char == '|') {
                state_0[k] = state_0[k] | x_k;
                state_1[k] = state_1[k] | x_k;
            } else if (op_char == '^') {
                state_0[k] = state_0[k] ^ x_k;
                state_1[k] = state_1[k] ^ x_k;
            }
        }
    }

    // Now, we have the final transformation for each bit.
    // We need to find constants A, B, C such that:
    // (input & A | B) ^ C gives the same result.
    // Or, more generally, a sequence of at most 5 operations.
    // The problem states "no more than 5 lines", but 3 operations are sufficient.
    // Let's find the combined effect of all operations.
    // For each bit k:
    // If input_k = 0, output_k = state_0[k].
    // If input_k = 1, output_k = state_1[k].

    // We can represent the transformation for each bit k as a function f_k(input_k).
    // There are 4 possible functions for a single bit:
    // 1. f(b) = 0 (always 0)
    // 2. f(b) = 1 (always 1)
    // 3. f(b) = b (identity)
    // 4. f(b) = !b (negation)

    // Let's construct the constants for the three operations: AND, OR, XOR.
    // We want to find A, B, C such that for any input_bit `b`:
    // `((b & A_k) | B_k) ^ C_k` equals `state_0[k]` if `b=0` and `state_1[k]` if `b=1`.

    int final_and_const = 1023; // All bits 1
    int final_or_const = 0;     // All bits 0
    int final_xor_const = 0;    // All bits 0

    for (int k = 0; k < 10; ++k) {
        int s0 = state_0[k];
        int s1 = state_1[k];

        // Case 1: f(b) = 0 (s0=0, s1=0)
        // We need ((b & A_k) | B_k) ^ C_k = 0 for b=0 and b=1.
        // If b=0: (0 | B_k) ^ C_k = B_k ^ C_k = 0 => B_k = C_k
        // If b=1: (A_k | B_k) ^ C_k = 0
        // If B_k = C_k = 0: (A_k | 0) ^ 0 = A_k = 0. So A_k=0, B_k=0, C_k=0.
        // This means: final_and_const_k = 0, final_or_const_k = 0, final_xor_const_k = 0.
        // This is equivalent to `& 0`.

        // Case 2: f(b) = 1 (s0=1, s1=1)
        // We need ((b & A_k) | B_k) ^ C_k = 1 for b=0 and b=1.
        // If b=0: (0 | B_k) ^ C_k = B_k ^ C_k = 1
        // If b=1: (A_k | B_k) ^ C_k = 1
        // If B_k = 1, C_k = 0: (A_k | 1) ^ 0 = 1. This is always true.
        // So A_k=any, B_k=1, C_k=0.
        // This means: final_or_const_k = 1.
        // This is equivalent to `| 1`.

        // Case 3: f(b) = b (s0=0, s1=1)
        // We need ((b & A_k) | B_k) ^ C_k = b for b=0 and b=1.
        // If b=0: (0 | B_k) ^ C_k = B_k ^ C_k = 0 => B_k = C_k
        // If b=1: (A_k | B_k) ^ C_k = 1
        // If B_k = C_k = 0: (A_k | 0) ^ 0 = A_k = 1. So A_k=1, B_k=0, C_k=0.
        // This means: final_and_const_k = 1.
        // This is equivalent to `& 1`.

        // Case 4: f(b) = !b (s0=1, s1=0)
        // We need ((b & A_k) | B_k) ^ C_k = !b for b=0 and b=1.
        // If b=0: (0 | B_k) ^ C_k = B_k ^ C_k = 1
        // If b=1: (A_k | B_k) ^ C_k = 0
        // If B_k = 0, C_k = 1: (A_k | 0) ^ 1 = A_k ^ 1 = 0 => A_k = 1.
        // So A_k=1, B_k=0, C_k=1.
        // This means: final_and_const_k = 1, final_xor_const_k = 1.
        // This is equivalent to `& 1 ^ 1`.

        // Let's set the bits for A, B, C based on these 4 cases.
        // A_k is the k-th bit of final_and_const
        // B_k is the k-th bit of final_or_const
        // C_k is the k-th bit of final_xor_const

        if (s0 == 0 && s1 == 0) { // f(b) = 0
            // A_k = 0, B_k = 0, C_k = 0
            final_and_const &= ~(1 << k); // Set A_k to 0
            final_or_const &= ~(1 << k);  // Set B_k to 0
            final_xor_const &= ~(1 << k); // Set C_k to 0
        } else if (s0 == 1 && s1 == 1) { // f(b) = 1
            // A_k = 0 (doesn't matter, but 0 is fine), B_k = 1, C_k = 0
            final_and_const &= ~(1 << k); // Set A_k to 0
            final_or_const |= (1 << k);   // Set B_k to 1
            final_xor_const &= ~(1 << k); // Set C_k to 0
        } else if (s0 == 0 && s1 == 1) { // f(b) = b
            // A_k = 1, B_k = 0, C_k = 0
            final_and_const |= (1 << k);  // Set A_k to 1
            final_or_const &= ~(1 << k);  // Set B_k to 0
            final_xor_const &= ~(1 << k); // Set C_k to 0
        } else { // s0 == 1 && s1 == 0, f(b) = !b
            // A_k = 1, B_k = 0, C_k = 1
            final_and_const |= (1 << k);  // Set A_k to 1
            final_or_const &= ~(1 << k);  // Set B_k to 0
            final_xor_const |= (1 << k);  // Set C_k to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If not all bits are 1 for AND, then AND operation is needed
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If not all bits are 0 for OR, then OR operation is needed
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If not all bits are 0 for XOR, then XOR operation is needed
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, -2); // -2 indicates not computed, -1 indicates infinite loop
    std::vector<int> dp_x(n + 1, 0);

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a[1] for the current run

        long long current_y = 0;
        int current_x = 1;

        // Path tracking for cycle detection
        std::vector<bool> visited(n + 1, false);
        std::vector<long long> path_y_val(n + 1, 0); // y value when entering a state (x)
        std::vector<int> path_x_val(n + 1, 0); // x value when entering a state (x)

        bool terminated = false;
        while (true) {
            if (current_x <= 0 || current_x > n) {
                terminated = true;
                break;
            }

            if (dp_y[current_x] != -2) { // Already computed or known to be infinite
                if (dp_y[current_x] == -1) { // Known infinite loop
                    current_y = -1;
                } else { // Known finite path
                    current_y += dp_y[current_x];
                }
                terminated = true;
                break;
            }

            if (visited[current_x]) { // Cycle detected
                current_y = -1;
                terminated = true;
                break;
            }

            visited[current_x] = true;
            path_y_val[current_x] = current_y;
            path_x_val[current_x] = current_x;

            long long val_a_x = a[current_x];

            // Step 2
            current_x += val_a_x;
            current_y += val_a_x;

            if (current_x <= 0 || current_x > n) {
                terminated = true;
                break;
            }

            // Step 3
            current_x -= val_a_x;
            current_y += val_a_x;
        }

        // Backtrack and fill DP table for states encountered in this run
        if (current_y == -1) { // Infinite loop
            for (int j = 1; j <= n; ++j) {
                if (visited[j]) {
                    dp_y[j] = -1;
                }
            }
        } else { // Terminated
            for (int j = 1; j <= n; ++j) {
                if (visited[j]) {
                    dp_y[j] = current_y - path_y_val[j];
                }
            }
        }

        std::cout << current_y << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zero_run(n); // Length of consecutive zeros to the left, including current
    std::vector<int> right_zero_run(n); // Length of consecutive zeros to the right, including current
    std::vector<int> left_one_run(n);  // Length of consecutive ones to the left, including current
    std::vector<int> right_one_run(n); // Length of consecutive ones to the right, including current

    // Calculate left runs
    left_zero_run[0] = (a[0] == 0);
    left_one_run[0] = (a[0] == 1);
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
            left_one_run[i] = 0;
        } else {
            left_one_run[i] = left_one_run[i - 1] + 1;
            left_zero_run[i] = 0;
        }
    }

    // Calculate right runs
    right_zero_run[n - 1] = (a[n - 1] == 0);
    right_one_run[n - 1] = (a[n - 1] == 1);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
            right_one_run[i] = 0;
        } else {
            right_one_run[i] = right_one_run[i + 1] + 1;
            right_zero_run[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Current element is 0
            // Check for 1 0 1 pattern
            if (i > 0 && a[i - 1] == 1 && i < n - 1 && a[i + 1] == 1) {
                // This 0 will turn into 1.
                // The number of steps for this 0 to turn into 1 is min(left_one_run[i-1], right_one_run[i+1])
                // The actual number of steps is ceil(min_run_length / 2.0)
                // For example, 11011 -> 11111 in 1 step. min_run_length = 2. ceil(2/2) = 1.
                // 1110111 -> 1111111 in 2 steps. min_run_length = 3. ceil(3/2) = 2.
                int k_val = std::min(left_one_run[i - 1], right_one_run[i + 1]);
                max_k = std::max(max_k, (k_val + 1) / 2);
            }
        } else { // Current element is 1
