struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a[j] to a very large value, effectively positive infinity.
    // This is because type 2 operations (max(a_j) = m) impose upper bounds.
    // If initial_a[j] is too large, it will be reduced by type 2 operations.
    // A value like 2e9 is safe as |a_i| <= 1e9.
    std::vector<long long> initial_a(n, 2000000000LL); 

    // Process operations in reverse to determine initial_a values
    // For type 2 operations (max(a_j) = m), we know that for all j in [l, r],
    // initial_a[j] + current_delta[j] <= m.
    // This means initial_a[j] <= m - current_delta[j].
    // We want to find the largest possible initial_a[j] that satisfies all constraints.
    // So, initial_a[j] = min(initial_a[j], m - current_delta[j]).
    // current_delta[j] is the sum of d's applied to a[j] *after* this operation.
    // So, we need to track the total delta applied to each element.
    std::vector<long long> current_delta(n, 0);
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // This is an increase operation.
            // When processing in reverse, this operation *removes* d from the future delta.
            // So, we subtract d from current_delta for elements in [l, r].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val;
            }
        } else {
            // This is a max query operation.
            // For all j in [l, r], initial_a[j] + current_delta[j] <= ops[i].val.
            // So, initial_a[j] <= ops[i].val - current_delta[j].
            // We update initial_a[j] with the minimum of its current value and this new upper bound.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Verify the reconstructed initial_a
    // Simulate operations from start to end with the found initial_a
    std::vector<long long> simulated_a = initial_a;
    current_delta.assign(n, 0); // Reset current_delta for forward simulation

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Apply the increase operation to current_delta
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else {
            // Check the max query operation
            long long max_val = -3000000000000000000LL; // A very small number
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, initial_a[j] + current_delta[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the initial array
    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
