struct Child {
    int id;
    long long v, d, p;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_in_line;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_in_line.push_back({i + 1, v_val, d_val, p_val});
    }

    std::vector<int> cured_children_ids;

    while (!children_in_line.empty()) {
        Child current_child = children_in_line.front();
        children_in_line.pop_front();
        cured_children_ids.push_back(current_child.id);

        long long current_v_cry = current_child.v;
        long long accumulated_d_cry = 0;

        auto it = children_in_line.begin();
        while (it != children_in_line.end()) {
            // Apply accumulated d_cry from previous children who left
            it->p -= accumulated_d_cry;

            // Apply current_v_cry from the child in the doctor's office
            if (current_v_cry > 0) {
                it->p -= current_v_cry;
                current_v_cry--;
            }

            if (it->p < 0) {
                accumulated_d_cry += it->d;
                it = children_in_line.erase(it); // Child leaves, iterator invalidated
            } else {
                ++it; // Move to the next child
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

