// Function to calculate the number of '1's in a string
int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If initial 'a' has an odd number of '1's, we can append a '1' to make it even.
    // This effectively increases the count of '1's by 1.
    // If initial 'a' has an even number of '1's, we append a '0', count of '1's remains same.
    // So, the maximum number of '1's we can achieve in 'a' (by appending parity)
    // is `ones_a` if `ones_a` is even, or `ones_a + 1` if `ones_a` is odd.
    // This can be simplified to `ones_a + (ones_a % 2)`.
    int max_ones_a_after_parity_op = ones_a + (ones_a % 2);

    // We can always remove characters from the front of 'a'.
    // This means we can always reduce the length of 'a' down to 1 (or 0 if we remove all).
    // The number of '1's in 'a' can be reduced by removing '1's from the front.
    // The length of 'a' can be increased by appending parity.
    // The maximum length 'a' can effectively reach is `|a| + (max_ones_a_after_parity_op - ones_a)`.
    // However, the crucial observation is that we can always make the parity of 'a' 0
    // by appending `parity(a)`. If `parity(a)` is 0, we append '0', count of '1's is same.
    // If `parity(a)` is 1, we append '1', count of '1's increases by 1.
    // In both cases, the new string `a'` will have `parity(a') == 0`.
    // So, we can always reach a state where `a` has an even number of '1's.
    // The maximum number of '1's we can have in `a` (after potentially one parity op)
    // is `ones_a` if `ones_a` is even, or `ones_a + 1` if `ones_a` is odd.
    // Let's call this `effective_ones_a`.
    int effective_ones_a = ones_a;
    if (effective_ones_a % 2 != 0) {
        effective_ones_a++;
    }

    // Now, we need to check if `b` can be formed.
    // For `b` to be formed, two conditions must be met:
    // 1. The number of '1's in `b` must be less than or equal to the maximum possible '1's we can get in `a`.
    //    This maximum is `effective_ones_a`.
    // 2. The length of `b` must be less than or equal to the maximum possible length we can get from `a`.
    //    The maximum length we can get from `a` is `|a| + (effective_ones_a - ones_a)`.
    //    This is because if `ones_a` was odd, we append a '1', increasing length by 1.
    //    If `ones_a` was even, we append a '0', increasing length by 1.
    //    So, we can always increase the length of `a` by 1, and make its parity 0.
    //    After this, we can keep appending '0's (since parity is 0), increasing length.
    //    So, the length of `a` can be arbitrarily increased (as long as we have enough '1's to match `b`).
    //    The only constraint is that we must have enough '1's.
    //    The number of '1's in `b` must be less than or equal to `effective_ones_a`.
    //    And the length of `b` must be less than or equal to the length of `a` after we've potentially
    //    added a '1' to make `effective_ones_a`.
    //    The length of `a` after potentially adding a '1' is `a.length() + (effective_ones_a - ones_a)`.
    //    This is the maximum number of '1's we can have in `a` while also having its parity be 0.
    //    Any string `a'` that can be formed from `a` must have `count_ones(a') <= effective_ones_a`.
    //    And `|a'|` can be anything from 1 up to `|a| + (effective_ones_a - ones_a) + K` for any K >= 0.
    //    The key is that we can always make the parity of `a` even, and then append as many '0's as we want.
    //    So, if `ones_b <= effective_ones_a`, then we can always achieve `ones_b` '1's.
    //    And we can always achieve `|b|` length by appending '0's if needed, or removing characters.
    //    The only constraint is that `|b|` must be achievable.
    //    The minimum length of `a` is 1. The maximum length is effectively infinite.
    //    So, the only real constraint is the number of '1's.
    //    We can always make `a` have `effective_ones_a` '1's.
    //    If `ones_b <= effective_ones_a`, then it's possible.

    if (ones_b <= effective_ones_a) {
