struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all in subsequence 1)
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness1 = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // To minimize goodness, we want to make min_f as large as possible and max_f as small as possible.
    // The smallest possible sum is a_0 + a_1.
    // The largest possible sum is a_{n-2} + a_{n-1}.
    //
    // If a_0 and a_1 are in different subsequences, min_f = a_0 + a_1 + h.
    // If a_0 and a_1 are in the same subsequence, min_f = a_0 + a_1.
    //
    // If a_{n-2} and a_{n-1} are in different subsequences, max_f = a_{n-2} + a_{n-1} + h.
    // If a_{n-2} and a_{n-1} are in the same subsequence, max_f = a_{n-2} + a_{n-1}.
    //
    // Consider a partition where a_0 is in S1 and all other elements are in S2.
    // This means a_0 is in a different subsequence from all a_i (i > 0).
    // All a_i (i > 0) are in the same subsequence.
    //
    // Minimum f value:
    // - a_0 + a_1 + h (a_0 in S1, a_1 in S2)
    // - If n > 2, a_1 + a_2 (a_1 in S2, a_2 in S2)
    // So, min_f = std::min(a_0 + a_1 + h, a_1 + a_2) if n > 2.
    // If n = 2, min_f = a_0 + a_1 + h.
    //
    // Maximum f value:
    // - a_0 + a_{n-1} + h (a_0 in S1, a_{n-1} in S2)
    // - a_{n-2} + a_{n-1} (a_{n-2} in S2, a_{n-1} in S2)
    // So, max_f = std::max(a_0 + a_{n-1} + h, a_{n-2} + a_{n-1}).

    long long min_f_val_case2;
    if (n == 2) {
        min_f_val_case2 = elements[0].value + elements[1].value + h;
    } else {
        min_f_val_case2 = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    }

    long long max_f_val_case2 = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 2].value + elements[n - 1].value);

    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Compare goodness values and print the result
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

