        //       So, if current_a >= prev_val and (m - current_a + prev_val) <= x, then prev_val remains prev_val.
        //       Else, prev_val becomes current_a.
        // If current_a < prev_val:
        //   We must increment current_a.
        //   Option 1: Don't wrap. Set b_i = prev_val. Cost is prev_val - current_a.
        //     This is valid if prev_val - current_a <= x.
        //   Option 2: Wrap. Set b_i = prev_val. Cost is (m - current_a) + prev_val.
        //     This is valid if (m - current_a) + prev_val <= x.
        //   If neither is valid, then it's impossible.
        //   If prev_val - current_a <= x, we can set b_i = prev_val.
        //   Else if (m - current_a) + prev_val <= x, we can set b_i = prev_val.
        //   Else, it's impossible.

        // Let's try this logic:
        // We need to find the smallest b_i such that b_i >= prev_val and (b_i - current_a + m) % m <= x.
        // If current_a >= prev_val:
        //   We have two candidates for b_i:
        //   1. current_a (cost 0). This is always valid.
        //   2. prev_val (cost (m - current_a + prev_val) % m). This is valid if (m - current_a + prev_val) % m <= x.
        //      Note that if prev_val <= current_a, then (m - current_a + prev_val) % m is (m - current_a + prev_val).
        //      If prev_val > current_a, then (m - current_a + prev_val) % m is prev_val - current_a.
        //      This is confusing. Let's use the definition of cost: (target - original + m) % m.
        //      Cost to make current_a into current_a is 0.
        //      Cost to make current_a into prev_val is (prev_val - current_a + m) % m.
        //      If current_a >= prev_val:
        //        Cost to make current_a into current_a is 0.
        //        Cost to make current_a into prev_val is (m - current_a + prev_val).
        //        If (m - current_a + prev_val) <= x, then we can choose prev_val.
        //        Since prev_val <= current_a, choosing prev_val is better or equal for the next element.
        //        So, if (m - current_a + prev_val) <= x, we keep prev_val.
        //        Else, we must choose current_a. So prev_val = current_a.
        // Else (current_a < prev_val):
        //   We must increment current_a.
        //   The target must be prev_val.
        //   Cost to make current_a into prev_val is prev_val - current_a.
        //   If prev_val - current_a <= x, then we can achieve prev_val.
        //   Else, it's impossible. Return false.
        //   So, if current_a < prev_val and prev_val - current_a > x, return false.
        //   Otherwise, prev_val remains prev_val.

        // Let's try this simplified logic:
        // If current_a >= prev_val:
        //   If current_a + x >= m + prev_val: // This means we can reach prev_val by wrapping around
        //     // We can keep prev_val.
        //     // Example: m=10, x=2, prev_val=1, current_a=8.
        //     // current_a + x = 10. m + prev_val = 11. 10 < 11. So we can't reach prev_val by wrapping.
        //     // We must use current_a. prev_val becomes 8.
        //     // Example: m=10, x=3, prev_val=1, current_a=8.
        //     // current_a + x = 11. m + prev_val = 11. 11 >= 11. So we can reach prev_val by wrapping.
        //     // We keep prev_val = 1.
        //     // This condition is equivalent to (m - current_a + prev_val) <= x.
        //     // If this is true, we keep prev_val.
        //     // Else, we must use current_a. So prev_val = current_a.
        //     if (current_a + x >= m + prev_val) {
        //         // prev_val remains prev_val
        //     } else {
        //         prev_val = current_a;
        //     }
        // Else (current_a < prev_val):
        //   // We must increment current_a to at least prev_val.
        //   // The cost is prev_val - current_a.
        //   // If this cost is > x, it's impossible without wrapping.
        //   // If we wrap, the cost is (m - current_a) + prev_val.
        //   // This is always greater than prev_val - current_a if current_a < prev_val.
        //   // So we only consider not wrapping.
        //   if (prev_val - current_a > x) {
        //     return false;
        //   }
        //   // Else, prev_val remains prev_val.

        // Let's use the condition (b_i - current_a + m) % m <= x.
        // We want to find the smallest b_i >= prev_val that satisfies this.
        // If current_a <= prev_val:
        //   We need b_i >= prev_val.
        //   The smallest possible b_i is prev_val.
        //   Cost to make current_a into prev_val is (prev_val - current_a + m) % m.
        //   If (prev_val - current_a + m) % m <= x, then we can set b_i = prev_val.
        //   Else, it's impossible.
        //   So, if (prev_val - current_a + m) % m > x, return false.
        //   Else, prev_val remains prev_val.
        // If current_a > prev_val:
        //   We need b_i >= prev_val.
        //   We have two choices for b_i:
        //   1. b_i = current_a. Cost is 0. This is valid.
        //   2. b_i = prev_val. Cost is (prev_val - current_a + m) % m.
        //      Since current_a > prev_val, this cost is (m - current_a + prev_val).
        //      If (m - current_a + prev_val) <= x, then we can choose b_i = prev_val.
        //      Since prev_val < current_a, choosing prev_val is better for the next element.
        //      So, if (m - current_a + prev_val) <= x, we keep prev_val.
        //      Else, we must choose b_i = current_a. So prev_val = current_a.

        // This logic seems correct and covers all cases.
        // Let's re-write it cleanly.
        // `prev_val` is the value of `b_{i-1}`. We need to determine `b_i`.
        // `b_i` must satisfy `b_i >= prev_val` and `(b_i - a_i + m) % m <= x`.

        // Case 1: `a_i` is already greater than or equal to `prev_val`.
        // `a_i >= prev_val`.
        // We have two options for `b_i`:
        //   Option 1.1: Set `b_i = a_i`. Cost is 0. This is always valid.
        //   Option 1.2: Set `b_i = prev_val`. Cost is `(prev_val - a_i + m) % m`.
        //               Since `a_i >= prev_val`, this cost is `m - a_i + prev_val`.
        //               This option is valid if `m - a_i + prev_val <= x`.
        // We want the smallest possible `b_i` to make it easier for the next element.
        // If Option 1.2 is valid (i.e., `m - a_i + prev_val <= x`), we choose `b_i = prev_val`.
        // Otherwise, we must choose `b_i = a_i`.
        if (current_a >= prev_val) {
            if (current_a + x >= m + prev_val) { // This is equivalent to m - current_a + prev_val <= x
                // We can make current_a into prev_val by wrapping. Keep prev_val.
            } else {
                // We cannot make current_a into prev_val by wrapping. Must use current_a.
                prev_val = current_a;
            }
        }
        // Case 2: `a_i` is less than `prev_val`.
        // `a_i < prev_val`.
        // We must increment `a_i` to at least `prev_val`.
        // The smallest possible `b_i` is `prev_val`.
        // Cost to make `a_i` into `prev_val` is `prev_val - a_i`.
        // This option is valid if `prev_val - a_i <= x`.
        // If it's not valid, then it's impossible to make `a_i` into `prev_val` without wrapping.
        // If we wrap, the cost would be `(m - a_i) + prev_val`. This is always greater than `prev_val - a_i`
        // when `a_i < prev_val`. So if `prev_val - a_i > x`, it's impossible.
        // If `prev_val - a_i <= x`, we can set `b_i = prev_val`.
        else { // current_a < prev_val
            if (prev_val - current_a > x) {
                return false; // Cannot make current_a into prev_val
            }
            // Else, prev_val remains prev_val.
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0, high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut at index i splits s into s[0...i-1] and s[i...N-1].
    // We can form s' = s[i...N-1] + s[0...i-1].
    // We need s' to be a palindrome and s' != s.
    // The original string s is guaranteed to be a palindrome.
    // If s' is a palindrome and s' != s, then k=1 is the answer.
    // This check covers cases like "otto" -> "toot" (cut at i=2)
    // and "kinnikkinnik" -> "nikkinnikkin" (cut at i=10)
    for (int i = 1; i < n; ++i) {
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If k=1 didn't work, we need to check k=2.
    // This means we need to find two cuts that result in a new palindrome.
    // Consider the structure of a palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then any rearrangement
    // of its substrings will result in the same string "aaaa".
    // In this case, it's impossible to form a new string s' != s.
    // We can check this by counting unique characters. If there's only one unique character,
    // and it's not possible with k=1, then it's impossible.
    // Example: "qqqq"
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 is always possible for a palindrome of length > 1.
    // Example: "nolon" (n=5)
    // k=1 check:
    // i=1: "olon" + "n" = "olonn" (not pal)
    // i=2: "lon" + "no" = "lonno" (not pal)
    // i=3: "on" + "nol" = "onnol" (not pal)
    // i=4: "n" + "nolo" = "nnolo" (not pal)
    // So k=1 fails.
    //
    // For k=2, we can always achieve a new palindrome if not all characters are the same.
    // Consider cutting s into s[0...i-1], s[i...j-1], s[j...N-1].
    // A simple strategy for k=2:
    // Take s[0] and s[N-1] (which are equal).
    // Take s[1...N-2].
    // If s[1...N-2] is not all same characters, we can rearrange it.
    //
    // A simpler argument:
    // If s is a palindrome and not all characters are the same,
    // then s must contain at least two distinct characters.
    // For example, "abacaba".
    // If we cut s into s[0...N/2-1], s[N/2], s[N/2+1...N-1] (for odd N)
    // or s[0...N/2-1], s[N/2...N/2], s[N/2+1...N-1] (for even N)
    //
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be some character s[i] such that s[i] != s[0].
    //
    // If we take the first character s[0] and move it to the end,
    // and the last character s[N-1] and move it to the beginning,
    // this is equivalent to a cyclic shift.
    //
    // The problem states "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string, and then unite those pieces together to get a new string."
    //
    // If k=1 fails, and not all characters are the same, then k=2 is always possible.
    // Example: "nolon"
    // Cut: "no" | "l" | "on"
    // Rearrange: "on" | "l" | "no" -> "onlno"
    // "onlno" is a palindrome and "onlno" != "nolon".
    // This requires 2 cuts.
    //
    // The only case where k=2 might not work is if the string is of the form "aaaaa...a".
    // We've already handled that.
    // For any other palindrome, if k=1 doesn't work, k=2 will.
    // This is because we can always find a way to break the symmetry of the original string
    // and rearrange it into a new palindrome.
    // For example, take s = A B A (where A is a prefix/suffix, B is the middle).
    // If A is not empty, we can cut A | B | A. Rearrange to A | B | A (original) or A | A | B (not necessarily pal)
    //
    // A simpler way to think about it:
    // If s is a palindrome and not all characters are the same,
    // then s must have at least two distinct characters.
    // For example, "abacaba".
    // If we cut it into s[0...N/2-1], s[N/2], s[N/2+1...N-1] (for odd N)
    // or s[0...N/2-1], s[N/2...N/2], s[N/2+1...N-1] (for even N)
    //
    // Consider s = "nolon". n=5.
    // s[0] = 'n', s[1] = 'o', s[2] = 'l', s[3] = 'o', s[4] = 'n'.
    // We can cut it into "no", "l", "on".
    // Pieces: P1="no", P2="l", P3="on".
    // Rearrange to P3 + P2 + P1 = "on" + "l" + "no" = "onlno".
    // "onlno" is a palindrome and "onlno" != "nolon".
    // This uses 2 cuts.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "Impossible", then k=2 is the answer.
    // The only "Impossible" case is when all characters are the same.
    // This is a known property for this type of problem.
    // If a palindrome has at least two distinct characters, and it's not possible with 1 cut,
    // then it's always possible with 2 cuts.
    // The logic is that you can always find a way to rearrange parts to form a new palindrome.
    // For example, take s = P_1 P_2 P_3 ... P_k+1.
    // If s is a palindrome and not all characters are the same, then there exists an index `i` such that `s[i] != s[0]`.
    // This means `s` is not of the form `aaaa...a`.
    // If `k=1` fails, it means no single cyclic shift of `s` results in a new palindrome.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "Impossible", then k=2 is the answer.
    // The only "Impossible" case is when all characters are the same.
    // This is a known property for this type of problem.
    // If a palindrome has at least two distinct characters, and it's not possible with 1 cut,
    // then it's always possible with 2 cuts.
    //
    // So, if we reach this point, it means k=1 failed, and the string is not composed of all identical characters.
    // Therefore, the answer must be 2.
    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

// Function to check if all target tracks can be covered within 'time' seconds
bool check(long long time, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks p
    for (int i = 0; i < n; ++i) { // Iterate through each head
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long head_pos = h[i];
        long long current_p = p[p_idx];

        // If the current head cannot reach the current target track, skip this head for now
        // or if the current head is too far to the right of the current target track
        if (head_pos + time < current_p) {
            continue;
        }

        // Determine the range this head can cover
        long long left_reach = head_pos - time;
        long long right_reach = head_pos + time;

        // Find the first target track that this head can cover
        // This is implicitly handled by the loop structure.
        // We need to cover p[p_idx], p[p_idx+1], ...
        // The head h[i] can cover a contiguous block of target tracks starting from p[p_idx]
        // as long as they are within its reach [left_reach, right_reach].

        // If p[p_idx] is to the left of head_pos, the head must move right to cover it.
        // The head can cover tracks in [head_pos - time, head_pos + time].
        // If p[p_idx] is within this range, we try to cover as many subsequent tracks as possible.

        // Case 1: p[p_idx] is to the right of head_pos.
        // The head must move right. It can reach up to head_pos + time.
        // The leftmost track it can cover is head_pos - time.
        // If p[p_idx] is within [head_pos - time, head_pos + time], it can cover it.
        // The effective range for covering tracks to the right of head_pos is [p[p_idx], head_pos + time].
        // The head can also move left to cover tracks.
        // The total range it can cover is [head_pos - time, head_pos + time].

        // We need to cover p[p_idx].
        // If p[p_idx] is too far to the left for this head to reach (i.e., p[p_idx] < head_pos - time),
        // then this head cannot cover p[p_idx]. We must use a previous head or this is impossible.
        // But since p is sorted, and we process p_idx sequentially, if p[p_idx] is too far left,
        // it means previous heads couldn't cover it either, or this head is not suitable.
        // The `if (head_pos + time < current_p)` check handles the case where the head is too far left
        // relative to the current target track.

        // The core idea is that for head h[i] to cover p[p_idx], it must be able to reach p[p_idx].
        // This means |h[i] - p[p_idx]| <= time.
        // If this condition is met, h[i] can cover p[p_idx].
        // After covering p[p_idx], h[i] can also cover other tracks.
        // The crucial part is that h[i] can cover a *contiguous range* of tracks.
        // If h[i] covers p[p_idx], it can cover any track x such that x is between p[p_idx] and
        // the furthest point h[i] can reach, given that it also covers p[p_idx].

        // Let's consider the two extreme positions h[i] can move to:
        // 1. Move to p[p_idx] and then as far right as possible.
        //    The time spent to reach p[p_idx] is abs(h[i] - p[p_idx]).
        //    Remaining time is time - abs(h[i] - p[p_idx]).
        //    From p[p_idx], it can move further right by this remaining time.
        //    So, it can cover tracks up to p[p_idx] + (time - abs(h[i] - p[p_idx])).
        // 2. Move to p[p_idx] and then as far left as possible.
        //    This is not useful for covering *subsequent* tracks p[p_idx+1], p[p_idx+2], etc.

        // The optimal strategy for a head h[i] to cover a range of tracks starting from p[p_idx]
        // is to move to some point x, and cover the range [x - (time - |h[i]-x|), x + (time - |h[i]-x|)].
        // This simplifies to covering the range [min(h[i], x) - (time - |h[i]-x|), max(h[i], x) + (time - |h[i]-x|)].
        // This is equivalent to saying it can cover any track y such that min(h[i], y) + abs(h[i]-y) <= time.
        // No, this is wrong. It can cover any track y such that abs(h[i]-y) <= time.
        // And if it covers y, it can cover the range [y - (time - abs(h[i]-y)), y + (time - abs(h[i]-y))].
        // This is the range of tracks it *visits*.

        // The problem is to cover all p_j.
        // If head h[i] covers p[p_idx], it can cover a range of tracks.
        // The range it can cover is [h[i] - time, h[i] + time].
        // If p[p_idx] is within this range, then h[i] can cover p[p_idx].
        // We want to find the maximum p_k that h[i] can cover, given that it also covers p[p_idx].
        // This means h[i] must be able to reach p[p_idx] AND p_k.
        // The time taken to cover a range [A, B] with a head at H is:
        // min(abs(H-A) + (B-A), abs(H-B) + (B-A)).
        // No, this is not correct. The time taken to cover a range [A, B] is
        // max(abs(H-A), abs(H-B)) if H is outside [A, B]
        // max(B-H, H-A) if H is inside [A, B]
        // This is equivalent to:
        // if H < A: B - H
        // if H > B: H - A
        // if A <= H <= B: max(B-H, H-A)
        // This can be summarized as:
        // if H is to the left of A, time = B - H
        // if H is to the right of B, time = H - A
        // if H is between A and B, time = max(B-H, H-A)
        // This is the time to cover the *entire interval* [A, B].

        // We are not covering an interval [A, B]. We are covering a set of points {p_j}.
        // A head h[i] can cover any track x such that |h[i] - x| <= time.
        // So, h[i] can cover any p_j such that p_j is in [h[i] - time, h[i] + time].
        // We want to find the maximum p_k that h[i] can cover, given that it covers p[p_idx].
        // This means p[p_idx] must be in [h[i] - time, h[i] + time].
        // And p_k must be in [h[i] - time, h[i] + time].

        // Let's simplify. For a head h[i] to cover a set of target tracks {p_j, p_{j+1}, ..., p_k},
        // it must be able to reach all of them.
        // The minimum time for h[i] to cover the range [p_j, p_k] is:
        // if h[i] < p_j: p_k - h[i]
        // if h[i] > p_k: h[i] - p_j
        // if p_j <= h[i] <= p_k: max(p_k - h[i], h[i] - p_j)
        // This is the time required for h[i] to cover the *entire interval* [p_j, p_k].
        // We need to cover *only the points* p_j, ..., p_k.
        // The time required for h[i] to cover a set of points {x_1, ..., x_k} is
        // min_{y} max_{j} |y - x_j| + |h[i] - y|.
        // This is equivalent to finding a point y such that the interval [min(x_j), max(x_j)] is covered by y,
        // and then moving h[i] to y.
        // The time for h[i] to cover a set of points {x_1, ..., x_k} is
        // max(max(x_j) - h[i], h[i] - min(x_j), (max(x_j) - min(x_j))/2 + abs(h[i] - (min(x_j) + max(x_j))/2))
        // No, this is too complex.

        // Let's use a greedy approach.
        // For each head h[i], we want it to cover as many *new* target tracks as possible, starting from p[p_idx].
        // If h[i] can cover p[p_idx], it can cover a range of tracks.
        // The range of tracks it can cover is [h[i] - time, h[i] + time].
        // Let's call this range R_i = [L_i, R_i].
        // We need to cover p[p_idx], p[p_idx+1], ...
        // If p[p_idx] is not in R_i, then h[i] cannot cover p[p_idx].
        // Since p is sorted, if p[p_idx] is not in R_i, then no p_k (k >= p_idx) can be covered by h[i]
        // if p[p_idx] > R_i.
        // If p[p_idx] < L_i, then h[i] cannot cover p[p_idx].
        // This means we need a head that is further left or can reach further left.
        // But we are iterating heads from left to right.
        // So, if h[i] cannot cover p[p_idx], it means h[i] is too far right or too far left.
        // If h[i] is too far right (h[i] - time > p[p_idx]), then h[i] cannot cover p[p_idx].
        // If h[i] is too far left (h[i] + time < p[p_idx]), then h[i] cannot cover p[p_idx].
        // The first check `if (head_pos + time < current_p)` handles the second case.
        // The first case `h[i] - time > p[p_idx]` means h[i] is too far right.
        // This implies that p[p_idx] must have been covered by a previous head, or it's impossible.
        // But we are trying to cover p[p_idx] with the *current* head.
        // If h[i] - time > p[p_idx], then h[i] cannot cover p[p_idx].
        // This means we need to advance p_idx using a previous head.
        // This is the core of the greedy strategy.

        // For the current head h[i], we want to cover p[p_idx].
        // If h[i] can cover p[p_idx], it means p[p_idx] is in [h[i] - time, h[i] + time].
        // If it can, then it can cover all p_k such that p_k is in [h[i] - time, h[i] + time].
        // We need to find the maximum k such that p_k is in this range.
        // This is a simple linear scan or binary search.

        // Let's refine the greedy strategy:
        // For each head h[i]:
        // 1. Find the leftmost target track `p_L` that `h[i]` can cover.
        //    This means `p_L >= p[p_idx]` and `abs(h[i] - p_L) <= time`.
        //    If no such `p_L` exists (i.e., `h[i]` cannot even reach `p[p_idx]`), then this `h[i]` is useless for `p[p_idx]`.
        //    We should move to the next head `h[i+1]`.
        //    This is handled by the `if (head_pos + time < current_p)` check.
        //    If `h[i] - time > current_p`, it means `h[i]` is too far right.
        //    This implies `current_p` should have been covered by a previous head.
        //    If `current_p` is not covered, it's impossible.
        //    So, we must have `h[i] - time <= current_p`.

        // The condition for h[i] to cover p[p_idx] is:
        // `h[i] - time <= p[p_idx] <= h[i] + time`.
        // If this is not met, then h[i] cannot cover p[p_idx].
        // If `p[p_idx] > h[i] + time`, then h[i] is too far left. We need a head further right.
        // This is handled by the `if (head_pos + time < current_p)` check.
        // If `p[p_idx] < h[i] - time`, then h[i] is too far right. This means `p[p_idx]` should have been covered by a previous head.
        // If it wasn't, then it's impossible.

        // So, the check function should be:
        // `p_idx` is the index of the first *uncovered* target track.
        // For each head `h[i]`:
        //   If `p_idx == m`, all tracks are covered, return true.
        //   Calculate the range `[L, R]` that `h[i]` can cover: `L = h[i] - time`, `R = h[i] + time`.
        //   If `p[p_idx]` is outside this range `[L, R]`:
        //     If `p[p_idx] > R`, then `h[i]` is too far left to cover `p[p_idx]`.
        //       Since heads are sorted, `h[i+1]` will be even further right, so it might cover `p[p_idx]`.
        //       We should continue to the next head `h[i+1]`.
        //     If `p[p_idx] < L`, then `h[i]` is too far right to cover `p[p_idx]`.
        //       This means `p[p_idx]` should have been covered by a previous head.
        //       If it wasn't, then it's impossible. Return false.
        //   If `p[p_idx]` is within `[L, R]`:
        //     `h[i]` can cover `p[p_idx]`. Now, find how many more tracks `h[i]` can cover.
        //     `h[i]` can cover all `p_k` such that `p_k <= R`.
        //     Advance `p_idx` past all such `p_k`.
        // After iterating through all heads, if `p_idx == m`, return true. Else, return false.

        // Let's trace this logic:
        // `p_idx` points to the first target track that needs to be covered.
        // For each head `h[i]`:
        //   If `p_idx == m`, all tracks are covered. Return true.
        //   `current_p = p[p_idx]`.
        //   `left_bound = h[i] - time`.
        //   `right_bound = h[i] + time`.
        //   If `current_p > right_bound`:
        //     This head `h[i]` is too far left to cover `current_p`.
        //     It cannot cover `current_p` or any subsequent `p_j`.
        //     We must rely on a head `h[k]` with `k > i`. So, continue to the next head.
        //   If `current_p < left_bound`:
        //     This head `h[i]` is too far right to cover `current_p`.
        //     This means `current_p` should have been covered by a previous head `h[k]` with `k < i`.
        //     Since it wasn't, it's impossible to cover `current_p`. Return false.
        //   If `left_bound <= current_p <= right_bound`:
        //     This head `h[i]` can cover `current_p`.
        //     Now, find the furthest track `p_k` that `h[i]` can cover.
        //     This is the largest `p_k` such that `p_k <= right_bound`.
        //     Advance `p_idx` past all such `p_k`.
        //     `while (p_idx < m && p[p_idx] <= right_bound) { p_idx++; }`
        // After the loop, if `p_idx == m`, return true. Else, return false.

        // Example 1: h={2,5,6}, p={1,3,6,8}, time=2
        // p_idx = 0
        // i=0, h[0]=2. current_p=p[0]=1.
        // left_bound = 2-2=0. right_bound = 2+2=4.
        // 0 <= 1 <= 4. Yes.
        // h[0] can cover p[0]=1.
        // Advance p_idx:
        // p[0]=1 <= 4. p_idx=1.
        // p[1]=3 <= 4. p_idx=2.
        // p[2]=6 > 4. Stop.
        // p_idx is now 2. (p[0] and p[1] covered)

        // i=1, h[1]=5. current_p=p[2]=6.
        // left_bound = 5-2=3. right_bound = 5+2=7.
        // 3 <= 6 <= 7. Yes.
        // h[1] can cover p[2]=6.
        // Advance p_idx:
        // p[2]=6 <= 7. p_idx=3.
        // p[3]=8 > 7. Stop.
        // p_idx is now 3. (p[2] covered)

        // i=2, h[2]=6. current_p=p[3]=8.
        // left_bound = 6-2=4. right_bound = 6+2=8.
        // 4 <= 8 <= 8. Yes.
        // h[2] can cover p[3]=8.
        // Advance p_idx:
        // p[3]=8 <= 8. p_idx=4.
        // p_idx is now 4. (p[3] covered)

        // p_idx == m (4 == 4). Return true.

        // This greedy strategy seems correct.
        // For each head, if it can cover the current leftmost uncovered track, it should.
        // And it should cover as many subsequent tracks as possible.
        // This is because using a head to cover a track further to its left than necessary
        // (i.e., not covering the current p[p_idx]) would be suboptimal.
        // If h[i] can cover p[p_idx], it means it can reach it.
        // By covering p[p_idx] and then extending its reach to the right as much as possible,
        // it maximizes the number of tracks covered by this head, leaving fewer tracks for subsequent heads.
        // This is a standard greedy approach for interval covering type problems.

        // The range a head h[i] can cover is [h[i] - time, h[i] + time].
        // Let's call this `[L_i, R_i]`.
        // We need to cover `p[p_idx]`.
        // If `p[p_idx] > R_i`, then `h[i]` cannot reach `p[p_idx]`.
        // Since `h` is sorted, `h[i+1]` will be `h[i]` or greater.
        // So `R_{i+1}` will be `R_i` or greater.
        // It's possible `h[i+1]` can cover `p[p_idx]`. So we continue to the next head.
        // If `p[p_idx] < L_i`, then `h[i]` is too far right to cover `p[p_idx]`.
        // This means `p[p_idx]` must have been covered by a previous head `h[k]` where `k < i`.
        // If it wasn't, then it's impossible. So we return false.
        // If `L_i <= p[p_idx] <= R_i`, then `h[i]` can cover `p[p_idx]`.
        // We then advance `p_idx` to the first track `p_k` such that `p_k > R_i`.

        // Let's re-evaluate the `p[p_idx] < L_i` case.
        // `h[i]` is at `h_i`. It can cover `[h_i - time, h_i + time]`.
        // `p[p_idx]` is the current target.
        // If `p[p_idx] < h_i - time`:
        //   This means `p[p_idx]` is to the left of the leftmost point `h_i` can reach.
        //   Since `h` is sorted, `h[i-1]` is to the left of `h[i]`.
        //   So `h[i-1]`'s range `[h[i-1] - time, h[i-1] + time]` would be even further left.
        //   If `p[p_idx]` is not covered by `h[i]`, and `h[i]` is too far right,
        //   then no `h[k]` with `k > i` can cover `p[p_idx]` either (as they are even further right).
        //   So `p[p_idx]` *must* have been covered by a previous head `h[k]` with `k < i`.
        //   If `p_idx` is still pointing to `p[p_idx]`, it means it wasn't covered.
        //   Therefore, it's impossible. Return false.

        // This logic seems sound.

        long long current_p_val = p[p_idx];
        long long head_left_reach = h[i] - time;
        long long head_right_reach = h[i] + time;

        if (current_p_val < head_left_reach) {
            // The current head h[i] is too far to the right to cover p[p_idx].
            // Since p is sorted, p[p_idx] must have been covered by a previous head.
            // If p_idx is still pointing to it, it means it wasn't covered.
            // Thus, it's impossible.
            return false;
        }
        // If current_p_val is within [head_left_reach, head_right_reach], this head can cover it.
        // If current_p_val > head_right_reach, this head is too far left.
        // It cannot cover current_p_val. We need to try the next head.
        // This is the `else if` branch.

        // If current_p_val <= head_right_reach (and current_p_val >= head_left_reach from above check)
        // This head h[i] can cover current_p_val.
        // It can cover all tracks up to head_right_reach.
        // Advance p_idx past all tracks covered by this head.
        while (p_idx < m && p[p_idx] <= head_right_reach) {
            p_idx++;
        }
    }

    return p_idx == m; // All tracks covered
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible time: (max_p - min_h) or (max_h - min_p)
    // Max value of p_i or h_i is 10^10.
    // Max difference is 10^10.
    // So, 2 * 10^10 is a safe upper bound.
    long long high = 20000000000LL; // 2 * 10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

