int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);

        long long ans = 0;

        // Use +5 or -5 buttons as much as possible
        ans += diff / 5;
        diff %= 5;

        // Now diff is 0, 1, 2, 3, or 4
        if (diff == 0) {
            // No remaining difference
        } else if (diff == 1) {
            // Need to change by 1.
            // Option 1: Use one +1/-1 button. Total: ans + 1
            // Option 2: If we used a +5/-5 button, we could have used +2/+2/-1 or +2/+1/+1.
            //           This means we could have used (X-1)*5 + 5 to get X*5.
            //           If we need to change by 1, we can do (X-1)*5 + 2 + 2 + 2 - 5.
            //           This is not how it works.
            //           Consider the total difference.
            //           If diff is 1, we can use one +1/-1.
            //           Or, we can use one +2/-2 and one +1/-1 in the opposite direction.
            //           E.g., if we need +1, we can do +2 then -1. This is 2 presses.
            //           So, for diff=1, it's 1 press.
            ans += 1;
        } else if (diff == 2) {
            // Need to change by 2.
            // Option 1: Use one +2/-2 button. Total: ans + 1
            // Option 2: Use two +1/-1 buttons. Total: ans + 2
            // So, for diff=2, it's 1 press.
            ans += 1;
        } else if (diff == 3) {
            // Need to change by 3.
            // Option 1: Use one +5/-5 and two +1/-1 in opposite direction. E.g., +5, -1, -1. Total: ans + 3
            // Option 2: Use one +2/-2 and one +1/-1. Total: ans + 2
            // Option 3: Use three +1/-1. Total: ans + 3
            // So, for diff=3, it's 2 presses.
            ans += 2;
        } else if (diff == 4) {
            // Need to change by 4.
            // Option 1: Use one +5/-5 and one +1/-1 in opposite direction. E.g., +5, -1. Total: ans + 2
            // Option 2: Use two +2/-2. Total: ans + 2
            // Option 3: Use one +2/-2 and two +1/-1. Total: ans + 3
            // Option 4: Use four +1/-1. Total: ans + 4
            // So, for diff=4, it's 2 presses.
            ans += 2;
        }

        std::cout << ans << "\n";
    }
    return 0;
}

