#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long remaining_days = d;

    for (int i = 1; i < n; ++i) { // Iterate through piles from index 1 (pile 2) to n-1 (pile n)
        int pile_index = i; // 0-indexed
        int pile_number = i + 1; // 1-indexed

        long long cost_per_haybale = pile_index; // Cost to move one haybale from pile_number to pile 1
                                                  // (pile_index moves for 0-indexed array)

        if (cost_per_haybale == 0) { // This should only happen for pile 1 itself, which is skipped
            continue;
        }

        long long haybales_in_pile = a[pile_index];

        if (haybales_in_pile == 0) {
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // based on remaining_days and cost_per_haybale
        long long max_haybales_movable_by_days = remaining_days / cost_per_haybale;

        // The actual number of haybales moved is the minimum of
        // haybales available in the pile and haybales affordable by days
        long long haybales_to_move = std::min(haybales_in_pile, max_haybales_movable_by_days);

        current_a1 += haybales_to_move;
        remaining_days -= haybales_to_move * cost_per_haybale;

        if (remaining_days <= 0) {
            break; // No more days left
        }
    }

    std::cout << current_a1 << std::endl;
}

