#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the value 'val' to the current_sum 'count' times.
        // We only care about forming 2048. If current_sum already exceeds 2048,
        // adding more won't change the outcome for 2048.
        // We can simply sum up all values less than or equal to 2048.
        // If the total sum is >= 2048, we can always form 2048.
        // This is because any power of two can be combined with an equal power of two
        // to form the next higher power of two.
        // If we have a total sum S, and S >= 2048, and all numbers are powers of two,
        // we can always combine them to eventually form 2048.
        // For example, if we have {1, 1, 1, 1, ..., 1} (2048 times), sum is 2048.
        // We can combine pairs of 1s to get 2s, pairs of 2s to get 4s, and so on,
        // until we get 2048.
        // The only constraint is that we can't break down larger numbers.
        // But since we only consider numbers <= 2048, this is not an issue.
        // Any number X <= 2048 can contribute to the sum.
        // If the sum of all such numbers is >= 2048, we can always make 2048.
        // The logic is that we can always combine smaller powers of two to form larger ones.
        // If the total "value" (sum) is enough, we can always arrange the combinations.
        // For example, if we have {1024, 512, 512}, sum is 2048.
        // Combine 512, 512 -> 1024. Multiset becomes {1024, 1024}.
        // Combine 1024, 1024 -> 2048. Win.
        // This holds true for any combination of powers of two.
        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

