    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // This is because all other values p[j] (j!=i) are at most n-1.
        // If p[i] was n-1, then max_val_in_row would be at most n-1.
        // If p[i] was less than n-1, then max_val_in_row would be less than n-1.
        // So if max_val_in_row is n-1, p[i] must be n.
        // Otherwise, p[i] can be max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
