                // The distance needed to cover this gap is (i + 1) - last_R_pos.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current cell (i+1)
            }
        }
        // After iterating through the string, consider the gap from the last 'R' cell
        // to the target cell n+1.
        // The distance needed to cover this final gap is (n + 1) - last_R_pos.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

