    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' must satisfy:
        // 1. k <= c (at least k coders needed)
        // 2. k <= m (at least k mathematicians needed)
        // 3. 3k <= c + m + x (total students available)
        // So, k <= min(c, m, (c + m + x) / 3)
        // This condition is also sufficient.
        // If we form k teams, we use k coders and k mathematicians for the mandatory roles.
        // This leaves c-k coders, m-k mathematicians, and x non-specialized students.
        // We need to fill k additional spots (3 members per team - 1 coder - 1 mathematician = 1 spot).
        // The total remaining students are (c-k) + (m-k) + x.
        // If (c-k) + (m-k) + x >= k, then we have enough students to fill the remaining spots.
        // This simplifies to c + m + x >= 3k, which is exactly the third condition.
        // Since k <= c and k <= m, we always have c-k >= 0 and m-k >= 0.
        // Thus, the minimum of these three values is the answer.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

