int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use to generate k distinct differences (1 to k)

    // The first k+1 elements will generate k distinct differences.
    // We alternate between left and right pointers to get differences k, k-1, ..., 1.
    // Example: k=4. right=5.
    // 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1.
    // This generates k distinct differences: k, k-1, ..., 1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index (0, 2, 4, ...)
            std::cout << left++;
        } else { // Odd index (1, 3, 5, ...)
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // The remaining n - (k+1) elements should not introduce new distinct differences.
    // We can achieve this by simply appending the remaining numbers in increasing order.
    // Since the previous element was either 'left-1' or 'right+1', and the next number
    // is 'k+2' (which is 'left' if k+1 is odd, or 'right' if k+1 is even),
    // the difference will be 1.
    // Example: k=4, n=7. Permutation so far: 1 5 2 4 3.
    // Next number is 6. Difference |3-6|=3. This is already in {1,2,3,4}.
    // Next number is 7. Difference |6-7|=1. This is already in {1,2,3,4}.
    // This strategy works because the numbers k+2, k+3, ..., n are appended.
    // The last number printed from the alternating sequence is either `left-1` or `right+1`.
    // If `k` is even, the last number printed is `(k/2)+1` (which is `left-1`).
    // The next number to print is `k+2`. The difference is `k+2 - ((k/2)+1) = k/2 + 1`.
    // This difference is <= k for k >= 1.
    // If `k` is odd, the last number printed is `(k+1)/2 + 1` (which is `right+1`).
    // The next number to print is `k+2`. The difference is `k+2 - ((k+1)/2 + 1) = (k+1)/2`.
    // This difference is <= k for k >= 1.
    // All subsequent differences will be 1.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

