            // The last one is > 10^18. So there will be about 30 iterations.
            // `next_power_of_2` can reach `2^30` or `2^31`.
            // `(next_power_of_2 - 1) * next_power_of_2 / 2` can reach `(2^31-1)*2^31/2` which is approx `2^61/2 = 2^60`.
            // `long long` is sufficient.

            sum_of_powers_of_2 *= 2;
            current_cost = (sum_of_powers_of_2 - 1) * sum_of_powers_of_2 / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long num_multiples = n / m;

        // Calculate the sum of last digits for one full cycle of 10 multiples
        // (m, 2m, ..., 10m)
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (static_cast<long long>(i) * m) % 10;
        }

        // Calculate how many full cycles of 10 multiples are there
        long long full_cycles = num_multiples / 10;
        long long total_sum = full_cycles * cycle_sum;

        // Add the sum of last digits for the remaining multiples
        // (10*k*m + m, ..., 10*k*m + (num_multiples % 10)*m)
        long long remaining_multiples = num_multiples % 10;
        for (int i = 1; i <= remaining_multiples; ++i) {
            total_sum += (static_cast<long long>(i) * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the subsegment is just [1]. This is always possible.
    // The subsegment is p[pos[1]...pos[1]]. Length is 1. Max is 1. Min is 1.
    result[0] = '1';

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Expand the current window [current_min_idx, current_max_idx]
        // to include the number 'm'.
        // The number 'm' must be at pos[m].
        // We need to ensure that the window [current_min_idx, current_max_idx]
        // covers all numbers from 1 to m.
        // This means the window must extend from min(pos[1]...pos[m]) to max(pos[1]...pos[m]).

        // Update the bounds of the window to include pos[m]
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current window [current_min_idx, current_max_idx]
        // forms a permutation of 1 to m.
        // Condition 1: The minimum value in the window is 1 (guaranteed by construction, as pos[1] is always included).
        // Condition 2: The maximum value in the window is m (guaranteed by construction, as we expand to include pos[m]).
        // Condition 3: The length of the window must be exactly m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        } else {
            result[m - 1] = '0';
        }
    }

    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            // Since d >= 4, discriminant >= 0, so sqrt is real.
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Both a1 and b1 must be non-negative.
            // Since d >= 4, d + sqrt_discriminant is clearly positive.
            // For b1, d - sqrt_discriminant:
            // We know d^2 - 4d >= 0 => d^2 >= 4d.
            // Since d >= 4, d is positive, so we can take sqrt:
            // sqrt(d^2) >= sqrt(4d) => d >= 2*sqrt(d).
            // This means d - 2*sqrt(d) >= 0.
            // The term sqrt_discriminant is sqrt(d^2 - 4d).
            // We need to check if d - sqrt(d^2 - 4d) >= 0.
            // This is equivalent to d >= sqrt(d^2 - 4d).
            // Since both sides are non-negative, we can square them:
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So, both a1 and b1 are guaranteed to be non-negative.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

