int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2;

    // Cost for the median element itself
    operations += std::abs(a[mid_idx] - s);

    // Cost for elements to the left of median
    // These elements must be <= s
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Cost for elements to the right of median
    // These elements must be >= s
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

