// Function to check if a box can be the special box
// A, B, C, D are initial counts of toys in boxes 1, 2, 3, 4 respectively.
// target_box is the index of the box we are checking (0-indexed: 0, 1, 2, 3)
bool can_be_special_box(long long A, long long B, long long C, long long D, int target_box) {
    long long total_toys = A + B + C + D;

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        return false;
    }
    if (total_toys == 1) {
        if (A == 1 && target_box == 0) return true;
        if (B == 1 && target_box == 1) return true;
        if (C == 1 && target_box == 2) return true;
        if (D == 1 && target_box == 3) return true;
        return false;
    }

    // Case 1: Target Box 1 (fun value <= -1)
    if (target_box == 0) {
        // Final product must be negative. This means an odd number of negative factors.
        // Initial negative factors come from Box 1 (A toys) and Box 2 (B toys).
        // So, (A + B) must be odd.
        if ((A + B) % 2 == 0) return false;

        // Final product must have magnitude >= 1.
        // This requires at least one toy from Box 1 or Box 4 to "dominate"
        // or a sequence of multiplications that results in a large magnitude.
        // If A + D == 0, all initial toys have magnitude < 1.
        // The product of any number of toys with magnitude < 1 will always be < 1.
        // So, if A + D == 0, it's impossible to get a magnitude >= 1.
        if (A + D == 0) return false;

        // If A + D > 0 and (A + B) is odd, it's always possible.
        // We can construct values such that the magnitude grows or shrinks as needed.
        // For example, if we have a toy from Box 1 or 4, say x_large.
        // We can multiply it by a toy from Box 2 or 3, say x_small.
        // If we want |x_large * x_small| >= 1, we pick |x_small| close to 1.
        // If we want |x_large * x_small| < 1, we pick |x_small| close to 0.
        // The only constraint is the sign and the existence of at least one large magnitude toy.
        return true;
    }

    // Case 2: Target Box 2 (fun value in (-1, 0))
    if (target_box == 1) {
        // Final product must be negative. So (A + B) must be odd.
        if ((A + B) % 2 == 0) return false;

        // Final product must have magnitude < 1.
        // This is always possible if (A + B) is odd.
        // If A + D == 0, all initial toys have magnitude < 1, so the product will be < 1.
        // If A + D > 0, we can pick values such that the final product is < 1.
        // For example, if we have a toy from Box 1 or 4 (e.g., 100), and a toy from Box 2 or 3 (e.g., 0.001).
        // We can multiply 100 * 0.001 = 0.1.
        // We can always choose values for toys in Box 2 and 3 to make the final product small enough.
        // For toys in Box 1 and 4, we can choose values like -1.00001 or 1.00001.
        // The only way this is impossible is if all toys are from Box 1 or Box 4 (A+D == total_toys)
        // AND total_toys > 1. In this case, the product of magnitudes >= 1 will always be >= 1.
        if (A + D == total_toys && total_toys > 1) return false;

        return true;
    }

    // Case 3: Target Box 3 (fun value in (0, 1))
    if (target_box == 2) {
        // Final product must be positive. So (A + B) must be even.
        if ((A + B) % 2 != 0) return false;

        // Final product must have magnitude < 1.
        // Similar to Box 2, this is always possible if (A + B) is even.
        // The only way this is impossible is if all toys are from Box 1 or Box 4 (A+D == total_toys)
        // AND total_toys > 1. In this case, the product of magnitudes >= 1 will always be >= 1.
        if (A + D == total_toys && total_toys > 1) return false;

        return true;
    }

    // Case 4: Target Box 4 (fun value >= 1)
    if (target_box == 3) {
        // Final product must be positive. So (A + B) must be even.
        if ((A + B) % 2 != 0) return false;

        // Final product must have magnitude >= 1.
        // This requires at least one toy from Box 1 or Box 4 to "dominate".
        // If A + D == 0, all initial toys have magnitude < 1.
        // The product of any number of toys with magnitude < 1 will always be < 1.
        // So, if A + D == 0, it's impossible to get a magnitude >= 1.
        if (A + D == 0) return false;

        // If A + D > 0 and (A + B) is even, it's always possible.
        return true;
    }

    return false; // Should not be reached
}

