    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (larger elements)
    for (int i = 0; i < n; ++i) { // Pointer for the elements in the original sorted array
        // We are trying to find an element a[j] such that a[j] > a[i]
        // and a[j] has not been used yet.
        // Since both arrays are sorted, if a[j] > a[i], then a[j+1] will also be > a[i] (or equal).
        // We want to use the smallest possible a[j] that satisfies the condition
        // to leave larger elements for later, potentially larger a[i].
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] > a[i]
            count++;
            j++; // Move to the next element to be placed
        } else {
            // No more elements in 'a' are greater than a[i].
            // Since 'a' is sorted, no subsequent a[k] (k > i) will find a match either.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

