struct Element {
    long long value;
    int original_index;
};

bool compareA(const Element& a, const Element& b) {
    return a.value < b.value;
}

bool compareB(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareA);
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    std::vector<long long> result(m);

    for (int i = 0; i < m; ++i) {
        // The i-th smallest A value (a_elements[i].value)
        // should be paired with the (m-1-i)-th smallest B value (b_elements[m-1-i].value)
        // to maximize F(A, B) = A / (B + 1)
        // The original index of this B value is b_elements[m-1-i].original_index
        // This means result[b_elements[m-1-i].original_index] should be a_elements[i].value
        result[b_elements[m - 1 - i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops
    // prefix_min_ops[i] stores the minimum value a[i] must take
    // to satisfy a[0] < a[1] < ... < a[i]
    // This means a[j] >= j for 0 <= j <= i
    std::vector<long long> prefix_min_ops(n);
    prefix_min_ops[0] = a[0]; // a[0] must be >= 0. We can make it 0 if a[0] >= 0.
                              // But we need a[0] < a[1] < ... < a[k].
                              // So a[i] must be at least i.
                              // If a[i] < i, it's impossible.
                              // If a[i] >= i, we can make it i.
                              // So, we need a[i] >= i for all i in the increasing part.

    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            possible_prefix = false;
            break;
        }
    }

    if (!possible_prefix) {
        std::cout << "No\n";
        return;
    }

    // Calculate suffix_min_ops
    // suffix_min_ops[i] stores the minimum value a[i] must take
    // to satisfy a[i] > a[i+1] > ... > a[n-1]
    // This means a[j] >= (n-1)-j for i <= j <= n-1
    // If a[j] < (n-1)-j, it's impossible.
    // If a[j] >= (n-1)-j, we can make it (n-1)-j.
    // So, we need a[i] >= (n-1)-i for all i in the decreasing part.

    bool possible_suffix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] < (n - 1) - i) {
            possible_suffix = false;
            break;
        }
    }

    if (!possible_suffix) {
        std::cout << "No\n";
        return;
    }

    // If we reach here, it means for every index i,
    // a[i] >= i (required for increasing part ending at i)
    // AND a[i] >= (n-1)-i (required for decreasing part starting at i)
    // This implies that for any k (peak index), we can satisfy the conditions.
    // For a peak at index k:
    // a[0] < a[1] < ... < a[k] requires a[i] >= i for 0 <= i <= k.
    // a[k] > a[k+1] > ... > a[n-1] requires a[i] >= (n-1)-i for k <= i <= n-1.
    // The conditions `a[i] >= i` and `a[i] >= (n-1)-i` are checked for all `i`.
    // If these hold for all `i`, then we can always find a `k`.
    // For example, we can choose `k` to be an index `i` where `a[i]` is maximized after operations.
    // Or more simply, if `a[i] >= i` for all `i` and `a[i] >= (n-1)-i` for all `i`,
    // then for any `i`, we can set `a_i'` to `i` for the increasing part and `a_i''` to `(n-1)-i` for the decreasing part.
    // The actual value `a_i` must be at least `max(i, (n-1)-i)`.
    // Since we can decrease `a_i` as much as we want (down to 0),
    // if `original_a_i >= max(i, (n-1)-i)`, we can make it `max(i, (n-1)-i)`.
    // The conditions `a[i] >= i` and `a[i] >= (n-1)-i` for all `i` are sufficient.
    // If these conditions hold, we can always construct a sharpened array.
    // For example, we can pick k such that a[k] is the maximum of a[i] - max(i, (n-1)-i).
    // Or simply, we can set a_i' = i for i from 0 to n-1, and a_i'' = (n-1)-i for i from 0 to n-1.
    // Then for any k, we can form the array:
    // [0, 1, ..., k-1, k, k-1, ..., 1, 0]
    // This requires a[i] >= i for i <= k and a[i] >= (n-1)-i for i >= k.
    // If the original a[i] satisfies a[i] >= i AND a[i] >= (n-1)-i for ALL i,
    // then we can always find a k.
    // For example, we can choose k to be the index where i and (n-1)-i are closest, or where a[i] is largest.
    // The simplest sharpened array is [0, 1, 2, ..., (n-1)/2, ..., 2, 1, 0].
    // This requires a[i] >= i for i <= (n-1)/2 and a[i] >= (n-1)-i for i >= (n-1)/2.
    // If a[i] >= i for all i and a[i] >= (n-1)-i for all i, then it's possible.
    // This is exactly what `possible_prefix` and `possible_suffix` check.

    std::cout << "Yes\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

