void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix properties
    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max possible value is n-1, but we use n+1 for 1-based indexing
    int current_max_prefix = 0;
    bool current_is_perm_prefix = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        int len = i + 1;

        if (val <= 0 || val > len || seen_prefix[val]) {
            current_is_perm_prefix = false;
        }
        seen_prefix[val] = true;
        if (val > current_max_prefix) {
            current_max_prefix = val;
        }

        prefix_max[i] = current_max_prefix;
        prefix_is_perm[i] = current_is_perm_prefix && (current_max_prefix == len);
    }

    // Precompute suffix properties
    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_is_perm(n);
    std::vector<bool> seen_suffix(n + 1, false); // Max possible value is n-1
    int current_max_suffix = 0;
    bool current_is_perm_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        int len = n - i;

        if (val <= 0 || val > len || seen_suffix[val]) {
            current_is_perm_suffix = false;
        }
        seen_suffix[val] = true;
        if (val > current_max_suffix) {
            current_max_suffix = val;
        }

        suffix_max[i] = current_max_suffix;
        suffix_is_perm[i] = current_is_perm_suffix && (current_max_suffix == len);
    }

    // Check all possible split points
    for (int l1 = 1; l1 < n; ++l1) { // l1 ranges from 1 to n-1
        int l2 = n - l1;

        // Check if p1 is a permutation of length l1
        bool p1_ok = prefix_is_perm[l1 - 1];

        // Check if p2 is a permutation of length l2
        bool p2_ok = suffix_is_perm[l1]; // p2 starts at index l1

        if (p1_ok && p2_ok) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

