void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor ^ b1 ^ b2 ^ b3)
    // Let X = current_xor and S = current_sum.
    // We need S + b1 + b2 + b3 = 2 * (X ^ b1 ^ b2 ^ b3)

    // Strategy: Append at most 3 elements.
    // It's always possible to append 2 elements.
    // Let's try to append b1 and b2.
    // We want S + b1 + b2 = 2 * (X ^ b1 ^ b2).
    // A simple choice for b1 and b2 that works is:
    // b1 = current_xor
    // b2 = current_sum + current_xor
    // Let's verify this:
    // New sum S' = current_sum + current_xor + (current_sum + current_xor) = 2 * current_sum + 2 * current_xor
    // New xor X' = current_xor ^ current_xor ^ (current_sum + current_xor) = 0 ^ (current_sum + current_xor) = current_sum + current_xor
    // Is S' = 2 * X'?
    // 2 * current_sum + 2 * current_xor = 2 * (current_sum + current_xor)
    // Yes, this holds true.

    // So, we can always append current_xor and (current_sum + current_xor).
    // This uses 2 elements.
    // The problem statement says "at most 3 elements".
    // If the array is already good, we can output 0 elements.
    // But the problem also says "you don't have to minimize the number of added elements!".
    // So, we can always output 2 elements using the strategy above.

    // Let's implement this strategy.
    // The values can be large, up to 10^18.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor can be up to 2^30 - 1 (approx 10^9).
    // So current_sum + current_xor can be up to 10^14 + 10^9, which fits in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << current_sum + current_xor << std::endl;
}

