#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n == 1) { // Base case: only 1 coin left
                chanek_coins += 1;
                n -= 1;
            } else if (n % 2 == 1) { // N is odd
                // Must take 1 coin
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Two options: take 1 or take N/2
                // If N/2 is odd, taking N/2 leaves an odd number for opponent.
                // If N/2 is even, taking N/2 leaves an even number for opponent.
                // Taking 1 leaves an odd number for opponent.

                // Strategy: If N is even, and N/2 is odd, taking N/2 is good.
                // This leaves an odd number for the opponent, forcing them to take 1.
                // If N is even, and N/2 is even, taking N/2 is also good.
                // This leaves an even number for the opponent, but N/2 is smaller.
                // The only exception is when N=2, taking N/2=1 is the same as taking 1.
                // For N=4, take N/2=2. Remaining 2. Opponent takes 1. Chanek takes 1. C=2+1=3. O=1.
                // For N=4, take 1. Remaining 3. Opponent takes 1. Remaining 2. Chanek takes 1. Remaining 1. Opponent takes 1. C=1+1=2. O=1+1=2.
                // So for N=4, taking N/2 is better.

                // The optimal strategy for Chanek when N is even:
                // If N is a power of 2 (and N > 2), taking N/2 is always optimal.
                // Example: N=4. Take 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0. Chanek: 2+1=3. Opponent: 1.
                // Example: N=8. Take 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0. Chanek: 4+1=5. Opponent: 2+1=3.
                // If N is even but not a power of 2, say N = 2^k * M where M is odd and M > 1.
                // Example: N=6. Take N/2=3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0. Chanek: 3+1=4. Opponent: 1+1=2.
                // Example: N=10. Take N/2=5. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0. Chanek: 5+2+1=8. Opponent: 1+1=2.
                // It seems taking N/2 is always better or equal when N is even and > 0.
                // The only exception is N=2, where taking 1 or N/2 gives the same result.
                // So, for N even and N > 0, Chanek should always take N/2.

                // Let's verify this.
                // If N is even, Chanek can take N/2. This leaves N/2 coins.
                // If N/2 is odd, the opponent is forced to take 1, leaving N/2-1 (even).
                // If N/2 is even, the opponent can also take N/4.
                // The key insight is that taking N/2 reduces the total coins significantly.
                // If Chanek takes 1, the opponent gets to play on N-1 (odd).
                // If Chanek takes N/2, the opponent gets to play on N/2.
                // The opponent will also try to maximize their coins.
                // By taking N/2, Chanek gets N/2 coins. The opponent then plays on N/2.
                // By taking 1, Chanek gets 1 coin. The opponent then plays on N-1.
                // The opponent will get more coins from N-1 than from N/2 if N-1 is much larger than N/2.
                // This happens when N is large.
                // For example, if N=10^18.
                // Take 1: Chanek gets 1. Opponent plays on 10^18-1.
                // Take N/2: Chanek gets 5*10^17. Opponent plays on 5*10^17.
                // Clearly, taking N/2 is better for Chanek.

                // The only edge case is when N/2 is 1, i.e., N=2.
                // If N=2, take N/2=1. Chanek gets 1. N=1. Opponent takes 1. Chanek: 1. Opponent: 1.
                // If N=2, take 1. Chanek gets 1. N=1. Opponent takes 1. Chanek: 1. Opponent: 1.
                // Both are same. So taking N/2 is fine.

                // So, for Chanek, if N is even, always take N/2.
                chanek_coins += n / 2;
                n /= 2;
            }
        } else { // Opponent's turn
            if (n == 1) {
                n -= 1; // Opponent takes 1
            } else if (n % 2 == 1) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                // Opponent also plays optimally to maximize their coins.
                // So opponent will also take N/2 if N is even.
                n /= 2;
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

