// Function to convert a non-negative integer to its parity pattern string
// Example: 241 -> "001", 92 -> "10", 50 -> "10"
std::string to_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern += '0';
        } else { // Odd digit
            pattern += '1';
        }
        n /= 10;
    }
    // The problem statement implies padding with 0s from the left for shorter numbers/patterns.
    // This means we need a fixed length representation for map keys.
    // Max length of number is 18 (for 10^18-1), max pattern length is 18.
    // So, we can pad to 18 characters.
    // The current pattern is built from right to left, so it's already in the correct order for comparison.
    // We just need to pad it to a fixed length.
    // Example: 241 -> "001". Padded to 18: "000000000000000001"
    // Example: 92 -> "10". Padded to 18: "000000000000000010"
    // The pattern string from the query is also processed similarly.
    // For example, query "010" means "000000000000000010"
    // This fixed length approach simplifies matching.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string
    // The key will be the 18-character parity pattern string
    // The value will be the count of numbers in the multiset that generate this pattern
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // The query pattern 's' also needs to be converted to the fixed 18-character format.
            // 's' is given from left to right, but represents digits from right to left.
            // Example: s = "010" means rightmost digit even, next odd, next even.
            // Our `to_parity_pattern` function builds the string from right to left.
            // So, we need to reverse 's' and then pad it.
            std::reverse(s.begin(), s.end());
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
