    // prefix_counts[1][i] stores count of 'y' in s[0...i-1]
    // prefix_counts[2][i] stores count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        prefix_counts[0][i + 1] = prefix_counts[0][i];
        prefix_counts[1][i + 1] = prefix_counts[1][i];
        prefix_counts[2][i + 1] = prefix_counts[2][i];
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r; // 1-indexed

