// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
        // We want the largest such x.
        // The strategy is to take p, and for each prime factor f of q,
        // remove as many factors of f from p as needed to make p no longer divisible by q,
        // but only for that specific prime factor f.
        // Then, we take the maximum of these modified p values.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Count how many times f divides q
            long long q_f_count = 0;
            long long temp_q = q;
            while (temp_q > 0 && temp_q % f == 0) {
                q_f_count++;
                temp_q /= f;
            }

            // Count how many times f divides p
            long long p_f_count = 0;
            long long temp_p = p;
            while (temp_p > 0 && temp_p % f == 0) {
                p_f_count++;
                temp_p /= f;
            }

            // If p has enough factors of f to be divisible by q (with respect to f),
            // we need to remove some factors of f from p.
            // Specifically, we need to remove p_f_count - (q_f_count - 1) factors of f.
            // This ensures that the new number has exactly q_f_count - 1 factors of f,
            // making it not divisible by q (with respect to f).
            long long factors_to_remove = p_f_count - (q_f_count - 1);

            for (int i = 0; i < factors_to_remove; ++i) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

