        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }
        // f4 = 0 means cannot move down, so target Y must be >= current Y
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
        // f2 = 0 means cannot move up, so target Y must be <= current Y
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid point exists. The problem guarantees that if a solution exists,
        // one such point has coordinates within [-10^5, 10^5].
        // We can pick any point in the valid range, e.g., (min_x, min_y).
        // We need to clamp min_x and min_y to [-10^5, 10^5] if they fall outside
        // the guaranteed range, but since the problem guarantees a solution within
        // this range, we can just output min_x and min_y directly.
        // The initial large values for min/max bounds ensure that if all robots
        // can move freely in a direction, the bound remains effectively infinite.
        // The problem statement implies that if a solution exists, min_x and min_y
