#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    int split_digit = -1; // The digit where the split occurs (digits <= split_digit go to S1, digits > split_digit go to S2)

    // Try all possible split_digit values from 0 to 9
    for (int k = 0; k <= 9; ++k) {
        std::vector<char> s1_digits;
        std::vector<char> s2_digits;
        bool possible_k = true;

        // Construct S1 and S2 based on the current split_digit k
        // Digits < k are forced into S1.
        // Digits > k are forced into S2.
        // Digits == k can be either in S1 or S2.
        // We put the first occurrence of k into S1, and subsequent occurrences into S2.

        int first_k_idx = -1;
        for (int i = 0; i < n; ++i) {
            if ((s[i] - '0') == k) {
                first_k_idx = i;
                break;
            }
        }

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < k) {
                s1_digits.push_back(s[i]);
                result[i] = '1';
            } else if (digit > k) {
                s2_digits.push_back(s[i]);
                result[i] = '2';
            } else { // digit == k
                if (i < first_k_idx) { // This case should not happen if first_k_idx is correctly found
                    // This branch is technically unreachable if first_k_idx is the first occurrence.
                    // If k is not found, first_k_idx remains -1, and this branch is not taken.
                    // If k is found, for i < first_k_idx, s[i] cannot be k.
                } else if (i == first_k_idx) {
                    s1_digits.push_back(s[i]);
                    result[i] = '1';
                } else { // i > first_k_idx
                    s2_digits.push_back(s[i]);
                    result[i] = '2';
                }
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // If both S1 and S2 are non-decreasing, then this k is a valid split_digit.
        // The combined sequence S1+S2 will be non-decreasing because:
        // 1. S1 is non-decreasing.
        // 2. S2 is non-decreasing.
        // 3. All digits in S1 are <= k. All digits in S2 are >= k.
        //    Specifically, if s1_digits is not empty, its last element is <= k.
        //    If s2_digits is not empty, its first element is >= k.
        //    So, last(S1) <= k <= first(S2).
        //    This ensures last(S1) <= first(S2).

        std::cout << result << "\n";
        return;
    }

    // If no k from 0 to 9 works
    std::cout << "-\n";
}

