    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <numeric>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
        used_in_s.insert(s[i]);
        used_in_s.insert(s[i+1]);
    }
    if (s.length() == 1) { // Handle single character password
        used_in_s.insert(s[0]);
    }

    char start_char = '\0';
    bool possible = true;

    for (char c : used_in_s) {
        if (adj[c].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Find a starting character for the path
    // It must be a character from 's' with degree 1, or if all have degree 2, any character from 's'.
    // If s has only one character, it has degree 0.
    if (used_in_s.empty()) { // Should not happen based on constraints |s| >= 1
        // This case implies s is empty, but |s| >= 1.
        // If s has one char, used_in_s will have 1 char.
        // If s has one char, adj[s[0]] will be empty.
        // So start_char will be s[0].
    } else if (used_in_s.size() == 1) {
        start_char = *used_in_s.begin();
    } else {
        for (char c : used_in_s) {
            if (adj[c].size() == 1) {
                start_char = c;
                break;
            }
        }
        if (start_char == '\0') { // All characters in s have degree 2 (implies a cycle or multiple paths)
                                  // This means it's a cycle or a path where all internal nodes have degree 2.
                                  // If it's a cycle, it's impossible to form a single path.
                                  // If it's a path, it must have two endpoints with degree 1.
                                  // So if start_char is still '\0', it means all characters in used_in_s have degree 2.
                                  // This implies a cycle or multiple disjoint paths/cycles.
                                  // A single path must have two endpoints of degree 1.
                                  // If all characters in used_in_s have degree 2, it means they form one or more cycles.
                                  // A single row keyboard is a path, not a cycle.
                                  // So if all characters in used_in_s have degree 2, it's impossible.
                                  // Example: abca -> a-b-c-a (cycle).
                                  // Example: abcd, all degree 2. This is not possible for a path.
                                  // A path of length N has 2 nodes of degree 1 and N-2 nodes of degree 2.
                                  // If all nodes have degree 2, it's a cycle.
                                  // So if start_char is still '\0', it's impossible.
            possible = false;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout_path;
    std::set<char> visited;
    if (start_char != '\0') { // If there's a character from 's' to start with
        char current = start_char;
        while (visited.find(current) == visited.end()) {
            layout_path += current;
            visited.insert(current);
            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (visited.find(neighbor) == visited.end()) {
                    next_char = neighbor;
                    break;
                }
            }
            current = next_char;
            if (current == '\0' && visited.size() < used_in_s.size()) {
                // This means we got stuck in a component that's not fully traversed,
                // or there are multiple disjoint components in 's'.
                // Example: ab, cd.
                // If we start with 'a', we get 'ab'. Then 'c' and 'd' are left.
                // This implies multiple disjoint paths/cycles in the graph formed by 's'.
                // A single keyboard layout can only represent one continuous path.
                possible = false;
                break;
            }
        }
    }

    if (!possible || visited.size() != used_in_s.size()) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining unused characters
    std::string remaining_chars;
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            remaining_chars += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_path << remaining_chars << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1}^{b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 with modular inverse.
    // Since MOD is prime (10^9 + 7), MOD_INV_2 = (MOD + 1) / 2.
    long long MOD_INV_2 = 500000004; // (1000000007 + 1) / 2

    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, b-1=0, sum is 0.

    sum_r_term = (sum_r_term % MOD * (b % MOD)) % MOD;
    sum_r_term = (sum_r_term * MOD_INV_2) % MOD;

    // Calculate sum_k = sum_{k=1}^{a} (k * b + 1)
    // sum_k = b * sum_{k=1}^{a} k + sum_{k=1}^{a} 1
    // sum_k = b * (a * (a+1) / 2) + a
    long long sum_k_term = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_term = (sum_k_term * MOD_INV_2) % MOD;
    sum_k_term = (sum_k_term * (b % MOD)) % MOD;
    sum_k_term = (sum_k_term + (a % MOD)) % MOD;

    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

