#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

// Z-algorithm implementation
std::vector<int> calculate_z_function(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    for (int i = 1, l = 0, r = 0; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    // Precompute Z-arrays for all cyclic shifts
    // z_arrays[i] stores the Z-array for s[i...n-1] + s[0...i-1]
    std::vector<std::vector<int>> z_arrays(n);
    for (int i = 0; i < n; ++i) {
        std::string shifted_s = s.substr(i) + s.substr(0, i);
        z_arrays[i] = calculate_z_function(shifted_s);
    }

    double total_win_prob = 0.0;

    // Iterate over all possible actual values of k (Kolya's choice)
    for (int actual_k = 0; actual_k < n; ++actual_k) {
        char t0_char = s[actual_k]; // The first character Vasya sees

        // Find all possible k' values that could produce t0_char
        std::vector<int> possible_k_values;
        for (int k_prime = 0; k_prime < n; ++k_prime) {
            if (s[k_prime] == t0_char) {
                possible_k_values.push_back(k_prime);
            }
        }

        if (possible_k_values.size() <= 1) {
            // If only one or zero k' values match t0_char, Vasya wins immediately.
            // (Zero k' values means actual_k was not in possible_k_values, which is impossible)
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal position p (1 to n-1)
        double max_win_prob_for_this_t0 = 0.0;

        // Iterate over all possible positions p Vasya can choose
        for (int p = 1; p < n; ++p) {
            char tp_char = s[(actual_k + p) % n]; // The character Vasya sees at position p

            int count_matches = 0;
            for (int k_prime : possible_k_values) {
                if (s[(k_prime + p) % n] == tp_char) {
                    // This k_prime is consistent with t[0] and t[p]
                    // Now check if it's consistent with the full string
                    // The string formed by k_prime is s[k_prime...n-1] + s[0...k_prime-1]
                    // The string formed by actual_k is s[actual_k...n-1] + s[0...actual_k-1]
                    // We need to check if these two strings are identical.
                    // This is equivalent to checking if s[k_prime...n-1] + s[0...k_prime-1]
                    // is equal to s[actual_k...n-1] + s[0...actual_k-1].
                    // This can be done by checking if the Z-value at index (actual_k - k_prime + n) % n
                    // in the Z-array for s[k_prime...n-1] + s[0...k_prime-1] is n.
                    // Or, more simply, check if the Z-value at index (k_prime - actual_k + n) % n
                    // in the Z-array for s[actual_k...n-1] + s[0...actual_k-1] is n.
                    // The latter is what we precomputed.

                    // The Z-array z_arrays[actual_k] is for the string starting with s[actual_k].
                    // We are comparing it with the string starting with s[k_prime].
                    // The relative shift is (k_prime - actual_k + n) % n.
                    // If z_arrays[actual_k][(k_prime - actual_k + n) % n] == n,
                    // then the string starting at k_prime is identical to the string starting at actual_k.

                    // This is the condition for two shifts to be indistinguishable.
                    // Vasya wins if only one k_prime is consistent AND leads to a unique string.
                    // The problem states: "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
                    // This means we need to count how many *distinct* cyclic shifts (full strings) are consistent.
                    // Two k_prime values, k1 and k2, are considered to produce the same cyclic shift if
                    // s[k1...n-1]s[0...k1-1] == s[k2...n-1]s[0...k2-1].
                    // This happens if z_arrays[k1][(k2 - k1 + n) % n] == n.

                    // For a fixed actual_k and chosen p, and observed t0_char, tp_char:
                    // We collect all k_prime such that s[k_prime] == t0_char and s[(k_prime+p)%n] == tp_char.
                    // Let this set be K_consistent.
                    // Vasya wins if all k_prime in K_consistent produce the same cyclic shift as actual_k,
                    // AND there is only one such distinct cyclic shift.
                    // This means all k_prime in K_consistent must produce the same string as actual_k.
                    // And no other k_prime (not in K_consistent) produces the same string as actual_k.
                    // This is equivalent to:
                    // 1. All k_prime in K_consistent must satisfy z_arrays[actual_k][(k_prime - actual_k + n) % n] == n.
                    // 2. There is no k_prime_other (not in K_consistent) such that z_arrays[actual_k][(k_prime_other - actual_k + n) % n] == n.
                    // This is too complex. The problem statement is simpler:
                    // "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
                    // This means we need to count the number of *distinct* cyclic shifts that are consistent with t[0] and t[p].
                    // If this count is 1, Vasya wins. Otherwise, he loses.

                    // Let's re-evaluate. For a given actual_k, Vasya sees s[actual_k] and s[(actual_k+p)%n].
                    // He then considers all k_prime such that s[k_prime] == s[actual_k] AND s[(k_prime+p)%n] == s[(actual_k+p)%n].
                    // From this set of k_prime, he needs to determine if there's only one *unique* cyclic shift.
                    // We can use a boolean array to mark which cyclic shifts (represented by their starting index) are consistent.
                }
            }

            std::vector<bool> is_consistent_shift(n, false);
            int distinct_consistent_shifts = 0;

            for (int k_prime_candidate = 0; k_prime_candidate < n; ++k_prime_candidate) {
                if (s[k_prime_candidate] == t0_char && s[(k_prime_candidate + p) % n] == tp_char) {
                    // This k_prime_candidate is consistent with the observed t[0] and t[p].
                    // Now, check if this k_prime_candidate represents a *new* distinct cyclic shift.
                    bool already_counted = false;
                    for (int prev_k_prime = 0; prev_k_prime < k_prime_candidate; ++prev_k_prime) {
                        if (is_consistent_shift[prev_k_prime]) {
                            // If prev_k_prime was consistent and produced the same string as k_prime_candidate,
                            // then k_prime_candidate doesn't add a new distinct shift.
                            if (z_arrays[prev_k_prime][(k_prime_candidate - prev_k_prime + n) % n] == n) {
                                already_counted = true;
                                break;
                            }
                        }
                    }
                    if (!already_counted) {
                        is_consistent_shift[k_prime_candidate] = true;
                        distinct_consistent_shifts++;
                    }
                }
            }

            if (distinct_consistent_shifts == 1) {
                // Vasya wins for this choice of p and observed characters
                max_win_prob_for_this_t0 = std::max(max_win_prob_for_this_t0, 1.0);
            } else {
                // Vasya loses for this choice of p and observed characters
                // The probability of winning for this p is 0.
                // We don't need to update max_win_prob_for_this_t0 if it's already 1.0
                // If it's 0.0, it remains 0.0.
            }
        }
        total_win_prob += max_win_prob_for_this_t0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n <= m for simpler logic, as the problem is symmetric for x and y
        if (n > m) {
            std::swap(n, m);
        }

        // Case 1: k < m. It's impossible to reach (n, m) in k moves if k is less than the maximum coordinate.
        // This is because each move changes a coordinate by at most 1.
        if (k < m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Calculate the parity of the target coordinates (n, m)
        long long n_parity = n % 2;
        long long m_parity = m % 2;

        // Calculate the parity of the total moves k
        long long k_parity = k % 2;

        long long ans;

        // If n and m have different parities, then (n_parity + m_parity) % 2 == 1.
        // This means the sum of coordinates (n+m) is odd.
        // After k moves, the current position (x,y) will have (x_parity + y_parity) % 2 == k_parity.
        // So, if (n_parity + m_parity) % 2 != k_parity, it's impossible.
        // This simplifies to: if (n % 2 != m % 2) and (k % 2 == 0), it's impossible.
        // Or, if (n % 2 == m % 2) and (k % 2 != 0), it's impossible.
        // In other words, (n % 2 == k % 2) must hold for both n and m.
        // No, this is not correct. The parity of (x+y) changes with each move.
        // A diagonal move changes (x,y) to (x+dx, y+dy) where dx, dy are both odd.
        // So (x+dx) and (y+dy) have different parities than x and y respectively.
        // (x+dx)%2 = (x%2 + 1)%2, (y+dy)%2 = (y%2 + 1)%2.
        // An axis-parallel move changes one coordinate's parity and keeps the other's.
        // (x+dx)%2 = (x%2 + 1)%2, (y+dy)%2 = y%2 (if dx=1, dy=0).
        //
        // Let's consider the parity of (n-m).
        // A diagonal move (dx, dy) changes (x-y) to (x+dx - (y+dy)) = (x-y) + (dx-dy).
        // dx-dy can be 0 (e.g., (1,1) -> 1-1=0) or +/-2 (e.g., (1,-1) -> 1-(-1)=2).
        // So a diagonal move preserves the parity of (x-y).
        // An axis-parallel move (dx, dy) changes (x-y) to (x+dx - (y+dy)).
        // If (dx,dy) = (1,0), (x-y) -> (x+1-y) = (x-y)+1. Parity flips.
        // If (dx,dy) = (0,1), (x-y) -> (x-(y+1)) = (x-y)-1. Parity flips.
        //
        // So, the parity of (x-y) flips with each axis-parallel move and stays the same with each diagonal move.
        // Let D be diagonal moves, A be axis-parallel moves.
        // Initial (x-y) is 0. Target (n-m).
        // Parity of (n-m) must be equal to parity of A.
        // (n-m)%2 == A%2.
        //
        // Also, the parity of (x+y) changes with each move.
        // A diagonal move (dx, dy) changes (x+y) to (x+dx + y+dy) = (x+y) + (dx+dy).
        // dx+dy can be 0 (e.g., (1,-1) -> 1-1=0) or +/-2 (e.g., (1,1) -> 1+1=2).
        // So a diagonal move preserves the parity of (x+y).
        // An axis-parallel move (dx, dy) changes (x+y) to (x+dx + y+dy).
        // If (dx,dy) = (1,0), (x+y) -> (x+1+y) = (x+y)+1. Parity flips.
        // If (dx,dy) = (0,1), (x+y) -> (x+y+1) = (x+y)+1. Parity flips.
        //
        // So, the parity of (x+y) flips with each axis-parallel move and stays the same with each diagonal move.
        // Initial (x+y) is 0. Target (n+m).
        // Parity of (n+m) must be equal to parity of A.
        // (n+m)%2 == A%2.
        //
        // This implies (n-m)%2 == (n+m)%2.
        // (n-m)%2 == (n+m)%2 is equivalent to (n-m) and (n+m) having the same parity.
        // (n-m) - (n+m) = -2m, which is always even.
        // So (n-m) and (n+m) always have the same parity. This condition is always met.
        //
        // The crucial condition is (n+m)%2 == A%2.
        // Since A = k - D, we have (n+m)%2 == (k-D)%2.
        // We want to maximize D.
        //
        // Consider the parity of n and m.
        // If n and m have the same parity (n%2 == m%2):
        //   Then n-m is even.
        //   (n+m) is also even.
        //   So, A must be even.
        //   Since A = k - D, (k-D) must be even.
        //   This means k and D must have the same parity.
        //   We want to maximize D.
        //   The maximum possible D is k.
        //   If k is even, we can potentially have D=k.
        //   If k is odd, we can potentially have D=k-1.
        //   The number of axis-parallel moves A must be even.
        //   If k is even, we can have A=0, D=k. This is possible if n and m are reachable.
        //   If k is odd, we must have A >= 1. A must be odd.
        //   No, A must be even. So if k is odd, D must be odd.
        //   If k is odd, and A must be even, then D must be odd.
        //   The maximum D would be k-1 (if k is odd, then k-1 is even, so A=1 is odd, this is wrong).
        //   If n%2 == m%2:
        //     (n+m) is even. So A must be even.
        //     If k is even, we can have D=k (A=0).
        //     If k is odd, we must have A >= 1. Since A must be even, A >= 2.
        //     So D <= k-2. The maximum D would be k-2.
        //     So if n%2 == m%2:
        //       If k%2 == 0, ans = k.
        //       If k%2 == 1, ans = k-2.
        //
        // If n and m have different parities (n%2 != m%2):
        //   Then n-m is odd.
        //   (n+m) is also odd.
        //   So, A must be odd.
        //   Since A = k - D, (k-D) must be odd.
        //   This means k and D must have different parities.
        //   If k is even, D must be odd. Max D = k-1.
        //   If k is odd, D must be even. Max D = k-1.
        //   So if n%2 != m%2:
        //     ans = k-1.

        // Combine these:
        // If n%2 == m%2:
        //   If k%2 == 0, ans = k.
        //   If k%2 == 1, ans = k-2.
        // Else (n%2 != m%2):
        //   ans = k-1.

        // This can be written as:
        // If (n%2 == m%2) == (k%2 == 0): ans = k.
        // Else if (n%2 == m%2) == (k%2 == 1): ans = k-2.
        // Else (n%2 != m%2): ans = k-1.
        //
        // Let's check the conditions again.
        // The minimum number of moves to reach (n,m) is max(n,m).
        // This is because each move changes max(abs(x), abs(y)) by at most 1.
        // So k must be >= m. We already checked this.

        // The maximum number of diagonal moves is k.
        // The minimum number of diagonal moves is 0.
        //
        // The number of axis-parallel moves A must have the same parity as (n+m).
        // A = k - D.
        // So (k-D) % 2 == (n+m) % 2.
        //
        // We want to maximize D.
        // If (k % 2 == (n+m) % 2):
        //   We can potentially set D = k. This means A = 0.
        //   This is possible if n and m have the same parity.
        //   If n%2 == m%2, then (n+m)%2 == 0.
        //   If k%2 == 0, then (k%2 == (n+m)%2) is true. So ans = k.
        //   If n%2 != m%2, then (n+m)%2 == 1.
        //   If k%2 == 1, then (k%2 == (n+m)%2) is true. So ans = k.
        //   This is wrong. If n%2 != m%2, then (n+m)%2 == 1.
        //   If k%2 == 1, then (k-D)%2 == 1. If D=k, then (k-k)%2 = 0 != 1. So D=k is not possible.
        //   We need (k-D)%2 == 1. If k is odd, D must be even. Max D = k-1.
        //
        // Let's re-evaluate the parity conditions based on (n,m) and k.
        //
        // Case 1: n and m have the same parity (n%2 == m%2).
        //   This means (n+m) is even.
        //   The number of axis-parallel moves A must be even.
        //   If k is even: We can have A=0, D=k. This is possible. ans = k.
        //   If k is odd: We need A to be even. Since A = k-D, and k is odd, D must be odd.
        //     The smallest even A is 2 (A cannot be 0 if k is odd).
        //     So D = k-2. This is possible. ans = k-2.
        //
        // Case 2: n and m have different parities (n%2 != m%2).
        //   This means (n+m) is odd.
        //   The number of axis-parallel moves A must be odd.
        //   If k is even: We need A to be odd. Since A = k-D, and k is even, D must be odd.
        //     The smallest odd A is 1. So D = k-1. This is possible. ans = k-1.
        //   If k is odd: We need A to be odd. Since A = k-D, and k is odd, D must be even.
        //     The smallest odd A is 1. So D = k-1. This is possible. ans = k-1.
        //
        // Summary of logic:
        // If (n % 2 == m % 2): // n and m have same parity
        //     If (k % 2 == 0): // k is even
        //         ans = k;
        //     Else: // k is odd
        //         ans = k - 2;
        // Else: // n and m have different parities
        //     ans = k - 1;

        // This logic seems correct and covers all cases.
        // The maximum number of diagonal moves is k.
        // The minimum number of diagonal moves is max(n,m) - (k - max(n,m)) if k >= max(n,m).
        // No, this is not about minimum diagonal moves.
        // The number of diagonal moves is D. The number of axis-parallel moves is A.
        // D + A = k.
        // We want to maximize D, which means minimizing A.
        //
        // The minimum number of moves to reach (n,m) is m (since n <= m).
        // This requires m diagonal moves to reach (n,n) and then m-n axis-parallel moves to reach (n,m).
        // No, this is not true. You can reach (n,m) in m moves by doing n diagonal moves to (n,n) and then m-n axis-parallel moves to (n,m).
        // This path has n diagonal moves and m-n axis-parallel moves. Total moves = n + (m-n) = m.
        // This is the minimum number of moves.
        //
        // If k = m:
        //   If n%2 == m%2:
        //     If k%2 == 0: ans = k. (Example: 2 2 2 -> 2. Path (0,0)->(1,1)->(2,2). D=2, A=0. k=2, n=2, m=2. n%2==m%2, k%2==0. Correct.)
        //     If k%2 == 1: ans = k-2. (Example: 1 1 1 -> -1. Path (0,0)->(1,1). D=1, A=0. k=1, n=1, m=1. n%2==m%2, k%2==1. ans=1-2=-1. Correct.)
        //   Else (n%2 != m%2):
        //     ans = k-1. (Example: 1 2 2 -> 1. Path (0,0)->(1,1)->(1,2). D=1, A=1. k=2, n=1, m=2. n%2!=m%2. ans=2-1=1. Correct.)
        //
        // The logic seems solid.

        if (n % 2 == m % 2) { // n and m have the same parity
            if (k % 2 == 0) { // k is even
                ans = k;
            } else { // k is odd
                ans = k - 2;
            }
        } else { // n and m have different parities
            ans = k - 1;
        }

        std::cout << ans << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // This is for jars 1 to k.
    // diff_L[0] = 0 (empty prefix)
    // diff_L[k] = diff_L[k-1] + (a[k-1] == 1 ? 1 : -1)
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // diff_R[k] = (count of 1s in a[2n-k...2n-1]) - (count of 2s in a[2n-k...2n-1])
    // This is for jars 2n-k+1 to 2n.
    // diff_R[0] = 0 (empty suffix)
    // diff_R[k] = diff_R[k-1] + (a[2n-k] == 1 ? 1 : -1)
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left (L)
    // to achieve a certain difference (s1_L - s2_L).
    // key: difference, value: L
    std::map<int, int> left_diff_to_L;
    for (int L = 0; L <= n; ++L) {
        int current_diff = diff_L[L];
        if (left_diff_to_L.find(current_diff) == left_diff_to_L.end()) {
            left_diff_to_L[current_diff] = L;
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars eaten from the right (R)
    for (int R = 0; R <= n; ++R) {
        int current_diff_R = diff_R[R];
        // We need s1_rem - s2_rem = 0.
        // This means (s1_total - s1_eaten) - (s2_total - s2_eaten) = 0
        // (s1_total - s2_total) - (s1_eaten - s2_eaten) = 0
        // (s1_total - s2_total) = (s1_eaten - s2_eaten)
        // Let D_total = s1_total - s2_total.
        // Let D_eaten = s1_eaten - s2_eaten.
        // We need D_total = D_eaten.
        // D_eaten = (s1_L_eaten - s2_L_eaten) + (s1_R_eaten - s2_R_eaten)
        // The jars eaten from left are a[0...L-1]. Their diff is diff_L[L].
        // The jars eaten from right are a[2n-R...2n-1]. Their diff is diff_R[R].
        // So, we need diff_L[L] + diff_R[R] = 0.
        // This means diff_L[L] = -diff_R[R].

        int target_diff_L = -current_diff_R;

        if (left_diff_to_L.count(target_diff_L)) {
            int L = left_diff_to_L[target_diff_L];
            min_jars_eaten = std::min(min_jars_eaten, L + R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // Case 1: Substring starts with '0'
            // The value f(s_l...s_r) is 0 if all characters are '0'.
            // If s_l...s_r consists of k zeros, its value is 0.
            // The length is k. So, 0 = k implies k=0, which is not possible for a non-empty substring.
            // Thus, a substring of all zeros cannot be good.
            // If there's a '1' in s_l...s_r, say at s_j, then f(s_l...s_r) > 0.
            // The value f(s_l...s_r) is the same as f(s_k...s_r) where s_k is the first '1'.
            // Let's count consecutive zeros before a '1'.
            int j = i;
            while (j < n && s[j] == '0') {
                j++;
            }
            // Now s[j] is either '1' or we reached end of string.
            // The number of leading zeros is `leading_zeros = j - i`.
            // We are interested in substrings starting at `i`.
            // For any substring s[i...k] where s[i] is '0', its value is f(s[first_one_idx...k]).
            // The length is k - i + 1.
            // The value is f(s[first_one_idx...k]).
            // The condition is k - i + 1 = f(s[first_one_idx...k]).
            // This is equivalent to (k - first_one_idx + 1) + (first_one_idx - i) = f(s[first_one_idx...k]).
            // Let L_prime = k - first_one_idx + 1 be the length of the suffix starting with '1'.
            // Let Z = first_one_idx - i be the number of leading zeros.
            // Condition becomes L_prime + Z = f(s[first_one_idx...k]).
            // Since f(s[first_one_idx...k]) >= L_prime (because 2^L_prime-1 is max value, and 2^X >= X+1 for X>=0),
            // we need Z to be small.
            // Specifically, f(s[first_one_idx...k]) - L_prime = Z.
            // The maximum possible value for f(s[first_one_idx...k]) - L_prime is 2^L_prime - 1 - L_prime.
            // This value grows very fast.
            // For L_prime = 1, max Z = 2^1 - 1 - 1 = 0.
            // For L_prime = 2, max Z = 2^2 - 1 - 2 = 1.
            // For L_prime = 3, max Z = 2^3 - 1 - 3 = 4.
            // For L_prime = 4, max Z = 2^4 - 1 - 4 = 11.
            // For L_prime = 5, max Z = 2^5 - 1 - 5 = 26.
            // For L_prime = 6, max Z = 2^6 - 1 - 6 = 57.
            // For L_prime = 7, max Z = 2^7 - 1 - 7 = 120.
            // For L_prime = 8, max Z = 2^8 - 1 - 8 = 247.
            // For L_prime = 9, max Z = 2^9 - 1 - 9 = 502.
            // For L_prime = 10, max Z = 2^10 - 1 - 10 = 1013.
            // For L_prime = 11, max Z = 2^11 - 1 - 11 = 2036.
            // For L_prime = 12, max Z = 2^12 - 1 - 12 = 4083.
            // For L_prime = 13, max Z = 2^13 - 1 - 13 = 8174.
            // For L_prime = 14, max Z = 2^14 - 1 - 14 = 16371.
            // For L_prime = 15, max Z = 2^15 - 1 - 15 = 32752.
            // For L_prime = 16, max Z = 2^16 - 1 - 16 = 65519.
            // For L_prime = 17, max Z = 2^17 - 1 - 17 = 131054.
            // For L_prime = 18, max Z = 2^18 - 1 - 18 = 262127.
            // For L_prime = 19, max Z = 2^19 - 1 - 19 = 524268.
            // For L_prime = 20, max Z = 2^20 - 1 - 20 = 1048555.
            // Max N is 2e5. So max Z is N. Max L_prime is N.
            // If L_prime is around 18, max Z is already > N.
            // So we only need to check L_prime up to about 18-20.
            // This means we only need to check substrings of length up to about 20 after the first '1'.

            // Iterate through possible ending positions `k` for substrings starting at `i`.
            // `k` goes from `i` to `n-1`.
            // `current_val` will store f(s[first_one_idx...k]).
            // `first_one_idx` is the index of the first '1' in s[i...k].
            // `leading_zeros` is `first_one_idx - i`.

            long long current_val = 0;
            int first_one_idx = -1;
            for (int k = i; k < n; ++k) {
                if (s[k] == '1') {
                    if (first_one_idx == -1) {
                        first_one_idx = k;
                    }
                    current_val = (current_val << 1) | 1;
                } else { // s[k] == '0'
                    if (first_one_idx != -1) { // If we've seen a '1' already
                        current_val = (current_val << 1);
                    }
                    // If first_one_idx is still -1, it means all chars from i to k are '0'.
                    // In this case, current_val remains 0.
                }

                if (first_one_idx != -1) { // Only consider substrings with at least one '1'
                    int len = k - i + 1;
                    if (current_val == len) {
                        good_substrings_count++;
                    }
                    // Optimization: If current_val exceeds len + max_leading_zeros_possible, break.
                    // Max leading zeros is n.
                    // If current_val > len + n, then current_val - len > n.
                    // Since Z <= n, this substring cannot be good.
                    // Also, if current_val becomes too large, it will keep growing.
                    if (current_val > len + n) { // current_val > len + (n-1) is a safer bound
                        break;
                    }
                }
            }
        } else { // s[i] == '1'
            // Case 2: Substring starts with '1'
            // Here, first_one_idx is always `i`.
            // `leading_zeros` is 0.
            // Condition is `len = f(s_i...s_r)`.
            long long current_val = 0;
            for (int k = i; k < n; ++k) {
                current_val = (current_val << 1) | (s[k] - '0');
                int len = k - i + 1;
                if (current_val == len) {
                    good_substrings_count++;
                }
                // Optimization: If current_val exceeds len, it will only grow faster.
                // So, if current_val > len, no further extension of this substring can be good.
                // This is because current_val grows exponentially, while len grows linearly.
                // Specifically, if current_val > len, then for the next character s[k+1],
                // new_val = current_val * 2 + s[k+1] - '0'
                // new_len = len + 1
                // new_val > 2 * len.
                // We need new_val = new_len.
                // If 2 * len >= len + 1, then new_val > new_len.
                // This holds for len >= 1.
                // So, if current_val > len, we can break.
                if (current_val > len + 2) { // A small buffer for safety, but len+1 is usually enough
                    break;
                }
            }
        }
    }
    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

