    // Initialize two values:
    // val0: what 0 becomes after all operations
    // val1: what 1023 becomes after all operations
    // We use 0 and 1023 because they represent all 0s and all 1s across the 10 bits.
    // For any bit position j:
    // The j-th bit of val0 shows what 0_j (0) becomes.
    // The j-th bit of val1 shows what 1_j (1) becomes.
    int val0 = 0;
    int val1 = 1023; // All 10 bits set to 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1 ^= x;
        }
    }

    // Now we have the final state of 0 and 1023.
    // For each bit position j (0 to 9):
    // Let x_j be the j-th bit of the input.
    // Let f_j(x_j) be the j-th bit of the output.
