    // If (val0_j == 1) and (val1_j == 0): f_j(x_j) = !x_j = x_j ^ 1. (XOR 1)
    // If (val0_j == 0) and (val1_j == 0): f_j(x_j) = 0 = x_j & 0. (AND 0)
    // If (val0_j == 1) and (val1_j == 1): f_j(x_j) = 1 = x_j | 1. (OR 1)

