        std::vector<long long> a(n);
        int min_idx = 0;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < a[min_idx]) {
                min_idx = i;
            }
        }

        long long total_operations = 0;
        long long min_val = a[min_idx];

        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue;
            }
            // For each other pile a[i], we can add min_val to it
            // until a[i] exceeds k.
            // The number of times we can add min_val is (k - a[i]) / min_val.
            // Note: k - a[i] could be 0 if a[i] == k, resulting in 0 operations.
            // If a[i] > k, this logic would be problematic, but problem constraints state a_i <= k.
            total_operations += (k - a[i]) / min_val;
        }
        std::cout << total_operations << "\n";
    }
    return 0;
}

#include <iostream>
