#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem guarantees that a solution exists.
    // Reversing the permutation always yields a permutation with the same fingerprint.
    // If the original permutation is not a palindrome, then the reversed permutation
    // will be different.
    // A permutation is a palindrome if p_i = p_{n-1-i} for all i.
    // For n >= 2, a permutation [1, 2, ..., n] is never a palindrome unless n=1 (which is not allowed)
    // or n=2 and p=[1,2] (not a palindrome) or p=[2,1] (not a palindrome).
    // The only way p could be equal to its reverse is if p_i = p_{n-1-i}.
    // For example, if n=3, p=[1,2,3], reverse is [3,2,1]. Different.
    // If n=4, p=[1,2,3,4], reverse is [4,3,2,1]. Different.
    // In general, for a permutation of distinct elements from 1 to n,
    // p_i = p_{n-1-i} for all i implies that the sequence is symmetric.
    // For example, [1,2,1] is not a permutation. [1,2,3,2,1] is not a permutation.
    // The only way p could be equal to its reverse is if p_i = p_{n-1-i} for all i.
    // This would mean that if n is odd, the middle element p_{n/2} is equal to itself.
    // If n is even, all elements must appear in pairs (p_i, p_{n-1-i}) where p_i = p_{n-1-i}.
    // But a permutation has distinct elements.
    // So, p_i must be distinct from p_{n-1-i} unless i = n-1-i (which means n is odd and i is the middle index).
    // If p is a permutation, and p_i = p_{n-1-i} for all i, then for i != n-1-i, we would have p_i = p_{n-1-i},
    // which means two distinct indices have the same value, violating the permutation property.
    // Therefore, p_i must be different from p_{n-1-i} for i != n-1-i.
    // This means that p cannot be equal to its reverse unless n=1 (not allowed) or n=0.
    // So, reversing the permutation always produces a different permutation.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

