#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int current_a1 = a[0];
    int remaining_days = d;

    for (int i = 1; i < n; ++i) {
        int pile_index = i; // 0-indexed pile_index
        int haybales_in_pile = a[pile_index];
        int days_to_move_one = pile_index; // 0-indexed distance from pile 0

        if (days_to_move_one == 0) { // This should only happen for a[0], which is handled by current_a1
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // Each haybale costs 'days_to_move_one' days
        int haybales_can_move = 0;
        if (days_to_move_one > 0) {
            haybales_can_move = remaining_days / days_to_move_one;
        }

        // We can move at most 'haybales_in_pile' haybales from this pile
        int actual_haybales_to_move = std::min(haybales_in_pile, haybales_can_move);

        current_a1 += actual_haybales_to_move;
        remaining_days -= actual_haybales_to_move * days_to_move_one;
    }

    std::cout << current_a1 << std::endl;
}

