        // For example, if we pick a[i] and a[j] as medians, with i < n-1 and j > n, then a[j] - a[i] >= a[n] - a[n-1].
        // If we pick a[i] and a[j] with i < n-1 and j = n, then a[n] - a[i] >= a[n] - a[n-1].
        // If we pick a[i] and a[j] with i = n-1 and j > n, then a[j] - a[n-1] >= a[n] - a[n-1].
        // The minimum difference is always between a[n] and a[n-1].
        long long diff = a[n] - a[n - 1];
        std::cout << diff << "\n";
    }
    return 0;
}

