    while (t--) {
        std::string s;
        std::cin >> s;
        int max_dist = 0;
        int last_R_pos = 0; // Represents the last position from which a right jump was possible (or cell 0)
                            // For cell 0, it's 0. For cell i, if s[i-1] is 'R', it's i.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R', it means we can jump from this cell (i+1) to the right.
                // The distance needed to reach this 'R' cell (i+1) from the previous 'R' cell (last_R_pos)
                // is (i+1) - last_R_pos.
                // We need to be able to make this jump.
                max_dist = std::max(max_dist, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current 'R' cell
            }
        }
        // After iterating through the string, we need to consider the jump from the last 'R' cell
        // (or cell 0 if no 'R's) to the target cell n+1.
        // The distance needed for this final jump is (n+1) - last_R_pos.
        max_dist = std::max(max_dist, (int)s.length() + 1 - last_R_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

