#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0) {
            // Only add ')' if we have already added enough '(' to balance it
            // or if we are just trying to fill up the remaining close_needed
            // after all open_needed are taken.
            // The condition `result.length() < k` ensures we don't exceed k.
            // The condition `result.length() - (k/2 - open_needed) < close_needed`
            // is implicitly handled by `close_needed > 0` and the overall length check.
            // A simpler approach is to just take the first k/2 '(' and then the first k/2 ')'
            // that appear after those '('.
            // However, the problem guarantees a solution exists.
            // A greedy approach that takes k/2 opening brackets and then k/2 closing brackets
            // from the remaining string (or from the original string, ensuring order)
            // will always produce a valid regular bracket sequence.
            // The most straightforward way to ensure regularity and subsequence property
            // is to take the first k/2 '(' characters encountered, and then the first k/2 ')' characters
            // encountered *after* those '(' characters.
            // This can be simplified: take k/2 '(' characters, then take k/2 ')' characters.
            // The order of taking them from 's' ensures subsequence property.
            // The order of appending them to 'result' ensures regularity.
            // The current logic: take '(' until open_needed is 0. Then take ')' until close_needed is 0.
            // This will produce a sequence like "((...))".
            // Example: s = "()(())", k = 4
            // open_needed = 2, close_needed = 2
            // c = '(': result = "(", open_needed = 1
            // c = ')': result = "()", close_needed = 1 (this is wrong, we need to prioritize open brackets first)

            // Let's refine the greedy strategy:
            // Take the first k/2 opening brackets.
            // Then take the first k/2 closing brackets that appear *after* the last chosen opening bracket.
            // This is equivalent to:
            // Iterate through s. If we need an opening bracket and see one, take it.
            // If we need a closing bracket and see one, take it.
            // But we must ensure the balance property.
            // A simpler approach for "any" regular bracket sequence:
            // Take k/2 opening brackets.
            // Then take k/2 closing brackets.
            // This will form `((...))`.
            // Example: s = "()(())", k = 4
            // We need 2 '(', 2 ')'.
            // Take first 2 '(': s[0] = '(', s[2] = '('. Result: "((".
            // Then take first 2 ')' after s[2]: s[3] = ')', s[4] = ')'. Result: "(())".
            // This is a valid regular bracket sequence and a subsequence.

            // The current code's logic:
            // It tries to take '(' first.
            // If `open_needed` is 0, it means we have taken all `k/2` opening brackets.
            // Then it will only take ')' if `close_needed` is > 0.
            // This will effectively construct `k/2` opening brackets followed by `k/2` closing brackets.
            // This is always a regular bracket sequence.
            // Let's trace `s = "()(())", k = 4`:
            // open_needed = 2, close_needed = 2
            // c = '(': result = "(", open_needed = 1
            // c = ')': (open_needed is not 0, so this ')' is skipped)
            // c = '(': result = "((", open_needed = 0
            // c = '(': (open_needed is 0, so this '(' is skipped)
            // c = ')': (open_needed is 0, close_needed is 2) result = "(()", close_needed = 1
            // c = ')': (open_needed is 0, close_needed is 1) result = "(())", close_needed = 0
            // Loop ends. result = "(())". This is correct for the example.

            // Let's trace `s = "(()(()))", k = 8`:
            // open_needed = 4, close_needed = 4
            // c = '(': result = "(", open_needed = 3
            // c = '(': result = "((", open_needed = 2
            // c = ')': skipped (open_needed != 0)
            // c = '(': result = "(((", open_needed = 1
            // c = '(': result = "((((", open_needed = 0
            // c = ')': result = "(((()", close_needed = 3
            // c = ')': result = "(((()))", close_needed = 2
            // c = ')': result = "(((())))", close_needed = 1
            // Loop ends. result = "(((())))". This is correct.

            // The logic is correct. It prioritizes taking all required opening brackets first,
            // then takes all required closing brackets. This forms a sequence like `((...))`.
            // This is always a regular bracket sequence and a subsequence of `s`.
            // The problem guarantees such a sequence exists.

            if (open_needed == 0 && close_needed > 0) {
                result += ')';
                close_needed--;
            }
        }
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
