void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the range is just pos[1] to pos[1].
        // min_idx = pos[1], max_idx = pos[1]. Length is 1.
        // This is a permutation of [1]. So 1 is beautiful.
        if (m == 1) {
            result += '1';
            continue;
        }

        // For m > 1, we need to include 'm' into the current range.
        // The current range [current_min_idx, current_max_idx] already covers 1, ..., m-1.
        // To cover 1, ..., m, we must extend the range to include 'm'.
        // The new range will be [min(current_min_idx, pos[m]), max(current_max_idx, pos[m])].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current range [current_min_idx, current_max_idx]
        // forms a permutation of 1, ..., m.
        // This requires two conditions:
        // 1. The minimum element in p[current_min_idx ... current_max_idx] is 1. (Guaranteed by construction)
        // 2. The maximum element in p[current_min_idx ... current_max_idx] is m. (Guaranteed by construction)
        // 3. The length of the subarray must be exactly m.
        //    Length = current_max_idx - current_min_idx + 1.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

