int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For real solutions, d^2 - 4d >= 0
            // d(d - 4) >= 0
            // Since d >= 0, this means d - 4 >= 0, so d >= 4.
            // If d = 0, it's a special case handled above.
            // If d >= 4, then d^2 - 4d >= 0, so sqrt(d^2 - 4d) is real.

            double sqrt_discriminant = std::sqrt(d * d - 4 * d);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a, b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d >= 4, then d-4 >= 0, so sqrt_discriminant >= 0.
            // Thus, d + sqrt_discriminant >= d > 0, so a1 > 0.
            // Also, d - sqrt_discriminant = d - sqrt(d^2 - 4d).
            // We know d^2 > d^2 - 4d (since 4d > 0 for d > 0).
            // So sqrt(d^2) > sqrt(d^2 - 4d) => d > sqrt(d^2 - 4d).
            // Therefore, d - sqrt(d^2 - 4d) > 0, so b1 > 0.
            // Both a1 and b1 are guaranteed to be positive for d > 4.
            // If d = 4, sqrt_discriminant = 0, so a1 = b1 = 4/2 = 2.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

