#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check if it's possible to form the increasing part
    // For a_i to be part of an increasing sequence 0, 1, 2, ..., i-1,
    // it must be at least i-1.
    // We can decrease a_i, so we need a_i_original >= i-1.
    // Let's find the maximum index `left_reach` such that a_0, ..., a_left_reach
    // can form 0, 1, ..., left_reach.
    int left_reach = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_reach = i;
        } else {
            break;
        }
    }

    // Check if it's possible to form the decreasing part
    // For a_i to be part of a decreasing sequence ..., 2, 1, 0 (from right),
    // it must be at least n-1-i.
    // We can decrease a_i, so we need a_i_original >= n-1-i.
    // Let's find the minimum index `right_reach` such that a_right_reach, ..., a_{n-1}
    // can form (n-1-right_reach), ..., 0.
    int right_reach = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_reach = i;
        } else {
            break;
        }
    }

    // An array is sharpened if there exists a peak k (0-indexed)
    // such that a_0 < ... < a_k and a_k > ... > a_{n-1}.
    // This means a_0, ..., a_k must be able to form 0, ..., k
    // AND a_k, ..., a_{n-1} must be able to form (k - (n-1-k)), ..., 0.
    // The condition for the increasing part is that a_i >= i for i <= k.
    // The condition for the decreasing part is that a_i >= n-1-i for i >= k.
    // So, we need to find if there's any index `k` such that:
    // `k` is reachable from the left (i.e., `k <= left_reach`)
    // AND `k` is reachable from the right (i.e., `k >= right_reach`)

    if (left_reach >= right_reach) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

