long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case: if N=2, Chanek takes 1, opponent takes 1. Chanek gets 1.
                chanek_coins += 1;
                n -= 1; // N becomes 1, next turn opponent takes 1.
            } else if ((n / 2) % 2 != 0) { // N/2 is odd
                // If Chanek takes N/2, remaining N/2 is odd. Opponent takes 1.
                // If Chanek takes 1, remaining N-1 is odd. Opponent takes 1.
                // Taking N/2 is better for Chanek.
                chanek_coins += n / 2;
                n /= 2;
            } else { // N/2 is even
                // If Chanek takes N/2, remaining N/2 is even. Opponent can take (N/2)/2 = N/4.
                // If Chanek takes 1, remaining N-1 is odd. Opponent takes 1.
                // Taking 1 is better for Chanek.
                chanek_coins += 1;
                n -= 1;
            }
        }
        // Opponent's turn logic (implicitly handled by the optimal choice for Chanek)
        // The opponent will also play optimally to maximize their own coins.
        // This means if N is odd, opponent takes 1.
        // If N is even, opponent takes N/2 if N/2 is odd, otherwise takes 1.
        // The key is that Chanek's decision is based on what's left for the opponent.
        // The opponent's turn is not explicitly simulated here, but their optimal play
        // influences Chanek's optimal choice.
        // The logic above for Chanek's turn already incorporates this.
        // For example, if N is even and N/2 is even, Chanek takes 1.
        // This leaves N-1 (odd) for the opponent. Opponent takes 1.
        // If Chanek took N/2, it leaves N/2 (even) for the opponent. Opponent takes N/4.
        // Chanek wants to minimize what the opponent gets from the remaining pile,
        // or maximize what Chanek gets directly.
        // The current logic is a greedy approach that works for this specific game.
    }
    return chanek_coins;
}

