// Function to determine if a box can be the special box
// A, B, C, D are initial counts of toys in boxes 1, 2, 3, 4 respectively.
// target_box_idx is 0 for Box 1, 1 for Box 2, 2 for Box 3, 3 for Box 4.
bool can_be_special(long long A, long long B, long long C, long long D, int target_box_idx) {
    long long total_toys = A + B + C + D;

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        return false;
    }
    if (total_toys == 1) {
        if (A == 1 && target_box_idx == 0) return true;
        if (B == 1 && target_box_idx == 1) return true;
        if (C == 1 && target_box_idx == 2) return true;
        if (D == 1 && target_box_idx == 3) return true;
        return false;
    }

    // Case 1: Target Box 1 (fun value <= -1)
    if (target_box_idx == 0) {
        // To get a negative result, we need an odd number of negative factors.
        // To get magnitude >= 1, we need to be able to achieve it.
        // If there are any toys in Box 1 or Box 4, we can always achieve magnitude >= 1.
        // If all toys are in Box 2 and Box 3, then all products will have magnitude < 1.
        if (A == 0 && D == 0) { // All toys are initially in (-1, 1)
            return false; // Cannot achieve magnitude >= 1
        }

        // We need an odd number of negative factors.
        // Number of negative factors is A + B.
        // If A + B is odd, we can potentially end up with a negative number.
        // If A + B is even, we can potentially end up with a positive number.
        // We can always manipulate the parity of negative factors by pairing them up.
        // For example, if we have two negative numbers, we can multiply them to get a positive.
        // If we have one negative and one positive, we get a negative.
        // The final sign depends on the parity of negative numbers used in the final product.
        // We can always choose to have an odd number of negative factors in the final product
        // if there is at least one negative toy (A+B > 0).
        // If A+B is 0, then all initial toys are positive, so the final product must be positive.
        if (A + B == 0) { // All initial toys are positive
            return false; // Cannot get a negative result
        }
        return true;
    }

    // Case 2: Target Box 2 (fun value in (-1, 0))
    if (target_box_idx == 1) {
        // To get a negative result, we need an odd number of negative factors.
        // If A+B is 0, all initial toys are positive, so final product must be positive.
        if (A + B == 0) {
            return false; // Cannot get a negative result
        }

        // To get magnitude < 1, we need to be able to achieve it.
        // If there are any toys in Box 1 or Box 4, we can always make a product >= 1.
        // If we have at least one toy in Box 2 or Box 3, we can multiply it with something else
        // to potentially get a value < 1.
        // The only way we *cannot* get a value < 1 is if all initial toys are >= 1 (i.e., A=0, B=0, C=0, D > 0).
        // But even then, if we have multiple D toys, say 1.5 and 2, their product is 3.
        // The question is whether we can *force* the final product to be < 1.
        // If A+B+C+D > 1, we can always pick two toys from Box 2 or Box 3 (if available)
        // or multiply a large number by a small number to get a small number.
        // Example: -3 (A), -0.5 (B), -0.5 (B), 3 (D)
        // (-0.5)*(-0.5) = 0.25 (C)
        // (-3)*(0.25) = -0.75 (B)
        // (-0.75)*(3) = -2.25 (A) -> This is not Box 2.
        // Example from problem: -3 (A), -0.33 (B), -0.25 (B), 3 (D)
        // (-3)*(-0.33) = 0.99 (C)
        // (0.99)*(3) = 2.97 (D)
        // (2.97)*(-0.25) = -0.7425 (B) -> This is Box 2.
        // This shows that if there are enough toys, we can manipulate the magnitude.
        // The only constraint is if all toys are in Box 1 or Box 4, and we can't get a small magnitude.
        // If A+B+C+D > 1, and A+B > 0, we can always achieve a negative value.
        // Can we always achieve magnitude < 1?
        // If C > 0 or B > 0, we can use these to reduce magnitude.
        // If A > 0 or D > 0, we can use these to increase magnitude.
        // If A=0, B=0, C=0, D=1, then the toy is in Box 4.
        // If A=0, B=0, C=1, D=0, then the toy is in Box 3.
        // If A=0, B=1, C=0, D=0, then the toy is in Box 2.
        // If A=1, B=0, C=0, D=0, then the toy is in Box 1.
        // If total_toys == 1, the answer is determined by the initial box.
        // For total_toys > 1:
        // If A+B > 0 (can get negative sign)
        // If C > 0 or B > 0, we can use these to get magnitude < 1.
        // If A=0, B=0, C=0, D > 0, then all toys are >= 1. Product will be >= 1. Cannot be Box 2.
        // If A > 0, B=0, C=0, D > 0, then all toys are <= -1 or >= 1. Product will be <= -1 or >= 1. Cannot be Box 2.
        // The only way to guarantee magnitude < 1 is if we have at least one toy in Box 2 or Box 3.
        // If B+C == 0, then all toys are in Box 1 or Box 4.
        // In this case, any product of two toys from Box 1 or Box 4 will result in a toy in Box 1 or Box 4.
        // So if B+C == 0, we cannot end up in Box 2 or Box 3.
        if (B + C == 0) {
            return false; // Cannot achieve magnitude < 1
        }
        return true;
    }

    // Case 3: Target Box 3 (fun value in (0, 1))
    if (target_box_idx == 2) {
        // To get a positive result, we need an even number of negative factors.
        // If A+B is odd, we can pair up all but one negative toy, then multiply by positives.
        // If A+B is even, we can pair up all negative toys.
        // So, we can always achieve a positive result.
        // The only way we cannot achieve a positive result is if A+B+C+D == 0, which is not allowed.
        // Or if we only have one toy and it's negative. But total_toys > 1 for this logic.
        // If total_toys == 1 and it's negative, then it's not Box 3.
        // If total_toys > 1, we can always make a positive product if we want to.
        // For example, if A=1, B=0, C=0, D=0, total_toys=1, then it's Box 1.
        // If A=1, B=1, C=0, D=0, total_toys=2. Multiply them: (-ve)*(-ve) = +ve.
        // So, we can always achieve a positive sign.

        // To get magnitude < 1, similar logic to Box 2.
        // If B+C == 0, then all toys are in Box 1 or Box 4.
        // In this case, any product of two toys from Box 1 or Box 4 will result in a toy in Box 1 or Box 4.
        // So if B+C == 0, we cannot end up in Box 2 or Box 3.
        if (B + C == 0) {
            return false; // Cannot achieve magnitude < 1
        }
        return true;
    }

    // Case 4: Target Box 4 (fun value >= 1)
    if (target_box_idx == 3) {
        // To get a positive result, we need an even number of negative factors.
        // We can always achieve a positive result if total_toys > 1.
        // If total_toys == 1 and it's negative, then it's not Box 4.
        // If total_toys > 1, we can always make a positive product.

        // To get magnitude >= 1, we need to be able to achieve it.
        // If A == 0 && D == 0, then all toys are initially in (-1, 1).
        // Any product of toys from Box 2 or Box 3 will result in a toy in Box 2 or Box 3.
        // So if A == 0 && D == 0, we cannot end up in Box 1 or Box 4.
        if (A == 0 && D == 0) {
            return false; // Cannot achieve magnitude >= 1
        }
        return true;
    }

    return false; // Should not reach here
}

