bool is_permutation(const std::vector<int>& arr, int len) {
    if (len == 0) return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero lengths.
                               // For this problem, l1, l2 >= 1.
    if (len > arr.size()) return false;

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (arr[i] < 1 || arr[i] > len) {
            return false;
        }
        if (seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_prefix_val = 0;
    bool prefix_distinct = true;
    for (int l = 1; l <= n; ++l) {
        int current_val = a[l - 1];
        if (current_val < 1 || current_val > l || seen_prefix[current_val]) {
            prefix_distinct = false;
        }
        if (prefix_distinct) {
            seen_prefix[current_val] = true;
            if (current_val > max_prefix_val) {
                max_prefix_val = current_val;
            }
            if (max_prefix_val == l) {
                is_prefix_perm[l] = true;
            }
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_suffix_val = 0;
    bool suffix_distinct = true;
    for (int l = 1; l <= n; ++l) {
        int current_val = a[n - l];
        if (current_val < 1 || current_val > l || seen_suffix[current_val]) {
            suffix_distinct = false;
        }
        if (suffix_distinct) {
            seen_suffix[current_val] = true;
            if (current_val > max_suffix_val) {
                max_suffix_val = current_val;
            }
            if (max_suffix_val == l) {
                is_suffix_perm[l] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

