#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let's try to append at most 2 elements.
    // The problem statement says "at most 3 elements".
    // A common strategy for these problems is to append 2 elements: X and S+X.
    // Let's try to append two elements: X_0 and S_0 + X_0.
    // New sum S' = S_0 + X_0 + (S_0 + X_0) = 2*S_0 + 2*X_0
    // New XOR sum X' = X_0 ^ X_0 ^ (S_0 + X_0) = 0 ^ (S_0 + X_0) = S_0 + X_0
    // For the array to be good, we need S' = 2*X'.
    // So, 2*S_0 + 2*X_0 = 2 * (S_0 + X_0).
    // This equation is always true.
    // So, appending X_0 and S_0 + X_0 always makes the array good.
    // The number of appended elements is 2.
    // The values are current_xor_sum and current_sum + current_xor_sum.
    // These values can be large, up to 10^9 * 10^5 + 10^9 ~ 10^14 + 10^9, which fits in long long.

    // The problem asks to append AT MOST 3 elements.
    // If the array is already good, we can append 0 elements.
    // If not, we can append 2 elements as described above.

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

