            // these 'a's will contribute 'count_a' steps.
            // After these 'count_a' 'a's move past this 'b', they will create 'count_a' new 'b's.
            // These new 'b's will then be available for 'a's further to the left.
            // The number of 'a's that need to move past subsequent 'b's effectively doubles.
            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it adds to the count of 'a's that are
            // waiting to move past 'b's to their right.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

