// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        return "0"; // Special case for 0
    }
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern += '0';
        } else { // Odd digit
            pattern += '1';
        }
        n /= 10;
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // The pattern s from input is already in the canonical form
            // (no leading zeros, unless it's "0").
            // The get_parity_pattern function also produces this form.
            // So, we can directly use s as the key.
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
    // This is the only way to force a '0' in w.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce s.
    // For each s[i], check if it can be '1' based on w.
    // If s[i] is '1', but our w cannot produce '1' at s[i], then no solution exists.
    for (int i = 0; i < n; ++i) {
        bool can_be_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            can_be_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            can_be_one = true;
        }

        if (s[i] == '1' && !can_be_one) {
            std::cout << -1 << std::endl;
            return;
        }
        // If s[i] == '0', we don't need to check can_be_one.
        // Our construction of w already ensures that if s[i] is '0',
        // then both w[i-x] and w[i+x] are '0' (if they exist),
        // so can_be_one would be false, which is consistent.
    }

    std::cout << w << std::endl;
}

