#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // `i` represents the number of items taken from the left (w_1, ..., w_i)
    // `n - i` represents the number of items taken from the right (w_{i+1}, ..., w_n)
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Cost for items taken from the left
        // These are w_1, ..., w_i
        current_energy += prefix_sum[i] * l;

        // Cost for items taken from the right
        // These are w_{i+1}, ..., w_n
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for taking more items from one side
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items from left. The last item taken must have been from the left.
            // The difference is (left_count - right_count).
            // If left_count = right_count + 1, no penalty.
            // If left_count = right_count + 2, one extra Ql.
            // If left_count = right_count + k, (k-1) extra Ql.
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items from right. The last item taken must have been from the right.
            // The difference is (right_count - left_count).
            // If right_count = left_count + 1, no penalty.
            // If right_count = left_count + 2, one extra Qr.
            // If right_count = left_count + k, (k-1) extra Qr.
            current_energy += (right_count - left_count - 1) * Qr;
        }
        // If left_count == right_count, no penalty.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

