// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // This means x must be p / (some factor of p that makes it not divisible by q).
        // To maximize x, we need to divide p by the smallest possible factor that makes it not divisible by q.
        // This smallest factor must be composed of prime factors of q.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long factor_q_prime : q_prime_factors) {
            long long current_p = p;
            while (current_p % factor_q_prime == 0) {
                current_p /= factor_q_prime;
            }
            // Now current_p is p with all occurrences of factor_q_prime removed.
            // If current_p is not divisible by q, then it's a candidate for x.
            // However, we need to ensure that p / (factor_q_prime^k) is not divisible by q.
            // The strategy is to remove just enough of factor_q_prime from p such that
            // p / (factor_q_prime^k) is no longer divisible by q.
            // This means we need to find the smallest k such that (p / factor_q_prime^k) % q != 0.
            // This is equivalent to finding the largest x = p / (factor_q_prime^k) such that x % q != 0.

            long long temp_p = p;
            while (temp_p % q == 0) { // Keep dividing temp_p by factor_q_prime until it's no longer divisible by q
                temp_p /= factor_q_prime;
            }
            max_x = std::max(max_x, temp_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

