#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // Since b-1 or b might be odd, we need to handle division by 2 carefully.
    // (b-1) * b is always even, so (b-1) * b / 2 is an integer.
    // We need to compute this modulo MOD.
    // (b-1) * b / 2 mod MOD = ((b-1) mod MOD * (b mod MOD)) mod MOD * (2^-1 mod MOD) mod MOD
    // 2^-1 mod 10^9+7 is 500000004.
    long long sum_r_term1 = (b - 1);
    long long sum_r_term2 = b;

    long long sum_r = (sum_r_term1 % MOD * (sum_r_term2 % MOD)) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 modulo 10^9+7
    sum_r = (sum_r * inv2) % MOD;

    // Calculate sum_k = sum_{k=1 to a} (k * b + 1)
    // sum_k = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // sum_k = b * sum_{k=1 to a} k + a
    // sum_{k=1 to a} k = a * (a+1) / 2
    long long sum_k_inner_term1 = a;
    long long sum_k_inner_term2 = (a + 1);

    long long sum_k_inner = (sum_k_inner_term1 % MOD * (sum_k_inner_term2 % MOD)) % MOD;
    sum_k_inner = (sum_k_inner * inv2) % MOD;

    long long sum_k = (b % MOD * sum_k_inner) % MOD;
    sum_k = (sum_k + a % MOD) % MOD;

    // Total sum = sum_k * sum_r
    long long total_sum = (sum_k * sum_r) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

