int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> pos(26);
    for (int i = 0; i < L; ++i) {
        pos[s[i] - 'a'].push_back(i);
    }

    std::vector<std::vector<int>> count_pairs(L, std::vector<int>(26, 0));
    for (int i = 0; i < L; ++i) {
        for (int c_idx = 0; c_idx < 26; ++c_idx) {
            int target_char_pos = (i + c_idx) % L;
            count_pairs[i][s[target_char_pos] - 'a']++;
        }
    }

    std::vector<std::vector<int>> count_pairs_shifted(L, std::vector<int>(26, 0));
    for (int j = 1; j < L; ++j) { // j is the second position Vasya opens
        for (int k = 0; k < L; ++k) { // k is the actual shift
            char char_at_j = s[(j + k) % L];
            count_pairs_shifted[j][char_at_j - 'a']++;
        }
    }

    double total_win_prob = 0.0;

    for (int first_char_val = 0; first_char_val < 26; ++first_char_val) {
        if (pos[first_char_val].empty()) {
            continue;
        }

        double max_win_prob_for_char = 0.0;

        for (int j = 1; j < L; ++j) { // Vasya chooses j
            double current_j_win_prob = 0.0;

            // Map to store counts of (t[0], t[j]) pairs for a fixed j
            // Key: t[j] character, Value: count of k's that result in this (t[0], t[j])
            std::map<char, int> char_j_counts;

            for (int k_val : pos[first_char_val]) { // Iterate over all k such that s[k] == first_char_val
                char_j_counts[s[(j + k_val) % L]]++;
            }

            for (auto const& [char_j, count] : char_j_counts) {
                if (count == 1) {
                    current_j_win_prob += 1.0;
                }
            }
            max_win_prob_for_char = std::max(max_win_prob_for_char, current_j_win_prob);
        }
        total_win_prob += max_win_prob_for_char;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<bool> present_in_s(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        present_in_s[s[i] - 'a'] = true;
        if (i > 0) {
            adj[s[i] - 'a'].insert(s[i-1]);
            adj[s[i-1] - 'a'].insert(s[i]);
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string keyboard_layout = "";
    std::vector<bool> visited(26, false);

    // Find a starting character for a chain
    // A starting character must be present in s and have only one neighbor
    // Or, if s has only one unique character, that character itself.
    // Or, if s has only two unique characters, either of them.

    char start_char = 0;
    bool found_start = false;

    // Try to find a character with degree 1 that is present in s
    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && adj[i].size() == 1) {
            start_char = (char)('a' + i);
            found_start = true;
            break;
        }
    }

    // If no character with degree 1 is found among those present in s,
    // it means all characters present in s have degree 2 (forming a cycle)
    // or s has only one unique character (degree 0).
    // Or s has two unique characters (degree 1 for both, handled above).
    // If all present characters have degree 2, pick any one of them as a start.
    if (!found_start) {
        for (int i = 0; i < 26; ++i) {
            if (present_in_s[i]) {
                start_char = (char)('a' + i);
                found_start = true;
                break;
            }
        }
    }

    if (found_start) {
        char current_char = start_char;
        char prev_char = 0; // Sentinel value

        while (current_char != 0 && !visited[current_char - 'a']) {
            keyboard_layout += current_char;
            visited[current_char - 'a'] = true;

            char next_char = 0;
            for (char neighbor : adj[current_char - 'a']) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
        }
    }

    // Add any remaining characters that were not part of the password's chain
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            keyboard_layout += (char)('a' + i);
        }
    }

    // Check if the constructed layout is valid (all characters from s are included and form a single chain)
    // This check is implicitly done by the logic: if any character in s has degree > 2, it's NO.
    // If there are multiple disjoint chains among characters in s, this logic will also fail.
    // For example, if s = "ab" and s = "cd" were combined, it would be "NO".
    // But here we only have one password s.
    // The only way for this to fail is if the graph formed by s is not a single path/line.
    // E.g., if s = "abacaba", 'a' is connected to 'b' and 'c'. This is fine.
    // If s = "abacada", 'a' is connected to 'b', 'c', 'd'. This is NO.
    // The degree check `adj[i].size() > 2` handles this.
    // What if s forms a cycle? e.g., "abcadb" (a-b-c-a, d-b).
    // If s forms a cycle, all characters in the cycle will have degree 2.
    // The `while` loop will traverse the cycle and then stop.
    // This is fine, a cycle can be laid out linearly. E.g., 'a'-'b'-'c'-'a' can be 'a'-'b'-'c'.
    // The problem is if there are multiple disjoint components among `present_in_s` characters.
    // Example: s = "ab" and "cd" (not possible in one string s).
    // If s = "abacaba", the graph is a-b, a-c.
    // 'b' has degree 1 (neighbor 'a'). 'c' has degree 1 (neighbor 'a'). 'a' has degree 2 (neighbors 'b', 'c').
    // Start with 'b'. Path: b-a-c. Then add remaining.
    // This logic seems robust.

    std::cout << "YES\n";
    std::cout << keyboard_layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

