int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    for (int i = 0; i < n; ++i) {
        int start_block = (n - 1 - i) / k;
        int block_offset = (n - 1 - i) % k;
        int value = start_block * k + (k - 1 - block_offset) + 1;
        std::cout << value << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two "test" numbers: 0 and 1023 (all bits set for 0-9)
    // We track how these two numbers change after all operations.
    // This allows us to determine the final transformation for each bit.
    // For each bit position i:
    //   - If input bit i is 0, what is output bit i? (tracked by `val0`)
    //   - If input bit i is 1, what is output bit i? (tracked by `val1`)
    int val0 = 0;
    int val1 = 1023; // 2^10 - 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1 ^= x;
        }
    }

    // Now, `val0` holds the result for input 0, and `val1` for input 1023.
    // We need to find a sequence of at most 5 operations that transforms
    // any input `v` to the same result as Petya's program.
    // This is equivalent to finding operations that transform 0 to `val0`
    // and 1023 to `val1`.

    // Let's determine the required operations for each bit position (0 to 9).
    // For each bit `j`:
    //   - `bit0_final`: the j-th bit of `val0` (what 0 becomes)
    //   - `bit1_final`: the j-th bit of `val1` (what 1 becomes)
    //
    // We want to find `A`, `O`, `X` such that for any input bit `b`:
    // `((b & A_j) | O_j) ^ X_j` gives the correct `bit_final`.
    //
    // Case 1: Input bit `b` is 0
    //   `((0 & A_j) | O_j) ^ X_j` = `(0 | O_j) ^ X_j` = `O_j ^ X_j`
    //   So, `O_j ^ X_j = bit0_final`
    //
    // Case 2: Input bit `b` is 1
    //   `((1 & A_j) | O_j) ^ X_j` = `(A_j | O_j) ^ X_j`
    //   So, `(A_j | O_j) ^ X_j = bit1_final`
    //
    // We can construct the constants for AND, OR, XOR operations.
    // Let `final_AND_const`, `final_OR_const`, `final_XOR_const` be these constants.
    int final_AND_const = 1023; // Initialize to all 1s (identity for AND)
    int final_OR_const = 0;    // Initialize to all 0s (identity for OR)
    int final_XOR_const = 0;   // Initialize to all 0s (identity for XOR)

    for (int j = 0; j < 10; ++j) {
        int bit0_final = (val0 >> j) & 1;
        int bit1_final = (val1 >> j) & 1;

        // Analyze the transformation for bit `j`:
        // (input_bit, output_bit)
        // (0, bit0_final)
        // (1, bit1_final)

        if (bit0_final == 0 && bit1_final == 0) {
            // Both 0 and 1 map to 0.
            // This means the bit must be forced to 0.
            // We can achieve this with `& 0`.
            final_AND_const &= ~(1 << j); // Set j-th bit of AND_const to 0
            // OR and XOR bits remain 0 (identity)
        } else if (bit0_final == 1 && bit1_final == 1) {
            // Both 0 and 1 map to 1.
            // This means the bit must be forced to 1.
            // We can achieve this with `| 1`.
            final_OR_const |= (1 << j); // Set j-th bit of OR_const to 1
            // AND and XOR bits remain 0 (identity)
        } else if (bit0_final == 0 && bit1_final == 1) {
            // 0 maps to 0, 1 maps to 1.
            // This means the bit is unchanged.
            // All constants remain identity for this bit (AND 1, OR 0, XOR 0).
        } else if (bit0_final == 1 && bit1_final == 0) {
            // 0 maps to 1, 1 maps to 0.
            // This means the bit is flipped.
            // We can achieve this with `^ 1`.
            final_XOR_const |= (1 << j); // Set j-th bit of XOR_const to 1
            // AND and OR bits remain 0 (identity)
        }
    }

    // Construct the output program.
    // The order of operations matters: AND, then OR, then XOR.
    // This order is chosen because:
    // - AND can clear bits regardless of OR/XOR.
    // - OR can set bits regardless of XOR (if AND didn't clear them).
    // - XOR can flip bits.
    //
    // The derived `final_AND_const`, `final_OR_const`, `final_XOR_const`
    // are designed to work in this specific order: `( (x & A) | O ) ^ X`.
    //
    // Let's verify:
    // If input bit is 0: `((0 & A_j) | O_j) ^ X_j` = `(0 | O_j) ^ X_j` = `O_j ^ X_j`.
    //   - If (0->0, 1->0): `A_j=0, O_j=0, X_j=0`. Result `0^0=0`. Correct.
    //   - If (0->1, 1->1): `A_j=1, O_j=1, X_j=0`. Result `1^0=1`. Correct.
    //   - If (0->0, 1->1): `A_j=1, O_j=0, X_j=0`. Result `0^0=0`. Correct.
    //   - If (0->1, 1->0): `A_j=1, O_j=0, X_j=1`. Result `0^1=1`. Correct.
    //
    // If input bit is 1: `((1 & A_j) | O_j) ^ X_j` = `(A_j | O_j) ^ X_j`.
    //   - If (0->0, 1->0): `A_j=0, O_j=0, X_j=0`. Result `(0|0)^0=0`. Correct.
    //   - If (0->1, 1->1): `A_j=1, O_j=1, X_j=0`. Result `(1|1)^0=1`. Correct.
    //   - If (0->0, 1->1): `A_j=1, O_j=0, X_j=0`. Result `(1|0)^0=1`. Correct.
    //   - If (0->1, 1->0): `A_j=1, O_j=0, X_j=1`. Result `(1|0)^1=0`. Correct.
    //
    // The logic holds.

    std::vector<std::pair<char, int>> simplified_program;
    if (final_AND_const != 1023) { // 1023 is identity for AND
        simplified_program.push_back({'&', final_AND_const});
    }
    if (final_OR_const != 0) { // 0 is identity for OR
        simplified_program.push_back({'|', final_OR_const});
    }
    if (final_XOR_const != 0) { // 0 is identity for XOR
        simplified_program.push_back({'^', final_XOR_const});
    }

    std::cout << simplified_program.size() << "\n";
    for (const auto& op : simplified_program) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long count = 0;

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // For substrings starting with '0', the value f(s_l...s_r) can be small.
            // We need to find r such that r - i + 1 = f(s_i...s_r).
            // The maximum value for f(s_i...s_r) is 2^18 - 1, which is less than 2^18.
            // So, the length r - i + 1 must be at most 18.
            // This means r - i <= 17, or r <= i + 17.
            // We only need to check substrings up to a certain length.
            // Let's say max_len_to_check = 18 (since 2^18 is large enough).
            // The actual maximum length for a binary string to have value up to N is log2(N).
            // If N is 2e5, log2(2e5) is about 17.6. So length up to 18 is sufficient.
            // For a substring of length L, its value is at most 2^L - 1.
            // If L = 18, value is 2^18 - 1 = 262143.
            // If L = 19, value is 2^19 - 1 = 524287.
            // The maximum possible length of a substring is N (2e5).
            // So we only need to check substrings whose length is up to ~18-19.
            // Let's use a safe upper bound for length, say 20.
            // This means r - i + 1 <= 20, so r <= i + 19.

            long long current_val = 0;
            for (int j = i; j < n; ++j) {
                int len = j - i + 1;

                // If current_val exceeds max possible length (N), break.
                // Or if current_val exceeds a reasonable upper bound for length (e.g., 20), break.
                // Since s[i] is '0', current_val will be small.
                // The maximum length of s is 2e5.
                // If len > 20, then current_val (which is at most 2^len - 1) could be very large.
                // But we are looking for len = current_val.
                // If len > 20, then current_val (which is at most 2^len - 1) is much larger than len.
                // So we can stop if len gets too large.
                // A safe upper bound for len is around 19-20 because 2^18 is 262144, which is > 2e5.
                // So if len >= 19, then 2^len-1 is definitely > N.
                // Thus, if len >= 19, current_val will be much larger than len, unless current_val is 0.
                // If current_val is 0, then len must be 0, which is not possible.
                // So we can stop if len > 18.
                if (len > 18) { // Max length of s is 2e5. 2^18 > 2e5.
                    break;
                }

                current_val = (current_val << 1) | (s[j] - '0');

                if (current_val == len) {
                    count++;
                }
            }
        } else { // s[i] == '1'
            // For substrings starting with '1', the value f(s_l...s_r) grows quickly.
            // We need to find r such that r - i + 1 = f(s_i...s_r).
            // The maximum possible length of a substring is N.
            // The maximum value of f(s_i...s_r) is 2^N - 1.
            // We can iterate up to a certain length, say 20, because if the length
            // exceeds 20, the binary value will be much larger than the length.
            // For example, if len = 20, min value is 2^19 (if s_i=1).
            // 2^19 = 524288, which is already > N (2e5).
            // So we only need to check substrings with length up to ~19.
            // Let's use a safe upper bound for length, say 20.
            // This means r - i + 1 <= 20, so r <= i + 19.

            long long current_val = 0;
            for (int j = i; j < n; ++j) {
                int len = j - i + 1;

                // If current_val exceeds max possible length (N), break.
                // Or if current_val exceeds a reasonable upper bound for length (e.g., 20), break.
                // If len > 19, then current_val (which starts with '1') will be at least 2^(len-1).
                // 2^(19-1) = 2^18 = 262144, which is > N (2e5).
                // So if len >= 19, current_val will be much larger than len.
                // Thus, we can stop if len > 18.
                if (len > 18) { // Max length of s is 2e5. 2^18 > 2e5.
                    break;
                }

                current_val = (current_val << 1) | (s[j] - '0');

                if (current_val == len) {
                    count++;
                }
            }
        }
    }
    std::cout << count << std::endl;
}

