        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    std::vector<int> b(2 * n); // 1 for strawberry, -1 for blueberry
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        b[i] = (a[i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // and suffix sums for the right side (jars n+1 to 2n)
    // The balance is sum(1s) - sum(2s)
    // For left side, we consider prefix sums from right to left (from index n-1 down to 0)
    // For right side, we consider prefix sums from left to right (from index n up to 2n-1)

    // Balances for removing k jars from the left side (jars 1 to k)
    // The remaining jars on the left are a[k]...a[n-1]
    // The balance of the removed jars is sum(b[0]...b[k-1])
    // We are interested in the balance of the *remaining* jars.
    // Let's define balance_left[k] as the balance of jars a[0]...a[k-1]
    // This is the balance of the first k jars.
    // We need to map balance_of_removed_jars_from_left to the number of jars removed.
    // Let's use a map to store (balance_of_removed_jars_from_left -> count_of_jars_removed)
    // The balance of jars 0 to k-1 is prefix_sum[k-1] (if prefix_sum is 0-indexed)
    // Or, let's just compute the balance of the first k jars.
    // `left_removed_balances[k]` stores the balance of jars `a[0]` through `a[k-1]`.
    // `k` is the number of jars removed from the left.
    std::map<int, int> left_removed_balances;
    left_removed_balances[0] = 0; // 0 jars removed from left, balance 0
    int current_balance_left = 0;
    for (int k = 1; k <= n; ++k) {
        current_balance_left += b[k - 1];
        if (left_removed_balances.find(current_balance_left) == left_removed_balances.end()) {
            left_removed_balances[current_balance_left] = k;
        }
    }

    // Calculate the total initial balance of all 2n jars
    int total_initial_balance = 0;
    for (int i = 0; i < 2 * n; ++i) {
        total_initial_balance += b[i];
    }

    int min_jars_removed = 2 * n; // Initialize with max possible

    // Case 1: No jars removed from the right side (R=0)
    // We need the balance of remaining jars to be 0.
    // This means total_initial_balance - balance_of_removed_jars_from_left = 0
    // So, balance_of_removed_jars_from_left = total_initial_balance
    if (left_removed_balances.count(total_initial_balance)) {
        min_jars_removed = std::min(min_jars_removed, left_removed_balances[total_initial_balance]);
    }

    // Iterate through possible numbers of jars removed from the right side (R)
    // `k` here represents the number of jars removed from the right side (from a[2n-1] down to a[2n-k])
    int current_balance_right = 0;
    for (int k = 1; k <= n; ++k) {
        current_balance_right += b[2 * n - k]; // Balance of jars a[2n-k]...a[2n-1]
        // If we remove `k` jars from the right, the balance of the remaining jars
        // must be `total_initial_balance - current_balance_right`.
        // This remaining balance must be achieved by removing some jars from the left.
        // So, we need `balance_of_removed_jars_from_left = total_initial_balance - current_balance_right`.
        int target_balance_left = total_initial_balance - current_balance_right;
        if (left_removed_balances.count(target_balance_left)) {
            min_jars_removed = std::min(min_jars_removed, left_removed_balances[target_balance_left] + k);
        }
    }

    std::cout << min_jars_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

