        bool possible_pivot = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < pivot) {
                colors[i] = 1;
                if (d[i] < last1) { // Check if S1 remains non-decreasing
                    possible_pivot = false;
                    break;
