                if (d[i] < first2) { // Check if S2 remains non-decreasing
                    first2 = d[i];
                }
            } else { // d[i] == pivot
                // Tentatively color 2. If it breaks S2, try color 1.
                // If it breaks S1, then this pivot is invalid.
                // This logic is flawed. A simpler approach is needed.
                // Let's try to assign all d[i] == pivot to color 1 first, then switch to color 2.
                // This means there's an implicit split point for digits equal to pivot.
