        //     Otherwise, we can set `b_i = prev_val`.
        //   If `a_i > prev_val`:
        //     We need to make `b_i >= prev_val`.
        //     We can choose `k=0`, then `b_i = a_i`. This satisfies `b_i >= prev_val`.
        //     So, `a_i` is a possible value for `b_i`.
        //     Can we achieve a smaller value for `b_i` that is still `>= prev_val`?
        //     This would happen if we increment `a_i` by `k` such that `a_i + k >= m` and `(a_i + k) % m >= prev_val`.
        //     The smallest such value is `prev_val` itself.
        //     To make `a_i` become `prev_val` (after modulo), we need `(m - a_i + prev_val)` operations.
        //     If `(m - a_i + prev_val) <= x`, then we can set `b_i = prev_val`.
        //     Otherwise (`(m - a_i + prev_val) > x`), we cannot reach `prev_val` by wrapping around.
        //     In this case, the smallest value we can achieve for `b_i` that is `>= prev_val` is `a_i` itself (by adding 0 operations).
        //     So, if `a_i > prev_val` and `(m - a_i + prev_val) <= x`, we can set `b_i = prev_val`.
        //     Otherwise, we must set `b_i = a_i`.

        // Combining these:
        // If a_i <= prev_val:
        //   If prev_val - a_i <= x: we can set b_i = prev_val.
        //   Else: impossible.
        // Else (a_i > prev_val):
        //   If (m - a_i + prev_val) <= x: we can set b_i = prev_val.
        //   Else: we must set b_i = a_i.

        if (current_a <= prev_val) {
            // We need to increase current_a to at least prev_val.
            // The minimum operations needed is prev_val - current_a.
            if (prev_val - current_a > x) {
                return false; // Cannot reach prev_val
            }
            // We can reach prev_val, so we set b_i = prev_val.
            lower_bound_b_i = prev_val;
        } else { // current_a > prev_val
            // We have two options for b_i:
            // 1. Keep b_i = current_a (0 operations). This satisfies b_i >= prev_val.
            // 2. Increment current_a by k operations (0 < k <= x) such that (current_a + k) % m >= prev_val.
            //    The smallest such value is prev_val itself, if we can reach it.
            //    Operations needed to make current_a become prev_val (after modulo) is (m - current_a + prev_val).
            if ((m - current_a + prev_val) <= x) {
                // We can reach prev_val by wrapping around.
                // So, we can set b_i = prev_val.
                lower_bound_b_i = prev_val;
            } else {
                // We cannot reach prev_val by wrapping around within x operations.
                // So, we must use current_a itself (0 operations).
                lower_bound_b_i = current_a;
            }
        }
        prev_val = lower_bound_b_i;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// The sum can exceed 2^31-1.
// x can also exceed n, but its value is only used for array indexing if x is within [1, n].
// If x goes out of bounds, the program terminates.

// Memoization table for results of (x, parity)
// dp[x][0] stores (final_x, final_y_increment) if starting at x with even step count (first op is x+a_x)
// dp[x][1] stores (final_x, final_y_increment) if starting at x with odd step count (first op is x-a_x)
// The y_increment is relative to the y value at the start of the subproblem.
// We use a pair {long long, long long} where first is final_x and second is final_y_increment.
// A special value like {0, 0} can indicate "not computed" or "cycle detected".
// For cycle detection, we can use a `visiting` state.
std::vector<std::vector<std::pair<long long, long long>>> dp;
std::vector<std::vector<bool>> visiting; // To detect cycles

int N;
std::vector<long long> A_values; // a_1 is set dynamically, a_2...a_n are stored here.

// Function to solve for a given starting x and parity
// x_curr: current x position (1-indexed)
// parity: 0 for even step count (next op is x+a_x), 1 for odd step count (next op is x-a_x)
// a_1_val: the value of a[1] for the current run
std::pair<long long, long long> solve(long long x_curr, int parity, long long a_1_val) {
    // Base cases for termination
    if (x_curr <= 0 || x_curr > N) {
        return {x_curr, 0}; // x_curr is the final x, 0 is the y increment from this point
    }

    // Check memoization table
    if (dp[x_curr][parity].first != 0 || dp[x_curr][parity].second != 0) {
        // If it's not {0,0}, it means it's already computed.
        // {0,0} is used as an initial value, so we need to be careful if a valid result could be {0,0}.
        // A valid result {0,0} would mean x ends at 0 and y increment is 0.
        // This is possible if x_curr=0, but we handle x_curr<=0 above.
        // If x_curr > N, it's also handled.
        // So, for x_curr in [1, N], {0,0} is a safe initial value.
        return dp[x_curr][parity];
    }

    // Cycle detection
    if (visiting[x_curr][parity]) {
        // Cycle detected, return a special value indicating infinite loop
        return {-1, -1};
    }

    visiting[x_curr][parity] = true;

    long long current_a_val;
    if (x_curr == 1) {
        current_a_val = a_1_val;
    } else {
        current_a_val = A_values[x_curr - 2]; // A_values stores a_2...a_n, so index x_curr-2 corresponds to a_x_curr
    }

    long long next_x;
    long long y_increment_from_this_step;

    if (parity == 0) { // Current operation is x = x + a_x, y = y + a_x
        next_x = x_curr + current_a_val;
        y_increment_from_this_step = current_a_val;
    } else { // Current operation is x = x - a_x, y = y + a_x
        next_x = x_curr - current_a_val;
        y_increment_from_this_step = current_a_val;
    }

    // Recursively solve for the next state
    std::pair<long long, long long> result_from_next_state = solve(next_x, 1 - parity, a_1_val);

    // If a cycle was detected in the recursive call, propagate it
    if (result_from_next_state.first == -1 && result_from_next_state.second == -1) {
        dp[x_curr][parity] = {-1, -1};
    } else {
        // Combine results
        dp[x_curr][parity] = {result_from_next_state.first, y_increment_from_this_step + result_from_next_state.second};
    }

    visiting[x_curr][parity] = false; // Backtrack: mark as not visiting

    return dp[x_curr][parity];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    A_values.resize(N - 1);
    for (int i = 0; i < N - 1; ++i) {
        std::cin >> A_values[i];
    }

    // Initialize dp table and visiting table
    // dp[x][parity] stores {final_x, total_y_increment}
    // x goes from 1 to N. parity is 0 or 1.
    dp.resize(N + 1, std::vector<std::pair<long long, long long>>(2, {0, 0}));
    visiting.resize(N + 1, std::vector<bool>(2, false));

    // For each possible a_1 value (from 1 to N-1)
    for (long long i = 1; i < N; ++i) {
        // Clear dp and visiting for each new a_1_val
        // This is crucial because a_1_val changes the 'a' array, thus changing the transitions.
        // A more efficient approach would be to pass a_1_val as a parameter to solve,
        // and only clear dp states that depend on a_1_val (i.e., dp[1][0] and dp[1][1]).
        // However, since N is up to 2*10^5, clearing the whole table N times is too slow (N*N*2 states).
        // The current implementation of `solve` passes `a_1_val` as a parameter,
        // so the `dp` table should be cleared for each `i`.
        // This means the `dp` table should be part of the `solve` function's scope or passed around,
        // or we need to re-think the memoization.

        // The problem states "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
        // This means a_1 is set to `i` for each run. The `a` array effectively changes.
        // So, the DP table needs to be re-initialized for each `i`.
        // This makes the DP approach as described above too slow if `dp` is global.
        // N * (N * 2) states * (some constant work) = N^2, which is (2*10^5)^2 = 4*10^10. Too slow.

        // Let's re-evaluate the problem.
        // The only value that changes is a_1.
        // The transitions for x > 1 are fixed.
        // The transitions for x = 1 depend on a_1.
        // This means we can precompute results for x > 1.
        // For x = 1, the first step is `x = 1 + a_1`, `y = a_1`.
        // Then we are at `(1 + a_1, a_1)` and the next operation is `x = x - a_x`.
        // So we need to solve `solve(1 + a_1, 1, a_1)`.

        // Let's define a new DP state:
        // dp[x][parity] stores {final_x, final_y_increment} assuming a_1 is NOT involved in the path.
        // This means dp[1][0] and dp[1][1] cannot be computed this way.
        // We can compute dp for x from 2 to N.
        // Then for each `i`, we start at `x=1, y=0`.
        // First step: `x = 1 + i`, `y = i`.
        // Then call `solve(1 + i, 1, i)` using the precomputed DP table.
        // The `a_1_val` parameter is only needed for `x_curr == 1`.
        // If `x_curr > 1`, `a_1_val` is not used.

        // Clear dp and visiting for each new `i`
        for (int k = 0; k <= N; ++k) {
            dp[k][0] = {0, 0};
            dp[k][1] = {0, 0};
            visiting[k][0] = false;
            visiting[k][1] = false;
        }

        // Initial state for the run: x=1, y=0.
        // First operation: x = 1 + i, y = 0 + i.
        // Then, the next operation is x = x - a_x. So parity is 1.
        long long initial_x_after_first_op = 1 + i;
        long long initial_y_after_first_op = i;

        std::pair<long long, long long> result = solve(initial_x_after_first_op, 1, i);

        if (result.first == -1 && result.second == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << initial_y_after_first_op + result.second << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool removed;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].removed = false;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (children[i].removed) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].removed = true;

        long long current_v_cry = children[i].v;
        long long accumulated_d_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (children[j].removed) {
                continue;
            }

            // Apply accumulated d_cry from previous children who ran away
            children[j].p -= accumulated_d_cry;

            // Apply v_cry from the child currently at the doctor
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].removed = true;
                accumulated_d_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric> // For std::accumulate

int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If initial 'a' has an odd number of '1's, we can always make it even by appending '1'.
    // If initial 'a' has an even number of '1's, we can always make it odd by appending '0' then '1'.
    // So, if we can append enough characters, we can achieve any parity.
    // The maximum number of '1's we can have in 'a' is its current count plus the number of characters we can append.
    // The number of characters we can append is effectively unlimited, as we can always append parity.
    // However, we are limited by the length of 'b'. We can only append characters until 'a' is at least as long as 'b'.
    // If we want to match 'b', 'a' must eventually become 'b'.
    // This means the final 'a' must have length |b|.
    // The number of '1's in 'a' can be increased by at most (length_of_b - length_of_a) if length_of_b > length_of_a.
    // If length_of_a >= length_of_b, we can't increase the number of '1's beyond ones_a.
    // The maximum number of '1's we can achieve in a string of length |b| starting from 'a'
    // is ones_a + (length_of_b - length_of_a) if length_of_b > length_of_a,
    // otherwise it's just ones_a (since we can only remove characters).
    // However, the parity operation allows us to add a '1' if the current count is odd, or a '0' if even.
    // This means we can always increase the count of '1's by 1 if we have an odd count,
    // or keep it the same if we have an even count.
    // More simply, if we have `k` ones, we can append `k%2`.
    // If `k%2 == 1`, we append '1', new count `k+1`.
    // If `k%2 == 0`, we append '0', new count `k`.
    // So, if `ones_a` is odd, we can make it `ones_a + 1`.
    // If `ones_a` is even, we can keep it `ones_a`.
    // This means the maximum number of '1's we can have in a string of length `L`
    // that was derived from `a` is `ones_a` if `ones_a` is even, or `ones_a + 1` if `ones_a` is odd.
    // This is equivalent to `ones_a + (ones_a % 2)`.
    // This is the maximum number of '1's we can have in the *prefix* of `a` that we are considering,
    // *before* we start removing characters to match `b`.
    // The actual maximum number of '1's we can have in a string of length `|b|`
    // that is derived from `a` is `ones_a + (ones_a % 2)` if `|a| < |b|`.
    // If `|a| >= |b|`, we can only remove characters, so the number of ones can only decrease or stay the same.
    // The key insight is that we can always make the number of ones `ones_a` or `ones_a + 1`
    // by appending at most one character.
    // After that, we can append '0's indefinitely without changing the parity or number of '1's.
    // So, the maximum number of '1's we can achieve in a string of length `|b|`
    // is `ones_a + (ones_a % 2)`.
    // This is because if `ones_a` is odd, we can append '1' to make it `ones_a + 1` (even).
    // If `ones_a` is even, we can append '0' to keep it `ones_a` (even).
    // In both cases, the new string has an even number of '1's.
    // After this, any subsequent parity operation will append '0', keeping the number of '1's the same.
    // So, the maximum number of '1's we can ever have in a string derived from `a`
    // (by appending characters) is `ones_a` if `ones_a` is even, or `ones_a + 1` if `ones_a` is odd.
    // Let `max_ones_a_possible = ones_a + (ones_a % 2)`.

    // Condition 1: The number of '1's in 'b' must not exceed the maximum possible '1's we can generate from 'a'.
    // This maximum is `ones_a` if `ones_a` is even, or `ones_a + 1` if `ones_a` is odd.
    // This can be written as `ones_a + (ones_a % 2)`.
    if (ones_b > ones_a + (ones_a % 2)) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'b' must not be greater than the length of 'a' plus the maximum number of
    // characters we can append to 'a' to reach the desired number of '1's.
    // The number of characters we need to append to 'a' to reach `ones_b` '1's is `ones_b - ones_a`
    // if `ones_b > ones_a`. If `ones_b <= ones_a`, we don't need to append '1's.
    // However, we can always append '0's.
    // The crucial part is that we can always make the length of `a` at least `|b|`
    // by appending parity bits.
    // If `|a| < |b|`, we need to append `|b| - |a|` characters.
    // We can always do this.
    // The only constraint is the number of '1's.
    // If `ones_b` is achievable, and `|b|` is achievable, then it's possible.
    // The length of `a` can be increased to any length `L >= |a|` by appending `L - |a|` parity bits.
    // The number of '1's in `a` can be at most `ones_a + (ones_a % 2)`.
    // If `ones_b` is greater than `ones_a + (ones_a % 2)`, it's impossible.
    // Otherwise, `ones_b` is less than or equal to `ones_a + (ones_a % 2)`.
    // This means we can always reach a state where the current string `a'` has `ones_b` ones
    // and its length is at least `|b|`.
    // For example, if `ones_a` is odd and `ones_b = ones_a + 1`, we append '1'.
    // If `ones_a` is even and `ones_b = ones_a`, we append '0'.
    // In both cases, we have achieved the target number of '1's.
    // After this, we can append `0`s (since the parity will be even) until the length is `|b|`.
    // Or, if `|a| >= |b|`, we just need to check if `ones_b <= ones_a`.
    // The condition `ones_b <= ones_a + (ones_a % 2)` covers both cases.
    // If `|a| >= |b|`, we can only remove characters. So `ones_b` must be `<= ones_a`.
    // If `ones_a` is even, `ones_a % 2 == 0`, so `ones_b <= ones_a`. This is correct.
    // If `ones_a` is odd, `ones_a % 2 == 1`, so `ones_b <= ones_a + 1`.
    // This means if `ones_b = ones_a + 1`, it would be possible if we could append.
    // But if `|a| >= |b|`, we cannot append. So `ones_b` must be `<= ones_a`.
    // This implies that the condition `ones_b <= ones_a + (ones_a % 2)` is not sufficient
    // if `|a| >= |b|` and `ones_a` is odd and `ones_b = ones_a + 1`.
    // Let's refine:
    // We need to reach a string `a'` such that `a'` has `ones_b` ones and `|a'| = |b|`.
    // The operations allow us to:
    // 1. Remove prefix characters. This decreases length and potentially `ones_a`.
    // 2. Append parity. This increases length and potentially `ones_a`.

    // The strategy is:
    // 1. Append parity bits to `a` until its length is at least `|b|`.
    //    During this process, the number of '1's in `a` might change.
    //    Let `current_ones_a` be the count of '1's in `a`.
    //    If `current_ones_a` is odd, we can append '1', making `current_ones_a + 1`.
    //    If `current_ones_a` is even, we can append '0', making `current_ones_a`.
    //    So, the maximum number of '1's we can achieve in `a` by appending is `ones_a + (ones_a % 2)`.
    //    Let `max_ones_reachable_by_appending = ones_a + (ones_a % 2)`.
    //    This is the maximum number of '1's we can have in `a` *before* we start removing characters
    //    to match `b`'s length.
    //    If `ones_b > max_ones_reachable_by_appending`, it's impossible.
    //    This is the first check.

    // 2. After potentially appending, we have a string `a_prime` with `max_ones_reachable_by_appending` '1's
    //    (or fewer, if we chose to append '0's when `ones_a` was odd, which is always possible by appending '0' then '1' then '0' etc.)
    //    and length `|a_prime| >= |b|`.
    //    Now we need to remove prefix characters from `a_prime` until its length is `|b|`.
    //    When we remove characters, the number of '1's can only decrease or stay the same.
    //    So, the number of '1's in the final string `b` must be less than or equal to the number of '1's
    //    in `a_prime` (which is `max_ones_reachable_by_appending`).

    // Combining these:
    // The maximum number of '1's we can have in a string of length `|b|` derived from `a` is:
    // `ones_a` if `ones_a` is even.
    // `ones_a + 1` if `ones_a` is odd.
    // This is `ones_a + (ones_a % 2)`.
    // Let this value be `max_ones_possible_in_b_length`.
    // If `ones_b > max_ones_possible_in_b_length`, then it's impossible.
    // Otherwise, it is always possible.
    // Why? Because we can always reach `max_ones_possible_in_b_length` by appending at most one '1' (if `ones_a` is odd).
    // After that, the parity is even, so we can append '0's indefinitely.
    // We can append enough '0's to make the string length `|b|`.
    // The number of '1's will be `max_ones_possible_in_b_length`.
    // Since `ones_b <= max_ones_possible_in_b_length`, we can always remove leading characters
    // until the string has `ones_b` ones and length `|b|`.
    // This is because we can always choose which characters to remove from the prefix.
    // We can remove '0's or '1's. If we need to reduce the '1's count, we remove '1's.
    // If we need to keep '1's, we remove '0's.
    // The only constraint is that we must end up with a string of length `|b|`.
    // The number of '1's in `b` must be achievable.

    // Example 1: a = 01011 (ones_a=3), b = 0110 (ones_b=2)
    // max_ones_possible_in_b_length = 3 + (3 % 2) = 3 + 1 = 4.
    // ones_b = 2. Since 2 <= 4, YES.

    // Example 2: a = 0011 (ones_a=2), b = 1110 (ones_b=3)
    // max_ones_possible_in_b_length = 2 + (2 % 2) = 2 + 0 = 2.
    // ones_b = 3. Since 3 > 2, NO.

    // This logic seems sound and covers all cases.

    if (ones_b <= ones_a + (ones_a % 2)) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: One cut, two pieces.
    // We can form s_suffix + s_prefix.
    // This is equivalent to a cyclic shift.
    // We iterate through all possible cut points (1 to n-1).
    for (int i = 1; i < n; ++i) {
        std::string s_suffix = s.substr(i);
        std::string s_prefix = s.substr(0, i);
