    while (track_idx < m) {
        if (head_idx >= n) {
            return false; // Ran out of heads but still have tracks to cover
        }

        // Find the first head that can potentially cover p[track_idx]
        // A head h[head_idx] can cover p[track_idx] if h[head_idx] - T <= p[track_idx]
        // So, we need h[head_idx] <= p[track_idx] + T
        while (head_idx < n && h[head_idx] < p[track_idx] - T) {
            head_idx++;
        }

        if (head_idx >= n) {
            return false; // No head can reach p[track_idx]
        }

        // Now, h[head_idx] is the first head such that h[head_idx] >= p[track_idx] - T
        // This head can cover tracks up to h[head_idx] + T.
        // We greedily use this head to cover as many subsequent tracks as possible.
        long long current_head_reach = h[head_idx] + T;

        // Advance track_idx as long as p[track_idx] is within the current head's reach
        while (track_idx < m && p[track_idx] <= current_head_reach) {
            track_idx++;
        }

        head_idx++; // Move to the next head for the remaining tracks
    }
    return true; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 (max coord) - 1 (min coord) + 10^10 (max coord) - 1 (min coord)
                                    // A safer upper bound is max(p_m - h_1, h_n - p_1) which is roughly 10^10.
                                    // Or simply (max_coord - min_coord) which is 10^10.
                                    // A head at 1 can cover 10^10, a track at 10^10. Distance is 10^10-1.
                                    // So 10^10 is a good upper bound. 2*10^10 is definitely safe.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long min_goodness = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> best_partition(n, 1);

    // Case 2: All elements in different subsequences (e.g., all 1s, or all 2s).
    // This is effectively the same as Case 1 for goodness calculation,
    // as all f values are shifted by h.
    // min_f = a[0].value + a[1].value + h
    // max_f = a[n-2].value + a[n-1].value + h
    // goodness = (a[n-2].value + a[n-1].value + h) - (a[0].value + a[1].value + h)
    //          = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    // So, the goodness is the same. The partition would be all 2s.
    // We already have min_goodness from Case 1, so no need to update.

    // Case 3: Mixed partition.
    // The minimum possible f value is a[0].value + a[1].value.
    // This can be achieved if a[0] and a[1] are in the same subsequence.
    // The maximum possible f value is a[n-1].value + a[n-2].value + h.
    // This can be achieved if a[n-1] and a[n-2] are in different subsequences.
    //
    // Consider a partition where a[0] is in subsequence 1, and all other elements
    // a[1], ..., a[n-1] are in subsequence 2.
    //
    // Pairs within subsequence 1: None (if n=1) or only a[0] (not a pair).
    // Pairs within subsequence 2: (a[i], a[j]) for i,j in [1, n-1].
    //   Min sum: a[1].value + a[2].value (if n-1 >= 2, i.e., n >= 3)
    //   Max sum: a[n-2].value + a[n-1].value
    // Pairs across subsequences: (a[0], a[i]) for i in [1, n-1].
    //   Min sum: a[0].value + a[1].value + h
    //   Max sum: a[0].value + a[n-1].value + h
    //
    // Let's analyze the range of f values for this specific partition:
    // min_f_val = min( (a[1].value + a[2].value if n>=3), (a[0].value + a[1].value + h) )
    // max_f_val = max( (a[n-2].value + a[n-1].value), (a[0].value + a[n-1].value + h) )
    //
    // This is the partition where a[0] is in one group, and a[1]...a[n-1] are in another.
    // Let's call a[0] group 1, and a[1]...a[n-1] group 2.
    //
    // The minimum possible sum of two elements is a[0].value + a[1].value.
    // The maximum possible sum of two elements is a[n-1].value + a[n-2].value.
    //
    // If a[0] is in group 1, and a[1]...a[n-1] are in group 2:
    //
    // Possible f values:
    // 1. a[i].value + a[j].value for i,j in [1, n-1] (both in group 2)
    //    Range: [a[1].value + a[2].value, a[n-2].value + a[n-1].value] (if n >= 3)
    // 2. a[0].value + a[i].value + h for i in [1, n-1] (one in group 1, one in group 2)
    //    Range: [a[0].value + a[1].value + h, a[0].value + a[n-1].value + h]
    //
    // The overall min_f for this partition:
    // If n=2: only (a[0], a[1]) pair. They are in different groups. f = a[0].value + a[1].value + h.
    //   min_f = a[0].value + a[1].value + h
    //   max_f = a[0].value + a[1].value + h
    //   goodness = 0. This is always better than the all-same-group case if h > 0.
    //   If n=2, a[0].value + a[1].value + h is the only f value. Goodness is 0.
    //   This is the optimal partition for n=2.
    //
    // If n >= 3:
    //   min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    //   max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
    //   current_goodness = max_f - min_f;
    //
    //   This specific partition is: a[0] in group 1, a[1]...a[n-1] in group 2.
    //   Let's check if this partition gives a better goodness.
    //
    //   The minimum possible f value is `a[0].value + a[1].value`.
    //   The maximum possible f value is `a[n-1].value + a[n-2].value + h`.
    //
    //   Consider the partition where `a[0]` is in group 1, and `a[1], ..., a[n-1]` are in group 2.
    //   The minimum `f` value is `min(a[1]+a[2], a[0]+a[1]+h)` (if n>=3).
    //   The maximum `f` value is `max(a[n-2]+a[n-1], a[0]+a[n-1]+h)`.
    //
    //   Let's check the goodness for this partition.
    //   The minimum value of `f` is `a[0].value + a[1].value`.
    //   The maximum value of `f` is `a[n-1].value + a[n-2].value + h`.
    //   The goodness for this partition is `(a[n-1].value + a[n-2].value + h) - (a[0].value + a[1].value)`.
    //   This is the goodness if we can achieve `a[0].value + a[1].value` as min_f and `a[n-1].value + a[n-2].value + h` as max_f.
    //   This happens if `a[0]` and `a[1]` are in the same group, AND `a[n-1]` and `a[n-2]` are in different groups.
    //   This is not the partition we are considering.
    //
    //   Let's re-evaluate the partition: `a[0]` in group 1, `a[1]...a[n-1]` in group 2.
    //   Min f: `a[0].value + a[1].value + h` (from (a[0], a[1]) pair)
    //          OR `a[1].value + a[2].value` (from (a[1], a[2]) pair, if n >= 3)
    //          So, `min_f = (n >= 3) ? std::min(a[0].value + a[1].value + h, a[1].value + a[2].value) : (a[0].value + a[1].value + h);`
    //   Max f: `a[0].value + a[n-1].value + h` (from (a[0], a[n-1]) pair)
    //          OR `a[n-2].value + a[n-1].value` (from (a[n-2], a[n-1]) pair, if n >= 3)
    //          So, `max_f = (n >= 3) ? std::max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value) : (a[0].value + a[n-1].value + h);`
    //
    //   This partition is only relevant if `a[0].value + a[1].value + h` is not too large.
    //   Specifically, if `a[0].value + a[1].value + h <= a[n-2].value + a[n-1].value`.
    //   If this condition holds, then `min_f` could be `a[0].value + a[1].value + h` (if n=2 or if `a[0]+a[1]+h <= a[1]+a[2]`).
    //   And `max_f` could be `a[n-2].value + a[n-1].value` (if `a[0]+a[n-1]+h <= a[n-2]+a[n-1]`).
    //
    //   Let's consider the specific partition where `a[0]` is in group 1, and `a[1], ..., a[n-1]` are in group 2.
    //   The minimum possible `f` value is `a[0].value + a[1].value + h`.
    //   The maximum possible `f` value is `a[n-2].value + a[n-1].value`.
    //   This is only possible if `a[0].value + a[1].value + h <= a[n-2].value + a[1].value` (for min_f)
    //   and `a[0].value + a[n-1].value + h <= a[n-2].value + a[n-1].value` (for max_f).
    //   The second condition simplifies to `a[0].value + h <= a[n-2].value`.
    //   If `a[0].value + h <= a[n-2].value`, then the max_f is `a[n-2].value + a[n-1].value`.
    //   The min_f is `a[0].value + a[1].value + h`.
    //   The goodness is `(a[n-2].value + a[n-1].value) - (a[0].value + a[1].value + h)`.
    //   This is a candidate for minimal goodness.
    //
    //   Let's check this specific partition: `a[0]` in group 1, `a[1]...a[n-1]` in group 2.
    //   The values of f are:
    //   - `a[i].value + a[j].value` for `1 <= i < j <= n-1`
    //   - `a[0].value + a[k].value + h` for `1 <= k <= n-1`
    //
    //   The minimum of these values is `min(a[1].value + a[2].value, a[0].value + a[1].value + h)` (if n >= 3).
    //   If n=2, it's just `a[0].value + a[1].value + h`.
    //   The maximum of these values is `max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)` (if n >= 3).
    //   If n=2, it's just `a[0].value + a[1].value + h`.
    //
    //   Let's calculate this goodness.
    long long current_min_f, current_max_f;
    if (n == 2) {
        current_min_f = a[0].value + a[1].value + h;
        current_max_f = a[0].value + a[1].value + h;
    } else { // n >= 3
        current_min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
        current_max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
    }
    long long current_goodness = current_max_f - current_min_f;

    if (current_goodness < min_goodness) {
        min_goodness = current_goodness;
        best_partition.assign(n, 2); // All 2s
        best_partition[a[0].original_index] = 1; // a[0] is 1
    }

    // Consider the partition where a[n-1] is in group 1, and a[0]...a[n-2] are in group 2.
    // This is symmetric to the previous case.
    // Min f: `min(a[0].value + a[1].value, a[n-1].value + a[0].value + h)` (if n >= 3).
    // Max f: `max(a[n-3].value + a[n-2].value, a[n-1].value + a[n-2].value + h)` (if n >= 3).
    //
    // Let's calculate this goodness.
    if (n == 2) { // Already handled, same as previous case.
        // current_min_f = a[0].value + a[1].value + h;
        // current_max_f = a[0].value + a[1].value + h;
    } else { // n >= 3
        current_min_f = std::min(a[0].value + a[1].value, a[n-1].value + a[0].value + h);
        current_max_f = std::max(a[n-3].value + a[n-2].value, a[n-1].value + a[n-2].value + h);
        current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition.assign(n, 2); // All 2s
            best_partition[a[n-1].original_index] = 1; // a[n-1] is 1
        }
    }

    // The crucial observation is that the minimum possible sum of two elements is a[0]+a[1].
    // The maximum possible sum of two elements is a[n-1]+a[n-2].
    //
    // If we want to minimize goodness, we want to make max_f - min_f as small as possible.
    //
    // Option A: All elements in the same group.
    // min_f = a[0]+a[1]
    // max_f = a[n-1]+a[n-2]
    // goodness = (a[n-1]+a[n-2]) - (a[0]+a[1])
    // This is the initial `min_goodness` and `best_partition` (all 1s).
    //
    // Option B: Split into two groups such that `a[0]` is in one group, and `a[1], ..., a[n-1]` are in the other.
    // Group 1: {a[0]}
    // Group 2: {a[1], ..., a[n-1]}
    //
    // Values of f:
    // 1. `a[i]+a[j]` for `1 <= i < j <= n-1` (both in Group 2)
    //    Range: `[a[1]+a[2], a[n-2]+a[n-1]]` (if n >= 3)
    // 2. `a[0]+a[k]+h` for `1 <= k <= n-1` (one in Group 1, one in Group 2)
    //    Range: `[a[0]+a[1]+h, a[0]+a[n-1]+h]`
    //
    // Overall min_f: `min(a[1]+a[2], a[0]+a[1]+h)` (if n >= 3). If n=2, it's `a[0]+a[1]+h`.
    // Overall max_f: `max(a[n-2]+a[n-1], a[0]+a[n-1]+h)` (if n >= 3). If n=2, it's `a[0]+a[1]+h`.
    //
    // This is the second case we checked.
    //
    // The key insight is that the minimum possible value of `f(x,y)` is `a[0]+a[1]`.
    // The maximum possible value of `f(x,y)` is `a[n-1]+a[n-2]+h`.
    //
    // If we can achieve `a[0]+a[1]` as `min_f` and `a[n-1]+a[n-2]+h` as `max_f`,
    // the goodness would be `(a[n-1]+a[n-2]+h) - (a[0]+a[1])`.
    // This requires `a[0]` and `a[1]` to be in the same group, AND `a[n-1]` and `a[n-2]` to be in different groups.
    //
    // Consider the partition where `a[0]` is in group 1, and `a[1], ..., a[n-1]` are in group 2.
    // The minimum `f` value is `min(a[1]+a[2], a[0]+a[1]+h)` (if n >= 3).
    // The maximum `f` value is `max(a[n-2]+a[n-1], a[0]+a[n-1]+h)` (if n >= 3).
    //
    // Let's analyze the condition `a[0].value + h <= a[n-2].value`.
    // If this holds, then `a[0].value + a[k].value + h <= a[n-2].value + a[k].value` for any `k`.
    // In particular, `a[0].value + a[n-1].value + h <= a[n-2].value + a[n-1].value`.
    // This means that `max_f` for the partition `a[0]` vs `a[1]...a[n-1]` would be `a[n-2].value + a[n-1].value`.
    // And `min_f` would be `a[0].value + a[1].value + h`.
    // The goodness would be `(a[n-2].value + a[n-1].value) - (a[0].value + a[1].value + h)`.
    // This is the third candidate for goodness.
    //
    // This specific partition is: `a[0]` in group 1, `a[1]...a[n-1]` in group 2.
    // This is exactly what we calculated in the second `if` block.
    //
    // The three main candidates for goodness are:
    // 1. All elements in one group: `(a[n-1]+a[n-2]) - (a[0]+a[1])`
    //    Partition: all 1s (or all 2s).
    // 2. `a[0]` in group 1, `a[1]...a[n-1]` in group 2.
    //    `min_f = (n >= 3) ? std::min(a[1]+a[2], a[0]+a[1]+h) : (a[0]+a[1]+h)`
    //    `max_f = (n >= 3) ? std::max(a[n-2]+a[n-1], a[0]+a[n-1]+h) : (a[0]+a[1]+h)`
    //    Goodness = `max_f - min_f`.
    // 3. `a[n-1]` in group 1, `a[0]...a[n-2]` in group 2.
    //    `min_f = (n >= 3) ? std::min(a[0]+a[1], a[n-1]+a[0]+h) : (a[0]+a[1]+h)`
    //    `max_f = (n >= 3) ? std::max(a[n-3]+a[n-2], a[n-1]+a[n-2]+h) : (a[0]+a[1]+h)`
    //    Goodness = `max_f - min_f`.

    // The logic for the second and third cases is already implemented.
    // The initial `min_goodness` covers the "all in one group" case.
    // The two `if (current_goodness < min_goodness)` blocks cover the "one element separated" cases.

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

