    std::vector<int> r_idx(n);
    for (int i = 0; i < n; ++i) {
        r_idx[i] = n; // Initialize to n, meaning no triple found yet for s[i...n-1]
    }

    // Iterate through all possible starting positions x for the pattern s_x = s_{x+k} = s_{x+2k}
    // x is 0-indexed.
    for (int x = 0; x < n; ++x) {
        // Iterate through possible values of k.
